-- Poems batch 177
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a87a36d6-d734-4e90-9e6d-10f9e96e1e0b','寄題徽州李君博文閣','陳文蔚','宋','宋诗','song-poetry','','[]','曾參一唯外，相顧了無言。',180,'全唐诗/poet.song.173000.json','["曾參一唯外，相顧了無言。", "顔淵但如愚，永謝枝葉繁。", "後人謂二子，獨得道之原。", "脫落章句卑，統宗而會元。", "誰知聖門教，入道固有門。", "非博奚反約，溯流乃求源。", "顔曾日用功，如海衆水吞。", "及其成功後，木落歸本根。", "固非求捷徑，大學廢講論。", "李君敞高閣，駕言避俗喧。", "藏書比鄴侯，日夕手自翻。", "百家期貫穿，目擊萬里存。", "上下洞今古，高深察乾坤。", "一旦忽融會，豁然破籬籓。", "笑彼習忘子，讀書嘗憚煩。"]'),
('163b585d-5305-4d67-9138-501c27b220f2','和胡應祥游石井韵','陳文蔚','宋','宋诗','song-poetry','','[]','世間潢潦水，可嘆無根源。',120,'全唐诗/poet.song.173000.json','["世間潢潦水，可嘆無根源。", "盈滿涸可待，驟雨空翻盆。", "鵝峰此邦鎮，秀潤草木繁。", "洩爲石井泉，永與天地存。", "平湖十頃開，風漪綠荷翻。", "意共一脈落，高下相吐吞。", "清游二三丈，歸途月黄昏。", "咫尺阻同集，笑我真憚煩。", "相期一朝去，雷電當飛奔。", "鞭龍起爲雨，微功不須論。"]'),
('916d6110-fdef-4f3e-9e88-c4b2fe0ea22c','壬申老人生旦','陳文蔚','宋','宋诗','song-poetry','','[]','兩歲霜風吹客袍，親庭禮闕捧香醪。',144,'全唐诗/poet.song.173000.json','["兩歲霜風吹客袍，親庭禮闕捧香醪。", "今日升堂祝親壽，親壽願比南山高。", "古來人生七十稀，吾親八十臉如桃。", "但得歲月無窮極，從教兩鬢添霜毛。", "閒中花竹自娛戲，日課詩禮勉兒曹。", "隨分家風嘗禮法，何心與世爭雄豪。", "自古作善天所佑，賦與龐眉并壽絛。", "不須神仙授秘訣，已保柱石常堅牢。", "年年新釀此時熟，真珠滴紅聽小槽。"]'),
('234ce97c-aceb-4199-b5cb-54b65d8ebcba','趙忠州有苦寒懶起之句和其韵','陳文蔚','宋','宋诗','song-poetry','','[]','生息同宇宙，形骸通物我。',48,'全唐诗/poet.song.173000.json','["生息同宇宙，形骸通物我。", "天寒雪盈尺，竈冷爐無火。", "酒面生紅光，花枝嬌婀娜。", "雖然太守樂，亦要民安妥。"]'),
('38aa338a-e597-4a38-9170-c6bebb7f7f49','去草棘','陳文蔚','宋','宋诗','song-poetry','','[]','草雖至微物，稟氣何不同。',156,'全唐诗/poet.song.173000.json','["草雖至微物，稟氣何不同。", "瑞者爲靈芝，大抵和所鍾。", "薰者爲蘭蓀，芬香播春風。", "人知外秀異，胡不原諸中。", "奈何一種類，亦費造化工。", "沾濡足雨露，山川徒茂豐。", "畏冗無地著，無足比蒿蓬。", "成熟不堪食，但逞毫芒鋒。", "除却刺人衣，此外無餘功。", "慘雖未荆棘，包藏固難容。", "因行爲芟除，當路靡留蹤。", "害物亦害己，去汝如去凶。", "安得天地間，榛翳亨衢通。"]'),
('0a61dc26-2600-45e1-9378-cd07ab3c1b98','和余方叔病中見寄','陳文蔚','宋','宋诗','song-poetry','','[]','我亦病閉門，機閒了無觸。',132,'全唐诗/poet.song.173000.json','["我亦病閉門，機閒了無觸。", "故人送詩來，綢繆寫心曲。", "胡乃稽報章，悼往牽服屬。", "天理循自然，非敢故羈束。", "人生壽夭定，心要無愧恧。", "逞欲千乘危，安分一瓢足。", "范雎傾穰侯，酈寄賣呂祿。", "何如北窗卧，酒熟巾自漉。", "况有聖賢書，可洗昏花目。", "一任歲月駛，流徙驚轉矚。", "安知疾疢餘，非以石攻玉。"]'),
('caf4873e-7de1-475d-ac66-6ca5ceda2e8e','用門牌日有好花迎客笑歲蒭新酒奉親歡爲韵爲老人壽','陳文蔚','宋','宋诗','song-poetry','','[]','地僻廣乾坤，身閒多月日。',288,'全唐诗/poet.song.173000.json','["地僻廣乾坤，身閒多月日。", "耕鑿太古民，天然自淳質。", "未始泥神仙，閲世自長久。", "日用飲食餘，帝力我何有。", "修竹三徑幽，青山四時好。", "何須萬間厦，一廛可娛老。", "園柑結新實，籬菊開晚花。", "旋篘甕頭酒，不負老年華。", "田夫與野老，一笑相逢迎。", "只說桑麻事，安知市朝爭。", "年年願今日，有酒可留客。", "雖是無珍饈，隨宜具餚核。", "人言鶴髮翁，翻作朱顔少。", "把酒更何辭，一對西風笑。", "環堵一畝宮，中有長生計。", "秋月與春花，今年又明歲。", "年高親可慶，家貧兒包羞。", "今年勝去年，粗有酒新篘。", "歲月綿綿永，福祿日日新。", "天開九齡數，眼見四世人。", "共樂堂上親，旋約山中友。", "雖是盤無饌，未至樽無酒。", "積善雖人爲，康寧荷天寵。", "但愧儒素風，日乏甘旨奉。"]'),
('e076550e-a80e-4132-9bf5-170bea8ffe6f','夏夜露坐偶書且勉同學子','陳文蔚','宋','宋诗','song-poetry','','[]','人生邂逅如岐路，南北東西忽離聚。',256,'全唐诗/poet.song.173000.json','["人生邂逅如岐路，南北東西忽離聚。", "淵明本賦歸去來，保社乃今隨所寓。", "讀書不雜囂塵聲，好在園林最幽處。", "朱橋跨出林陰外，一水繞庭將綠護。", "有時小立凭危欄，臨風不忍空歸去。", "矧逢暑夕遠燈火，杖策月林時散步。", "更深每與二三子，輟寐每爲清景駐。", "山高望望北斗低，花香拂拂南薰度。", "擬將胸次滌河漢，不管衣巾濕風露。", "清談未必真廢事，言下應當有微悟。", "不妨俯仰更觀察，此意直須起訓詁。", "郊墟次第新涼入，自可燈窗窮入暮。", "凡人努力在年少，老大悲傷欲何訴。", "嗟予學古雖有志，蹭蹬獨爲一生誤。", "鳶魚性分信機淺，風月情懷乃天賦。", "歸哉要結園綺徒，清夜團欒繞庭樹。"]'),
('31e5baa6-80f8-4c09-a71d-9f0d6bf63584','予始生日巖叟携酒見過且有壽語賦此以謝之','陳文蔚','宋','宋诗','song-poetry','','[]','自笑山澤爲癯儒，儕之富貴非其徒。',64,'全唐诗/poet.song.173000.json','["自笑山澤爲癯儒，儕之富貴非其徒。", "他人誕日讌歌酒，貧家簞瓢屢空虛。", "昨朝不記生年月，面前忽見樽罍列。", "感君祝我還祝君，兩翁相對頭如雪。"]'),
('52869ae5-5ce8-43ce-b5b4-b264f1052f48','乙亥老人生旦','陳文蔚','宋','宋诗','song-poetry','','[]','兒願歲歲登斯堂，再拜爲親扶壽觴。',208,'全唐诗/poet.song.173000.json','["兒願歲歲登斯堂，再拜爲親扶壽觴。", "近思去歲生日時，膝下羅列兒孫行。", "更願明年似今日，酒面菊花如意黄。", "人間富貴誰不願，兒只願壽長且康。", "田園薄有可衣食，但要作善思無疆。", "生涯淡淡隨分過，不逐勢利常奔忙。", "初非熊經慕仙術，自是日月閒中長。", "天賦清奇古容貌，精神矍鑠筋骨彊。", "今朝捧酒祝親意，不知何者堪比方。", "欲將吾親比松柏，松柏老不禁風霜。", "欲將吾親比龜鶴，龜齡鶴算終可量。", "溪北柱石山峩峩，蟠根結據由洪荒。", "家居山下不記年，永與山石同蒼蒼。"]'),
('6e409297-1ba0-4ce3-acb5-9970b9e28e8b','責己','陳文蔚','宋','宋诗','song-poetry','','[]','聖人當耳順，吾年已逾再。',60,'全唐诗/poet.song.173000.json','["聖人當耳順，吾年已逾再。", "日覬有新功，邇來如稍怠。", "嗟爾性雖駑，敢不鞭其退。", "須教十二時，此心無不在。", "書此當盤銘，終身以服佩。"]'),
('69ed6a01-70d5-41ed-aed4-5c2381553939','丁丑老人生旦','陳文蔚','宋','宋诗','song-poetry','','[]','箕疇五福孰居一，惟有年高無等匹。',208,'全唐诗/poet.song.173000.json','["箕疇五福孰居一，惟有年高無等匹。", "皆緣作善天降康，視履知當獲元吉。", "貧居衣食雖屢乏，牆下有桑園芋栗。", "乘肥衣輕豈不快，往往久長難可必。", "矍鑠吾翁八十五，骨勁雙瞳如點漆。", "安貧每甘菽水養，雖是形癯心則逸。", "菊花開晚似有意，不爲重陽爲今日。", "成行兒女羅酒漿，拜祝願天從所乞。", "不願分外樂事多，只願親安體無疾。", "不願官書汾陽考，只願親年增秩秩。", "兒孫倘或有生意，此去買田多種秫。", "直須釀酒如春紅，歲歲稱觴無了畢。", "况當風物一年好，盤薦黄橙并綠橘。"]'),
('ca3bf67e-4012-471d-a1e2-ab18dffa57b2','戊寅老人生旦','陳文蔚','宋','宋诗','song-poetry','','[]','吾家本是田家子，其先世世居田里。',224,'全唐诗/poet.song.173000.json','["吾家本是田家子，其先世世居田里。", "兒因逐食浪飄蓬，欲歸無以供甘旨。", "吾翁亦能甘淡薄，日夕飯疏而飲水。", "渾然質朴古人風，固應自有長生理。", "筋骸雖老自康健，聰明少壯猶難比。", "了無機械足怡神，不生嗜好彊精髓。", "人間可慕是榮華，人間可羨爲豪侈。", "榮華有似庭下花，芳菲之日知能幾。", "豪侈真如草頭露，不能頃刻朝陽裏。", "誰知貧賤自安分，年年如此只如此。", "吾鄉自來丙山高，位當南極崔嵬起。", "吾家門門對此山，算高欲與山同紀。", "加之西鄰與東舍，往往黄髮皆兒齒。", "酒熟長願相招呼，一笑忘形相汝爾。"]'),
('9b76d6c3-50e4-4091-90ce-b43e83b509da','自鉛山歸上饒途中感興','陳文蔚','宋','宋诗','song-poetry','','[]','來時積雪歸途熟，暗中流換驚時節。',128,'全唐诗/poet.song.173000.json','["來時積雪歸途熟，暗中流換驚時節。", "所幸康寧九十親，依然堂上垂華髮。", "隨意何當足甘旨，斑衣日戲慈顔悅。", "丈夫事業有用舍，窮通不必生分別。", "直須用力隨處處，無徒瀟灑送日月。", "嗟嗟世人泣岐路，東鄉久哉吾計决。", "終當緤馬扶桑樹，車行萬里誰能遏。", "慷慨自奮歌此章，老去不知情激烈。"]'),
('16feab59-5a7c-4f50-a0ac-9bfd862275ff','送周希顔游章貢','陳文蔚','宋','宋诗','song-poetry','','[]','憶昔吾先師，慷慨歌遠游。',180,'全唐诗/poet.song.173000.json','["憶昔吾先師，慷慨歌遠游。", "超忽凌八荒，咫尺視九州。", "東將征暘谷，挂衣扶桑頭。", "西不畏羊腸，而以摧其輈。", "南轅有遐眺，直指百粵陬。", "北駕何所之，亦欲窮燕幽。", "墮地弧矢志，壯歲無不酬。", "肯學鄙丈夫，拘剪守一丘。", "今日因送子，歌此臨清流。", "江深不可極，負重萬斛舟。", "慨然動高興，不作賈胡留。", "發足真自此，行矣萬里修。", "倘或跨疲蹇，路長殊可憂。", "願言自努力，歲晚當遂謀。", "江山有會意，寄書傳置郵。"]'),
('16e7bfa6-00c7-4300-9c2b-232c70bdffa3','己卯老人生旦','陳文蔚','宋','宋诗','song-poetry','','[]','今朝酒熟吾翁喜，又見生朝會鄰里。',144,'全唐诗/poet.song.173000.json','["今朝酒熟吾翁喜，又見生朝會鄰里。", "雖無盤饌羅羶葷，情話從容自嘉旨。", "人生富貴固足樂，惟有長年難得似。", "恬於世味心自閒，贏得龐眉更兒齒。", "晨興再拜啟阿爹，從古昭昭是天理。", "不因爲善天降祐，何以康寧膺壽祉。", "稱觴膝下列兒孫，雖說居貧良亦美。", "從今都不記春冬，只消歲月將時紀。", "束書但願早還家，年年祝頌秋風裏。"]'),
('6fe62a05-9975-4d31-9f48-2b145d830958','窮冬積雪閔織紡婦','陳文蔚','宋','宋诗','song-poetry','','[]','長哦豳人詩，九月欲授衣。',192,'全唐诗/poet.song.173000.json','["長哦豳人詩，九月欲授衣。", "方當流火辰，先已戒其期。", "當春非不蠶，入夏非不絲。", "一寸不上身，止爲憂啼饑。", "蠶畢起功績，關心聽鳴鵙。", "豈不念人生，所急在衣食。", "衣單寒不禦，鶉結百千縷。", "輕裘那得知，凄其良自苦。", "窮冬歲將往，雪片大如掌。", "憐他昨日織，安知今日紡。", "嬌癡貴安女，未始識機杼。", "紈綺厭不華，繒帛何曾數。", "貧富固有分，茫茫何足論。", "感觸此時心，寧不哀窮困。", "馮誰歌七月，俾汝知時節。", "塞墐聊補紉，團欒圍榾柮。"]'),
('6af0f83f-e6b5-4670-af30-c2c91c6a70e7','建德道中六言','陳文蔚','宋','宋诗','song-poetry','','[]','有底可人情意，盡是酒村魚市。',28,'全唐诗/poet.song.173000.json','["有底可人情意，盡是酒村魚市。", "行人忘却家鄉，沽酒買魚供醉。"]'),
('09135bfe-a54f-4737-b07b-579601fa24fb','徐敬甫出示所居之別墅南巖圖并諸公題詠欲予同作爲賦長韵','陳文蔚','宋','宋诗','song-poetry','','[]','憶昔同作康山游，杖屨歷遍千巖幽。',352,'全唐诗/poet.song.173000.json','["憶昔同作康山游，杖屨歷遍千巖幽。", "知君已具看山眼，每遇勝處嘗淹留。", "從茲一去間何闊，倒指殆欲忘春秋。", "不知此地復何地，但見大江東去流。", "相逢恍然如隔世，盡洗積年離別愁。", "首爲袖出南巖圖，著鞭先我占一丘。", "南巖之高不可攀，俗駕欲到何緣由。", "君乃結屋於其巔，避世擬追園綺儔。", "雪飛霜瀑自天落，戟列萬竹干雲修。", "客來煮茗話疇昔，酒熟春禽相勸酬。", "自言得此已足老，豈復更懷身世憂。", "無心偶作雲出岫，良念棣萼情綢繆。", "對床聽雨有真意，肯放拂衣歸去休。", "登高一日展遐眺，洗眼九華雲漬收。", "語我南巖卜築地，只放五老高一頭。", "丹梯萬丈徑可躡，獨恨未遂曾往謀。", "我生亦有山水癖，欲見未見心先投。", "長哦南山白石爛，夢寐滄江飛白鷗。", "歸與亟辦買山計，甘與世好相盾矛。", "采蕨可以忘朝饑，種橘自當千戶侯。", "眷言志事在𤱶畝，適我願兮遑他求。", "此時作書報同志，知肯遠爲題詩不。"]'),
('f0fb5ced-e19f-4943-b1e0-3e6b5d5d021a','石潭道中追賦大江','陳文蔚','宋','宋诗','song-poetry','','[]','我生大江東，與江不相識。',144,'全唐诗/poet.song.173000.json','["我生大江東，與江不相識。", "一日作遠遊，江頭因目極。", "桃花春未漲，水落略見石。", "望斷淮山青，隔岸纔咫尺。", "恃此一葦航，焉能恨南極。", "雲屯十萬衆，守衛以人力。", "撫御有良將，成城衆心得。", "江淮唇齒勢，如家護牆壁。", "守淮即守江，淮民須愛惜。", "我朝聖澤深，不在險在德。", "慈儉今天子，邇遐無間隔。", "大臣百執事，根本共培植。"]'),
('f0091eb0-25cd-4d23-9dc3-8370b7c00559','追賦九華','陳文蔚','宋','宋诗','song-poetry','','[]','我聞九華名，未登九華峰。',168,'全唐诗/poet.song.173000.json','["我聞九華名，未登九華峰。", "睨視百里外，烟翳嘗冥濛。", "快意一披抉，幾欲挾長風。", "庶識真面目，高下俱迎逢。", "飛雪如有意，未積先消融。", "凌晨展清眺，萬里開晴空。", "炯然明吾眸，洗出青芙蓉。", "未暇窺杳眇，固已領其宗。", "憶昔訪廬阜，妙處嘗支筇。", "景遇可題品，一一歸詩筒。", "九華名此邦，挺挺諸山雄。", "若欲於五老，優劣定其中。", "竊比之孔門，等級回與雍。", "未敢謂覈論，折衷章泉翁。"]'),
('4b7957b2-0002-4e62-a041-ae442be0c43d','追賦秋浦','陳文蔚','宋','宋诗','song-poetry','','[]','我爲秋浦遊，欲訪秋浦跡。',132,'全唐诗/poet.song.173000.json','["我爲秋浦遊，欲訪秋浦跡。", "及已到此邦，秋浦無處覓。", "或云百里間，始見江祖石。", "或云江祖石，止在齊山側。", "地形著山川，記載具文籍。", "父兄世流傳，論且不可覈。", "况出形器表，理可俄而測。", "所以聖人心，貴在於默識。", "不然差毫釐，千里成舛忒。", "想今錦鷤鳥，欲見已不得。", "試聽白猿吟，儻能喧夜寂。"]'),
('8109c7a3-589d-4d48-8fb7-9e128f5d5222','入郭回度黄沙嶺息木陰下口占古意','陳文蔚','宋','宋诗','song-poetry','','[]','孰驅我去，孰驅我歸。',50,'全唐诗/poet.song.173000.json','["孰驅我去，孰驅我歸。", "息蔭喬木，清風吹衣。", "火日炎空，聊此徘徊。", "夷險自若，怨尤誰哉。", "世間萬事，付酒一杯。"]'),
('f629b917-cb6b-466a-81db-28320139fcdd','辛巳老人生旦','陳文蔚','宋','宋诗','song-poetry','','[]','陶陶太古民風淳，詐僞不萌情意真。',176,'全唐诗/poet.song.173000.json','["陶陶太古民風淳，詐僞不萌情意真。", "何嘗吐納事屈伸，往往皆爲百歲人。", "中古便似秋冬辰，和氣無復如陽春。", "機巧百出妄喜嗔，七十者稀以爲珍。", "我翁逍遥常幅巾，朴素幾與太古鄰。", "飲食淡泊厭羶葷，衣裘不擇敝與新。", "日日娛嬉寂寞濱，甘與聖世爲遺民。", "天錫遐齡登九旬，回視同庚皆土塵。", "炯然雙眸且精神，堅彊直可齊松椿。", "兒孫雖不側朝紳，家庭禮法粗克遵。", "白酒年年造逡巡，膝下戲綵娛慈親。"]'),
('6d92f368-530a-4212-939a-e7c51b4845ce','周道人求詩書贈','陳文蔚','宋','宋诗','song-poetry','','[]','道人妙推算，未知誰賞音。',48,'全唐诗/poet.song.173000.json','["道人妙推算，未知誰賞音。", "章泉謹許可，贈之五字吟。", "老我已無用，窮通總無心。", "但思結茆地，訪君白雪深。"]'),
('3f7882c5-1512-4b19-a4e3-936d23933966','荷湖行爲趙忠州壽','陳文蔚','宋','宋诗','song-poetry','','[]','青山屋上名荷湖，故知下有神仙居。',204,'全唐诗/poet.song.173000.json','["青山屋上名荷湖，故知下有神仙居。", "全似太華峰頭玉井樣，花開十丈世所無。", "自有天地此山有，誰人種得如船藕。", "造物不肯輕畀付，付與湛溪雲隠手。", "雲隠濟人陰德多，有如此藕痊沉痾。", "自煉還丹成九轉，方瞳點漆顔長酡。", "甚不愛飛霞千樹結蟠桃，甚不愛湛溪千頃漲葡萄。", "蟠桃入口那能甘比蜜，湛溪不抵酒滴真珠槽。", "愛蓮往往緣青壁，俯笑凡人無路覓。", "不知身世若爲高，但見照人雙眼碧。", "寄語峰頭十丈花，年年來伴棗如瓜。", "不須更記歲與月，只記山前雲隠家。"]'),
('41dece42-b9fb-440c-be50-022539b9efa2','癸未老人生旦','陳文蔚','宋','宋诗','song-poetry','','[]','昔人端爲祈黄耈，再拜慇懃扶大斗。',224,'全唐诗/poet.song.173000.json','["昔人端爲祈黄耈，再拜慇懃扶大斗。", "吾翁今年九十一，兒從兩歲貧無酒。", "趨庭何以祝彌誕，盈把菊花空在手。", "嗅香嚼蘂當甘旨，翁亦怡然如適口。", "人生貧富在分定，獨是期頤世稀有。", "翁餘九十兒七十，膝下龐眉仍皓首。", "若將此事較人間，豈非造物意愈厚。", "因茲歷歷詔兒孫，自古悅親惟孝友。", "上惇下睦無間言，一門和氣薰蒸久。", "雖無旨酒奉杯酌，意樂心寬親自壽。", "更於大節保終始，立身揚名以垂後。", "世上榮親無若此，何必金章并紫綬。", "南鄰白酒况可賒，豐儉隨家惟用缶。", "年年此舉諒不難，甲子無窮環癸丑。"]'),
('3472cb07-1324-4d4d-a4aa-d53aa510fc58','寄題俞伯南所居 希賢','陳文蔚','宋','宋诗','song-poetry','','[]','毋爲陵學山，當爲川學海。',24,'全唐诗/poet.song.173000.json','["毋爲陵學山，當爲川學海。", "尹重貴自任，顔樂誓不改。"]'),
('9eb12a1e-7bd7-486e-8545-afc769a65949','寄題俞伯南所居 野處','陳文蔚','宋','宋诗','song-poetry','','[]','巖築無外求，莘耕有餘樂。',24,'全唐诗/poet.song.173000.json','["巖築無外求，莘耕有餘樂。", "既爲堯舜民，自抱羲農朴。"]'),
('ac47b2e9-6f69-40a6-9aae-0eeee5e2c18d','寄題俞伯南所居 毅齋','陳文蔚','宋','宋诗','song-poetry','','[]','器重或可勝，道遠疇能至。',24,'全唐诗/poet.song.173000.json','["器重或可勝，道遠疇能至。", "勉效既竭回，羞稱願息賜。"]'),
('435821ca-226f-4be4-b10b-17358b28d7c8','石溪道中偶作','陳文蔚','宋','宋诗','song-poetry','','[]','自從天地開闢來，溪水清駛山崔嵬。',256,'全唐诗/poet.song.173000.json','["自從天地開闢來，溪水清駛山崔嵬。", "山高水清亦奇觀，怪問胡不生人材。", "人材本作世間用，朴仆支傾作梁棟。", "不然空冒一時名，過眼空花已如夢。", "人生出處不可期，伊周亦偶遭明時。", "顔閔何嘗有科目，德尊百代帝王師。", "自古相傳惟此道，一派源流端可考。", "道存不係窮與通，經濟業窮耕釣老。", "風埃鼎鼎百年中，世事興廢何終窮。", "只有詩書傳聖學，堯舜授受同高風。", "喚醒此原山與水，孕秀發祥從此始。", "立朝有道佐明君，抱璞山林亦奇偉。", "吾家家此不計年，未知起者誰其先。", "丈夫才業貴自負，不必美惡歸山川。", "久欲題詩磨翠壁，要使後來聞義激。", "乾坤造化豈無人，細與摩挲觀此石。"]'),
('e6aee0ea-98bf-4636-a767-6256c7855185','諸君用東坡玉堂觀郭熙畫詩韵題江山王君平遠樓黄子京携至求同作','陳文蔚','宋','宋诗','song-poetry','','[]','有客有客心地閒，樓外青林林外山。',128,'全唐诗/poet.song.173000.json','["有客有客心地閒，樓外青林林外山。", "風烟出沒美無度，依約圖畫有無間。", "眼隨白鳥去邊遠，一聲漁唱江村晚。", "此時誰會倚欄心，雲出不知何處巘。", "歲寒松柏飽風霜，肯逐桃李爭春陽。", "安得共卧百尺樓，爲挹江瀨吞山光。", "當年影過八磚日，坡仙想像頻搔髮。", "無言細玩郭熙畫，應思老去尋泉石。"]'),
('43d0c90b-8375-49b5-9bc4-f489a26e1eed','寄題玉山周晦叔家似賢齋','陳文蔚','宋','宋诗','song-poetry','','[]','人心殊嗜好，黑白互相形。',132,'全唐诗/poet.song.173000.json','["人心殊嗜好，黑白互相形。", "逐臭不自悟，熒熒飛青蠅。", "一日對此君，炯然雙眼明。", "子猷雖借宅，綠陰仍滿庭。", "雅凈兩龔潔，高寒伯夷清。", "可近不可狎，勁挺干青冥。", "世人景先哲，繪畫勞丹青。", "想像不覿面，孔孟何由傾。", "安知君子交，日日與相迎。", "手種萬蒼玉，君家有典刑。", "清風流至今，修好無渝盟。"]'),
('e1be7385-0edb-42c4-a3ae-bbd24a2244cc','題周幾道桂軒','陳文蔚','宋','宋诗','song-poetry','','[]','軒前一樹桂，手種知爲誰。',48,'全唐诗/poet.song.173000.json','["軒前一樹桂，手種知爲誰。", "但見青如蓋，團圓障朝曦。", "西風入庭戶，吹香浮酒巵。", "相與一浩歌，渙焉剖藩籬。"]'),
('3d11e938-acb3-4ae0-af38-c529036b1cd6','玉山朱文龍有遺經林野二處趙昌甫程德夫皆有詩朱求予同作 遺經','陳文蔚','宋','宋诗','song-poetry','','[]','漢人一經訓，籯金云不如。',24,'全唐诗/poet.song.173000.json','["漢人一經訓，籯金云不如。", "君家遺經意，不與漢人俱。"]'),
('45167b70-2752-4839-ab7d-d2582398d221','玉山朱文龍有遺經林野二處趙昌甫程德夫皆有詩朱求予同作 林野','陳文蔚','宋','宋诗','song-poetry','','[]','有人抱幽真，偏適林野趣。',24,'全唐诗/poet.song.173000.json','["有人抱幽真，偏適林野趣。", "要之等喧寂，乃是安心處。"]'),
('5432482f-c0b7-4950-8042-f9307938a239','薛玠兩投詩以古風謝之','陳文蔚','宋','宋诗','song-poetry','','[]','知君家住象山麓，日有見聞新耳目。',144,'全唐诗/poet.song.173000.json','["知君家住象山麓，日有見聞新耳目。", "自憐各在天一涯，休譽惟能採鄉曲。", "却來一見玉溪頭，已知標致非凡俗。", "等閑揮翰墨淋浪，惠我新詩不金玉。", "細將學問說根源，異同更與明朱陸。", "吾道工夫有端緒，要是義精仁乃熟。", "博文約禮是真傳，收拾奇功歸謹獨。", "參前倚衡勿間斷，千載斷絃端可續。", "手披詩卷荷情真，聊以斯言報諄復。"]'),
('49672107-75af-47f7-8bdd-896dba516754','永邑楊君鑑子明闢齋讀書將從事於古人爲己之學求齋名於予并欲得一語以示爲學之方予謂學雖多端而其要莫先於明善所以子思孟子俱以此開道後學大學格物之訓實同出一源故因楊君之請扁以明善且詩以演其義幸毋忽其言之陋云','陳文蔚','宋','宋诗','song-poetry','','[]','人性靡不善，因物始有遷。',156,'全唐诗/poet.song.173000.json','["人性靡不善，因物始有遷。", "本體遭剝蝕，如鑑塵所昏。", "疇昔均秉彝，善端本綿綿。", "既茂閑邪功，誠心所由存。", "若爲用力地，格物居其先。", "萬殊一理貫，洞然見本根。", "表裏俱澄澈，斷斷義理分。", "言動中倫慮，狂愚詎同論。", "彼哉迷復子，一息萬里奔。", "認贅以爲嫡，未嘗知反觀。", "君子審取舍，不容涇渭渾。", "中扃瞭如燭，肯蔽耳目官。", "中庸示明訓，一言會其元。"]'),
('6bfece6c-9b27-4458-af7f-cca565f8b259','汪元思遺詩和意以謝','陳文蔚','宋','宋诗','song-poetry','','[]','吾道本公平，何嘗分彼此。',264,'全唐诗/poet.song.173000.json','["吾道本公平，何嘗分彼此。", "總只在人心，渾然皆天理。", "推原賦予初，所鍾均粹美。", "賢愚同一轍，所行無意軌。", "由其氣稟異，於焉有臧否。", "清者洞然明，泓澄如止水。", "濁者性天蒙，蕩然惟縱弛。", "末雖有善惡，反之即其始。", "變化在乎人，雖愚必明矣。", "日用無餘功，自修惟克己。", "近代朱文公，此道頼綱紀。", "居嘗語學者，虛名以爲恥。", "必先由博學，然後能約禮。", "顔淵躬四勿，魯參悟一唯。", "吁嗟今世人，非不究經旨。", "議論徒紛紜，反躬乖踐履。", "好惡徇私情，是非隨慍喜。", "體既雜真妄，用斯殊表裏。", "要在無間斷，善端勤積累。", "須臾不可忘，顛沛必如是。", "堅持敬一字，方知道在邇。", "我輩無他求，直須安汝止。"]'),
('90859327-6d0e-4013-ac09-973bc68c531a','辛丑春遊金華出東郊','陳文蔚','宋','宋诗','song-poetry','','[]','青山雙夾小溪流，綠篠人家古渡頭。',32,'全唐诗/poet.song.173000.json','["青山雙夾小溪流，綠篠人家古渡頭。", "雖是溪山不相識，勸人啼鳥却相留。"]'),
('ffe90eb4-3d26-4bbb-980c-45413ddc05dc','常山道中','陳文蔚','宋','宋诗','song-poetry','','[]','路勢弓腰轉，湖光鑑面開。',48,'全唐诗/poet.song.173000.json','["路勢弓腰轉，湖光鑑面開。", "稻田春事給，村碓晚舂催。", "問宿尚十里，與誰同一杯。", "自憐今日首，頻作望鄉回。"]'),
('c84ce5d3-d81b-4738-b1df-34905f5f3330','甲辰九月初訪晦菴先生大安道中和余正叔韵','陳文蔚','宋','宋诗','song-poetry','','[]','瀟瀟風露菊花秋，人在甌閩第一州。',64,'全唐诗/poet.song.173000.json','["瀟瀟風露菊花秋，人在甌閩第一州。", "少日已嘗懷壯志，今朝端不負清遊。", "陪君數日從容語，洗我平生散亂愁。", "從此歸來復何事，風濤雖險奈虛舟。"]'),
('616ade9d-edac-4937-b0cf-e3ef8587a11e','歸鉛山正叔復用前韵和答之','陳文蔚','宋','宋诗','song-poetry','','[]','歛藏先用肅如秋，次第陽和遍九州。',64,'全唐诗/poet.song.173000.json','["歛藏先用肅如秋，次第陽和遍九州。", "歲月正緣閑裏度，紛囂那得靜中遊。", "明知與點有真樂，未足希顔却自愁。", "諷詠棹歌思九曲，與君重約泛扁舟。"]'),
('35432082-4c25-4ef6-a21b-4ae6863376e2','和正叔詠梅一絕','陳文蔚','宋','宋诗','song-poetry','','[]','兒童剪伐未須施，竹外橫斜一兩枝。',32,'全唐诗/poet.song.173000.json','["兒童剪伐未須施，竹外橫斜一兩枝。", "冷艷更開深雪裏，此花應不冀人知。"]'),
('efa3a0e4-7fb4-47d0-8b8c-c41dfdc11b13','和李監稅','陳文蔚','宋','宋诗','song-poetry','','[]','一縷彤霞晚照晴，眼隨白鳥去邊明。',64,'全唐诗/poet.song.173000.json','["一縷彤霞晚照晴，眼隨白鳥去邊明。", "疏疏烟樹有無際，激激灘流高下聲。", "歸思楚雲連日暮，新詩邊月带霜清。", "前村倘有梅花約，草草相逢蓋亦傾。"]'),
('13173846-1a16-43bd-9948-b9a3f9562f73','和徐子融見寄','陳文蔚','宋','宋诗','song-poetry','','[]','學問分明有本根，一編魯論幸今存。',64,'全唐诗/poet.song.173000.json','["學問分明有本根，一編魯論幸今存。", "奈何至理難窮究，願與良朋細討論。", "欲探聖傳千古祕，莫令心鑑一毫昏。", "吾儕總在生成內，要識無私造化恩。"]'),
('b5f4ac3d-773a-4801-95c0-eb9613faf99b','記夢','陳文蔚','宋','宋诗','song-poetry','','[]','夢裏分明記本根，覺來無語正心君。',32,'全唐诗/poet.song.173000.json','["夢裏分明記本根，覺來無語正心君。", "陰陽却把量消長，且喜新來勝一分。"]'),
('add197bf-a58a-440d-9493-6741a381e45d','示浩','陳文蔚','宋','宋诗','song-poetry','','[]','持身端的在兢兢，謹獨方無愧怍情。',32,'全唐诗/poet.song.173000.json','["持身端的在兢兢，謹獨方無愧怍情。", "莫道隠微人不見，暗中臨我有神明。"]'),
('eaee9878-4017-4c97-92a1-582ce0f17468','雨中即事','陳文蔚','宋','宋诗','song-poetry','','[]','客身常恨春多雨，遥想吾廬長綠苔。',32,'全唐诗/poet.song.173000.json','["客身常恨春多雨，遥想吾廬長綠苔。", "每作家書問無恙，故園梅竹爲新栽。"]'),
('8ba2ddf4-8452-4fb4-8538-6af6b02eb716','送趙國開赴崇安丞','陳文蔚','宋','宋诗','song-poetry','','[]','十載交遊一日如，高情多謝不相疏。',64,'全唐诗/poet.song.173000.json','["十載交遊一日如，高情多謝不相疏。", "分携幸不隔江海，得便常須訪起居。", "折柳正當三月暮，汎舟深約九秋餘。", "相期暇日吟哦外，只有公勤是薦書。"]'),
('8c1ff5f4-f867-49f8-bfc5-31c450b5a77b','和徐子融韵  其一','陳文蔚','宋','宋诗','song-poetry','','[]','遜敏工夫不可偏，兩端相濟若韋弦。',32,'全唐诗/poet.song.173000.json','["遜敏工夫不可偏，兩端相濟若韋弦。", "允懷固是常存養，明善誰知合在先。"]'),
('828bdd3c-2adb-4f5d-b0f7-3a780566029f','和徐子融韵  其二','陳文蔚','宋','宋诗','song-poetry','','[]','讀書端的在研窮，洞貫精粗與始終。',32,'全唐诗/poet.song.173000.json','["讀書端的在研窮，洞貫精粗與始終。", "卓爾顔淵有真見，分明來自博文中。"]'),
('23580051-1d33-46f9-8fba-e15da6e129c7','和徐子融韵  其三','陳文蔚','宋','宋诗','song-poetry','','[]','雨餘雲靜太虛澄，月在今宵分外清。',32,'全唐诗/poet.song.173000.json','["雨餘雲靜太虛澄，月在今宵分外清。", "喜得佳篇來諷詠，世間榮辱一毫輕。"]'),
('d61d79f7-ea37-4a52-8564-5c6d9fc080bd','和徐子融韵  其四','陳文蔚','宋','宋诗','song-poetry','','[]','自憐涉世每多艱，事到縈心或厭煩。',32,'全唐诗/poet.song.173000.json','["自憐涉世每多艱，事到縈心或厭煩。", "近日工夫何所似，有時慚愧夢中閑。"]'),
('e4176a31-2896-4bea-9fb1-b19e5194e108','庚戌春下鄱陽舟中諸作 解舟汭口','陳文蔚','宋','宋诗','song-poetry','','[]','浩蕩春江洗客愁，歌聲欵乃發中流。',32,'全唐诗/poet.song.173000.json','["浩蕩春江洗客愁，歌聲欵乃發中流。", "溪齋却憶凭欄日，數盡來舟與去舟。"]'),
('f258ea20-65d0-4352-9912-b87b6b4592f1','庚戌春下鄱陽舟中諸作 過赭亭','陳文蔚','宋','宋诗','song-poetry','','[]','船篷推起不教低，爲放山光水色歸。',32,'全唐诗/poet.song.173000.json','["船篷推起不教低，爲放山光水色歸。", "客子離家已三日，赭亭山下欲斜暉。"]'),
('c0aa1a91-20a5-427f-b356-6397fe4dd32b','庚戌春下鄱陽舟中諸作 過桃花臺','陳文蔚','宋','宋诗','song-poetry','','[]','櫓聲終日聽咿啞，碧浪紅旌動彩霞。',32,'全唐诗/poet.song.173000.json','["櫓聲終日聽咿啞，碧浪紅旌動彩霞。", "獨我船中無一事，安排詩句過桃花。"]'),
('f7186212-4c70-4fc8-9bad-eeaaaaede488','庚戌春下鄱陽舟中諸作 過安仁界','陳文蔚','宋','宋诗','song-poetry','','[]','遠山淡淡水茫茫，知是江湖何處鄉。',32,'全唐诗/poet.song.173000.json','["遠山淡淡水茫茫，知是江湖何處鄉。", "娘子提携青裹布，始知風土近鄱陽。"]'),
('093e7e77-2d39-4b02-b88e-a701999426d5','書窗碧桃','陳文蔚','宋','宋诗','song-poetry','','[]','銅瓶只插碧桃花，日對幽人靜不譁。',32,'全唐诗/poet.song.173000.json','["銅瓶只插碧桃花，日對幽人靜不譁。", "爲爾細觀冰雪艷，就中便覺牡丹夸。"]'),
('6711e7a4-e89b-4071-93d9-37c5a85da46f','病中對竹','陳文蔚','宋','宋诗','song-poetry','','[]','窗外修篁僅百竿，相看不待報平安。',32,'全唐诗/poet.song.173000.json','["窗外修篁僅百竿，相看不待報平安。", "何時得我身彊健，共爾青青到歲寒。"]'),
('1f662721-1b6f-4add-aeec-7b3d51a7b080','和子融韵','陳文蔚','宋','宋诗','song-poetry','','[]','爲把新詩子細尋，時移不覺日西沉。',32,'全唐诗/poet.song.173000.json','["爲把新詩子細尋，時移不覺日西沉。", "固知妙旨存精一，須察人心與道心。"]'),
('88049c1d-7974-4ddd-bfcd-2464457b9ca0','又和清明日兀坐用前韵','陳文蔚','宋','宋诗','song-poetry','','[]','天理流行不用尋，鳶飛魚躍自升沉。',32,'全唐诗/poet.song.173000.json','["天理流行不用尋，鳶飛魚躍自升沉。", "細觀自有昭然處，始信嚴師是此心。"]'),
('cba10eab-9b07-4b07-a474-24ac4d39c863','和子融聞琴','陳文蔚','宋','宋诗','song-poetry','','[]','古曲誰彈起，千年無此音。',48,'全唐诗/poet.song.173000.json','["古曲誰彈起，千年無此音。", "尚憐惟韵在，端欲後人尋。", "指上雖傳操，聲中要識心。", "半生孤此志，絃續自而今。"]'),
('17f44e85-f331-4705-a135-afa218f5a344','趙守禱雨有感枕上得句足成五十六字呈趙守','陳文蔚','宋','宋诗','song-poetry','','[]','雨意隨人自及時，使君一念實通微。',64,'全唐诗/poet.song.173000.json','["雨意隨人自及時，使君一念實通微。", "不知沛澤人間遍，但覺炎蒸夢裏非。", "苗稼頓回枯欲死，桑林又喜綠添肥。", "從今飽喫鄱陽飯，細紀賢侯德政歸。"]'),
('48556511-892e-4b8a-920f-89e64e328891','七月廿六日登四望亭小酌和趙守韵二絕  其一','陳文蔚','宋','宋诗','song-poetry','','[]','爲愛黄雲到晚晴，一樽高興寄危亭。',32,'全唐诗/poet.song.173000.json','["爲愛黄雲到晚晴，一樽高興寄危亭。", "風荷捲水高低綠，烟樹連山遠近青。"]'),
('2e789b1e-7181-405e-9123-86d8ca6d415a','七月廿六日登四望亭小酌和趙守韵二絕  其二','陳文蔚','宋','宋诗','song-poetry','','[]','極目風煙盡一城，身閑無日不登亭。',32,'全唐诗/poet.song.173000.json','["極目風煙盡一城，身閑無日不登亭。", "雙明遠與孤鴻沒，繞郭一江羅带青。"]'),
('e616b1a5-da98-4e44-b154-31ba309b44e9','和趙守木犀','陳文蔚','宋','宋诗','song-poetry','','[]','花開時節趁柔金，冷露繁霜未許侵。',32,'全唐诗/poet.song.173000.json','["花開時節趁柔金，冷露繁霜未許侵。", "况是天香無俗韵，一樽清賞有知音。"]'),
('7962dbc2-44f1-4197-8e77-909a54476031','送歐陽國瑞歸鉛山','陳文蔚','宋','宋诗','song-poetry','','[]','交遊無數竟誰同，雅羨夫君氣似虹。',64,'全唐诗/poet.song.173000.json','["交遊無數竟誰同，雅羨夫君氣似虹。", "吾道久隨流俗弊，義居今見古人風。", "端能縱目秦淮上，邂逅論文楚水東。", "歸去梅花開也未，江頭葉葉剪霜風。"]'),
('252df8ac-c809-4776-8c78-d7a646c31708','寄題吳伯豐同榮堂','陳文蔚','宋','宋诗','song-poetry','','[]','一氣同流舉切身，胡然於此限比鄰。',64,'全唐诗/poet.song.173000.json','["一氣同流舉切身，胡然於此限比鄰。", "直須靜處工夫到，便覺閑中意思真。", "心遠獨游千載上，客來共醉一樽醇。", "寓形宇內皆生意，何但名園草木春。"]'),
('eab65bc5-d5c0-4318-9a2e-a2d0bb81bd80','舟行望龜峰','陳文蔚','宋','宋诗','song-poetry','','[]','面對靈龜最上峰，舟中活計不爲窮。',64,'全唐诗/poet.song.173000.json','["面對靈龜最上峰，舟中活計不爲窮。", "半春臺下桃花水，一霎岸邊楊柳風。", "天巧此時窮險怪，淵泉終日悟流通。", "一生堪笑漁翁拙，卧聽瀟瀟雨打篷。"]'),
('3bb5c252-877d-4c04-ae56-4e9bb0c0f122','舟次蘭溪和歐陽國瑞韵','陳文蔚','宋','宋诗','song-poetry','','[]','客子經行處，吳江萬頃秋。',48,'全唐诗/poet.song.173000.json','["客子經行處，吳江萬頃秋。", "風煙曉濃淡，雲樹遠稀稠。", "緩去花相送，重來鳥勸留。", "與君無楚粵，一笑况同舟。"]'),
('681ce6a1-dcae-4a14-80ef-faaad2226ae2','贈陳敬甫','陳文蔚','宋','宋诗','song-poetry','','[]','鄱水相逢亦偶然，吳中邂逅復掀髯。',32,'全唐诗/poet.song.173000.json','["鄱水相逢亦偶然，吳中邂逅復掀髯。", "細思話別秋風日，已是浮生一歲添。"]'),
('182f14bf-58ef-4213-8110-82ec3a68af55','月臺觀月','陳文蔚','宋','宋诗','song-poetry','','[]','秋來無日不登臨，獨喜今宵月滿襟。',64,'全唐诗/poet.song.173000.json','["秋來無日不登臨，獨喜今宵月滿襟。", "仰面青天思把酒，寄情古調欲携琴。", "涼風舞袂身將舉，白露沾衣夜向深。", "要看一臺清影滿，儘教移轉碧梧陰。"]'),
('b0ea12c6-5ef0-4e8d-a4c0-8aa9bdeef02d','又和歐陽國瑞韵','陳文蔚','宋','宋诗','song-poetry','','[]','臺高無奈月明何，豈憚攀緣上岌峩。',64,'全唐诗/poet.song.173000.json','["臺高無奈月明何，豈憚攀緣上岌峩。", "萬壑秋聲歸草木，百年鄉思動關河。", "遥知素影千家共，不獨秋光此地多。", "中夜酒酣狂欲舞，停杯且復聽吳歌。"]'),
('5c08108a-6ff7-4c79-912f-85597bc9dd03','和趙工部臨安見寄韵','陳文蔚','宋','宋诗','song-poetry','','["\u897f\u6e56"]','節物驚人故欲催，天涯倦客幾時回。',64,'全唐诗/poet.song.173000.json','["節物驚人故欲催，天涯倦客幾時回。", "坐傾濁酒醒還醉，手把新詩捲又開。", "遠想含香當奏事，近緣無月不登臺。", "烟波見說西湖好，要趁秋風把釣來。"]'),
('eb4ebd85-66d2-463f-b0f9-5cb0e2419d67','十一月十四夜誦康節詩至憶弟三首潸然有感','陳文蔚','宋','宋诗','song-poetry','','[]','人生雖是有愚賢，到底天倫只一般。',32,'全唐诗/poet.song.173000.json','["人生雖是有愚賢，到底天倫只一般。", "惆悵同安何處所，不堪歲暮更天寒。"]'),
('da7fe3a5-63cd-4b7c-8a41-d7c92ea5abcc','自吳中歸過釣臺','陳文蔚','宋','宋诗','song-poetry','','[]','倦游偶得賦歸來，我亦何心世莫猜。',32,'全唐诗/poet.song.173000.json','["倦游偶得賦歸來，我亦何心世莫猜。", "水綠山青從所好，一帆風過釣魚臺。"]'),
('0850a20c-de0a-4f5f-a76a-f62aa0605252','過趙清獻墓居','陳文蔚','宋','宋诗','song-poetry','','[]','爲讀忠臣孝子碑，欲行回首重依依。',32,'全唐诗/poet.song.173000.json','["爲讀忠臣孝子碑，欲行回首重依依。", "紛紛車馬門前過，知有幾人琴鶴歸。"]'),
('f53f9dd0-82a4-4bb7-b7ed-7a0da5b2f452','見梅','陳文蔚','宋','宋诗','song-poetry','','[]','曉鷄殘月更離程，只見梅花不忍行。',32,'全唐诗/poet.song.173000.json','["曉鷄殘月更離程，只見梅花不忍行。", "水郭山村誰是伴，惟伊與我共孤清。"]'),
('f511a3c1-6421-4ca0-9a0a-aabd909d6916','望靈山喜而又作','陳文蔚','宋','宋诗','song-poetry','','[]','白雲深處認靈山，喜氣津津眉宇間。',32,'全唐诗/poet.song.173000.json','["白雲深處認靈山，喜氣津津眉宇間。", "別去庭闈今八月，且欣明日慰親顔。"]'),
('7a72a3e7-f071-44c1-8a5b-2d9e7d36ebf1','程子雲欲還鄉阻雨聊戲之','陳文蔚','宋','宋诗','song-poetry','','[]','霏霏小雨釀梅黄，結束琴書底用忙。',64,'全唐诗/poet.song.173000.json','["霏霏小雨釀梅黄，結束琴書底用忙。", "已幸一春鄰絳帳，祇今十日是端陽。", "榴花照眼新篁翠，盧橘盈盤煮酒香。", "天識主人留客意，故教歸路滑羊腸。"]'),
('b956a4f8-6a1b-42b5-8cc4-e416884509ff','探梅不遇登祈雨峰','陳文蔚','宋','宋诗','song-poetry','','[]','人生何處不從容，旋向僧家借短筇。',32,'全唐诗/poet.song.173000.json','["人生何處不從容，旋向僧家借短筇。", "那爲孤芳窮僻遠，要留脚力上高峰。"]'),
('63dea410-96fe-4fb7-bd14-1ad4c5f2cd4e','送彭應期下鄱陽','陳文蔚','宋','宋诗','song-poetry','','[]','當年心事幾綢繆，長記天西玉一鈎。',64,'全唐诗/poet.song.173000.json','["當年心事幾綢繆，長記天西玉一鈎。", "客裏近來嗟我倦，江邊重得送君游。", "讀書會有新功用，把酒聊尋舊倡酬。", "自愧不能追往事，但勞清夢繞螺州。"]'),
('ac35f3c6-c006-4f4c-b446-c68b29d77a8c','湛溪納凉','陳文蔚','宋','宋诗','song-poetry','','[]','是處皆炎熱，澄江消客憂。',48,'全唐诗/poet.song.173000.json','["是處皆炎熱，澄江消客憂。", "相邀讀書罷，同作浴沂遊。", "自喜坐茂樹，誰能喚小舟。", "月華如有待，先在柳梢頭。"]'),
('6d10f220-0c0e-44ed-8b6d-791172bfea70','夜坐有感年四十','陳文蔚','宋','宋诗','song-poetry','','[]','仲尼切戒取人惡，孟子真能不動心。',32,'全唐诗/poet.song.173000.json','["仲尼切戒取人惡，孟子真能不動心。", "嗟我癡頑何所得，但能於此惜分陰。"]'),
('01add4d7-c1fc-42a6-aa5c-06387c31bca0','徐子融八月四夜見訪值予有出寄詩三絕和韵以謝  其一','陳文蔚','宋','宋诗','song-poetry','','[]','雲開日脚漏微明，無奈秋風掠面清。',32,'全唐诗/poet.song.173000.json','["雲開日脚漏微明，無奈秋風掠面清。", "因作西鄰閒縱步，不知乘興有高情。"]'),
('18d768c5-0207-4500-a8f9-d037e16add78','徐子融八月四夜見訪值予有出寄詩三絕和韵以謝  其二','陳文蔚','宋','宋诗','song-poetry','','[]','小齋雖不奉名譚，此理要須見倚參。',32,'全唐诗/poet.song.173000.json','["小齋雖不奉名譚，此理要須見倚參。", "料得歸懷明月滿，不應對影祗成三。"]'),
('e46afe44-731d-489b-b4b4-4cf57de69e5c','徐子融八月四夜見訪值予有出寄詩三絕和韵以謝  其三','陳文蔚','宋','宋诗','song-poetry','','[]','夜凉燈火掩柴扉，詩誦城南憶退之。',32,'全唐诗/poet.song.173000.json','["夜凉燈火掩柴扉，詩誦城南憶退之。", "更把新詩細紬繹，無言誰會點頭時。"]'),
('27149d07-cd18-4d3b-9d22-d5fc7e88ca41','予酷愛桂香置兩枝於蕭寺之寓室日出不得對花夜歸月影在窗撒燈清坐爲賦二十八字','陳文蔚','宋','宋诗','song-poetry','','[]','惜香故剪碧雲枝，却負花香花有辭。',32,'全唐诗/poet.song.173000.json','["惜香故剪碧雲枝，却負花香花有辭。", "爲輟清眠陪永夜，月窗相對恰相宜。"]'),
('6b9e0390-05a1-4088-82d1-4b3f35a82691','十月三夜省愆二絕  其一','陳文蔚','宋','宋诗','song-poetry','','[]','親爲父子須還愛，分屬君臣合用欽。',32,'全唐诗/poet.song.173000.json','["親爲父子須還愛，分屬君臣合用欽。", "細算天心無負我，我生猶有負天心。"]'),
('e05c10bd-e094-452f-b731-d7cc9fe7a212','十月三夜省愆二絕  其二','陳文蔚','宋','宋诗','song-poetry','','[]','孔子九思頻點檢，曾參三省重綢繆。',32,'全唐诗/poet.song.173000.json','["孔子九思頻點檢，曾參三省重綢繆。", "事來若也能思省，事過何因有悔尤。"]'),
('4b364155-4ed8-497d-91ed-16c27c4829a9','和徐子融見寄','陳文蔚','宋','宋诗','song-poetry','','[]','清時何故有遺材，酒膽如虹亦壯哉。',64,'全唐诗/poet.song.173000.json','["清時何故有遺材，酒膽如虹亦壯哉。", "多謝論交比金石，自慚進德未涓埃。", "政須尊酒風前共，莫作扁舟月下回。", "風雪當門須有夜，要觀四物一時來。"]'),
('fc005dab-f59a-43a7-ae07-f3ad55c05568','用趙國興梅韵自賦','陳文蔚','宋','宋诗','song-poetry','','[]','西郊有客枕溪居，特爲孤芳小結廬。',64,'全唐诗/poet.song.173000.json','["西郊有客枕溪居，特爲孤芳小結廬。", "窗外橫枝疏带竹，花邊流水暗通渠。", "伊方傲矣百花上，我亦翛然三徑餘。", "此外不關茅屋事，爲誰煙雨自妝梳。"]'),
('2c17edb9-3466-49a1-86f6-9c20990e7642','國興招飲後圃即席賦','陳文蔚','宋','宋诗','song-poetry','','[]','主人命酒嫌杯淺，狂客催詩恨句遲。',32,'全唐诗/poet.song.173000.json','["主人命酒嫌杯淺，狂客催詩恨句遲。", "此夜直須詩酒領，十分春色在花枝。"]'),
('eb04a2de-6ac2-46cd-9c64-97a63fa482ef','上巳遊惠泉和趙國興韵','陳文蔚','宋','宋诗','song-poetry','','[]','閒倚欄桿覓句時，此身如在浣花溪。',64,'全唐诗/poet.song.173000.json','["閒倚欄桿覓句時，此身如在浣花溪。", "草迷芳徑王孫醉，花滿春山杜宇啼。", "酒罷啜茶留石井，興餘隨月步江堤。", "清泉白石平生約，未有工夫爲品題。"]'),
('97ebafed-57d2-400c-bea6-0778af4f95a8','徐子融以詩送余方叔吳介甫二書見示和韵以謝  其一','陳文蔚','宋','宋诗','song-poetry','','[]','借得緘書卷又開，喜同千里故人來。',32,'全唐诗/poet.song.173000.json','["借得緘書卷又開，喜同千里故人來。", "切嗟正爲求真益，肯使鱗鴻泛往回。"]'),
('fc017e3b-0714-4d21-8425-86934d5dae6a','徐子融以詩送余方叔吳介甫二書見示和韵以謝  其二','陳文蔚','宋','宋诗','song-poetry','','[]','簪去良朋未有期，無邪端欲正吾思。',32,'全唐诗/poet.song.173000.json','["簪去良朋未有期，無邪端欲正吾思。", "近來自服無他藥，一卷中庸對證醫。"]'),
('5f6d70b3-7eb2-4db9-8f43-7a9bf577a520','送趙德勤將漕淮東  其一','陳文蔚','宋','宋诗','song-poetry','','[]','逼人富貴固駸駸，體國憂時一寸心。',64,'全唐诗/poet.song.173000.json','["逼人富貴固駸駸，體國憂時一寸心。", "符印遞遷無曠歲，廟堂誰謂少知音。", "民間利病搜求久，財計源流講究深。", "飛輓恢恢有餘地，要知罷困極于今。"]'),
('68e847fc-9537-4145-a36a-f2fda37b9b00','送趙德勤將漕淮東  其二','陳文蔚','宋','宋诗','song-poetry','','[]','才難嘆息古猶今，使節雙持委寄深。',64,'全唐诗/poet.song.173000.json','["才難嘆息古猶今，使節雙持委寄深。", "真主厲精思吏治，累朝忠孝結人心。", "激揚正頼扶風憲，欽恤惟存布德音。", "吏稱民安兩無事，不妨丹扆獻規箴。"]'),
('a0bddd6f-76e6-4c47-881e-58e9d5c5d627','送趙德勤將漕淮東  其三','陳文蔚','宋','宋诗','song-poetry','','[]','登亭每憶楚東時，把酒吟詩對落暉。',64,'全唐诗/poet.song.173000.json','["登亭每憶楚東時，把酒吟詩對落暉。", "拭目正看黄鵠舉，回頭不奈白雲飛。", "未應失計荒茅屋，正坐無錢買釣磯。", "𤱶畝有懷常抱膝，論思惟日望公歸。"]'),
('defab003-b160-462e-a71c-a0c7679745c4','送彭應期遊淮東  其一','陳文蔚','宋','宋诗','song-poetry','','[]','昔日淮西今又東，爲文怪似史遷公。',32,'全唐诗/poet.song.173000.json','["昔日淮西今又東，爲文怪似史遷公。", "遠遊要是丈夫志，自足一枝真計窮。"]'),
('25c8e31b-45ea-406f-99d7-31f830c20b92','送彭應期遊淮東  其二','陳文蔚','宋','宋诗','song-poetry','','[]','論心有約未能遂，兩載江頭再語離。',32,'全唐诗/poet.song.173000.json','["論心有約未能遂，兩載江頭再語離。", "縱乏青銅沽一醉，臨風分袂可無詩。"]'),
('5cfcb03b-2066-4acd-badc-93ff212762dd','六月十四夜獨坐無喧閣','陳文蔚','宋','宋诗','song-poetry','','[]','凭欄無事此時情，一闋欣聞欵乃聲。',32,'全唐诗/poet.song.173000.json','["凭欄無事此時情，一闋欣聞欵乃聲。", "歸去夜闌誰管領，付他風月自清明。"]'),
('0f7ee49b-8447-4c42-9f15-0d7a6dd7e7e5','七月四夜雨過差凉閒坐和徐子融晦日所寄四絕  其一','陳文蔚','宋','宋诗','song-poetry','','[]','昏花病眼已經年，世味甘酸總澹然。',32,'全唐诗/poet.song.173000.json','["昏花病眼已經年，世味甘酸總澹然。", "堆案文書渾不讀，一燈危坐晚凉天。"]'),
('58b4f919-a157-4ffc-b9c2-cfbab8d6d8ca','七月四夜雨過差凉閒坐和徐子融晦日所寄四絕  其二','陳文蔚','宋','宋诗','song-poetry','','[]','珍重羲黄書一編，昔經秦火不能然。',32,'全唐诗/poet.song.173000.json','["珍重羲黄書一編，昔經秦火不能然。", "君今於此得消息，豈外吾身更覓天。"]'),
('adfd7108-1dcf-467b-8cac-0b8dba12a159','七月四夜雨過差凉閒坐和徐子融晦日所寄四絕  其三','陳文蔚','宋','宋诗','song-poetry','','[]','每向清宵自省愆，滔滔無奈世皆然。',32,'全唐诗/poet.song.173000.json','["每向清宵自省愆，滔滔無奈世皆然。", "盈虧消息因而悟，萬事支頤一聽天。"]'),
('e3b81f7e-662d-4345-8a3f-6be3a358b964','七月四夜雨過差凉閒坐和徐子融晦日所寄四絕  其四','陳文蔚','宋','宋诗','song-poetry','','[]','此理分明見各偏，何時講習到同然。',32,'全唐诗/poet.song.173000.json','["此理分明見各偏，何時講習到同然。", "寄書好與隨菴道，千里元來共一天。"]'),
('f7a75fd1-f30a-4efa-9411-ee180c01cdb4','送趙國晉隨侍之江西','陳文蔚','宋','宋诗','song-poetry','','[]','如今無復酒腸寬，十五年同一夢間。',64,'全唐诗/poet.song.173000.json','["如今無復酒腸寬，十五年同一夢間。", "歲月易從愁裏換，鬢毛多向別時斑。", "諸公臺閣總皆著，獨我山林自愛閒。", "見說西風欲回首，樽前重得話間關。"]'),
('5c0b5814-b0b0-4258-a636-c854825443e0','七月廿六日趙國興招飲山堂有詩和韵','陳文蔚','宋','宋诗','song-poetry','','[]','滿地秋陰日欲殘，故人相約過松關。',64,'全唐诗/poet.song.173000.json','["滿地秋陰日欲殘，故人相約過松關。", "風煙雨後呈姿態，杖屨秋來起廢閒。", "喜有詩情濃似酒，從渠日歷積如山。", "清溪况解知人意，爲繞山堂綠一灣。"]'),
('c3955cf1-c3fa-452d-8908-8c86e5d1a58f','和韵呈徐子融聊寓規諫時子融同會','陳文蔚','宋','宋诗','song-poetry','','[]','儒黨凋零類月殘，興言及此最情關。',64,'全唐诗/poet.song.173000.json','["儒黨凋零類月殘，興言及此最情關。", "杯觴固可隨宜醉，主宰何嘗有暫閒。", "行健要將乾作馬，登高須識艮爲山。", "莫教盡日勞舟楫，只在當初相見灣。"]'),
('7c0836e3-2df5-4ca8-9d7b-b2c8d2789801','和趙連州雨中宿蒙軒韵','陳文蔚','宋','宋诗','song-poetry','','[]','千巖萬壑暮雲歸，不但晴宜雨亦宜。',64,'全唐诗/poet.song.173000.json','["千巖萬壑暮雲歸，不但晴宜雨亦宜。", "妙處已將詩句寫，吟餘惟有夢魂知。", "對床誰共三更聽，擊節難名一段奇。", "安得山間伴清宿，擁衾推枕和公詩。"]'),
('f103e24d-4a3a-4d5e-9cf3-66b1c8b9840b','和傅國開縣丞竹澗韵','陳文蔚','宋','宋诗','song-poetry','','[]','隨宜適意小軒亭，傍竹臨流取次成。',64,'全唐诗/poet.song.173000.json','["隨宜適意小軒亭，傍竹臨流取次成。", "地接園池山逕近，畦分花木四時平。", "秋風日有酒杯樂，徑石時敲拄杖聲。", "既有清灣堪釣月，可無一葉小舟橫。"]'),
('0cbf586c-2cd1-4ef4-b86d-7e10a0c4a88c','又和載酒過竹澗韵','陳文蔚','宋','宋诗','song-poetry','','[]','名園一水綠瀠洄，消得風流太守來。',32,'全唐诗/poet.song.173000.json','["名園一水綠瀠洄，消得風流太守來。", "把酒哦詩真不惡，此時懷抱十分開。"]'),
('a6421263-d75e-427f-a079-ec0e06d4be65','連州再招飲蒙軒次其韵','陳文蔚','宋','宋诗','song-poetry','','[]','把酒蒙軒喜屢同，笑談終日坐生風。',64,'全唐诗/poet.song.173000.json','["把酒蒙軒喜屢同，笑談終日坐生風。", "但知此意無欣厭，一任時人自介通。", "醉裏直愁逢李白，席間何幸有車公。", "南枝趁取梅花未，賢聖時時爲一中。"]'),
('b9c64acb-57cb-4a29-8c48-7d0581d5c2ed','十一月望後同徐子融黄子功送先生歸閩是夕宿分水嶺頭遇雪次早別先生二兄北歸約聯詩不成自賦一絕','陳文蔚','宋','宋诗','song-poetry','','[]','先生風節本高寒，千仞峰頭雪正漫。',32,'全唐诗/poet.song.173000.json','["先生風節本高寒，千仞峰頭雪正漫。", "一夕諸生聆妙論，時人莫作剡溪看。"]'),
('0fd086e0-e8c4-4dfd-86a7-026106eeb0e7','後一日和徐子融韵','陳文蔚','宋','宋诗','song-poetry','','[]','未省千林變作瑶，祇知尊酒侍清宵。',64,'全唐诗/poet.song.173000.json','["未省千林變作瑶，祇知尊酒侍清宵。", "大將臣子明忠孝，妙在陰陽驗息消。", "憶此老仙衝雪去，歸歟兩袂喜風飄。", "嶺頭故事詩能紀，今古相逢總不饒。"]'),
('931b1f6d-9788-4273-9cf0-5efaec5fa0c4','乙卯正月別子融','陳文蔚','宋','宋诗','song-poetry','','[]','相逢便欲作歸謀，爲子慇懃一日留。',64,'全唐诗/poet.song.173000.json','["相逢便欲作歸謀，爲子慇懃一日留。", "山好不妨和雨看，水平重得繞湖遊。", "酒須更放微醺飲，詩亦無勞著意求。", "別去不愁山水隔，興來徑理雪中舟。"]'),
('5ed7a2a0-4619-4ae7-8b8a-8358f9865a16','三月望訪徐子顔','陳文蔚','宋','宋诗','song-poetry','','[]','近有平林遠有山，先生無日不開顔。',32,'全唐诗/poet.song.173000.json','["近有平林遠有山，先生無日不開顔。", "杜門有味心千古，何用浮名落世間。"]'),
('baaa1ea5-aedb-4af6-b95d-773fdf95b3d0','九月十一日挈浩同省先隴早起四山昏翳衝霧露涉水登山至山顛則日已東上澄空朗然下視村中霧猶蒙罩人烟桑柘皆不可辨戲成一絕','陳文蔚','宋','宋诗','song-poetry','','[]','拄上高峰近日輪，四山端的見來親。',32,'全唐诗/poet.song.173000.json','["拄上高峰近日輪，四山端的見來親。", "此身已在煙霾上，可惜煙霾底下人。"]'),
('93f20dd0-ca6a-4336-a607-80fe50002838','子融觀木犀懷趙連州有別後吟情渾冷落不知花卉若爲開之句錄以見寄予報云近讀書之暇多哦康節詩時有自適處忽奉佳章輒用此意繼韵後錄呈先生有報書','陳文蔚','宋','宋诗','song-poetry','','[]','詩哦擊壤興悠哉，一任光陰頭上催。',64,'全唐诗/poet.song.173000.json','["詩哦擊壤興悠哉，一任光陰頭上催。", "味好花間飲醇酎，風清竹外見疏梅。", "孤鴻忽自雲間至，好意驚從天外來。", "人有合離花一也，不應人去不花開。"]'),
('0b94a0cb-891b-43d5-883a-eac24092dfe3','晚步傅氏小園','陳文蔚','宋','宋诗','song-poetry','','[]','溪園信步晚徘徊，白白紅紅夾徑開。',32,'全唐诗/poet.song.173000.json','["溪園信步晚徘徊，白白紅紅夾徑開。", "漫折一枝携在手，也教人道看花來。"]'),
('e02c21d9-491c-487f-aa4b-775fcc57309e','趙湖州東園雜詠和人韵 先春堂','陳文蔚','宋','宋诗','song-poetry','','[]','芳園十畝面東開，春色知從此地來。',32,'全唐诗/poet.song.173000.json','["芳園十畝面東開，春色知從此地來。", "門外風光渾未覺，堂前早已發桃梅。"]'),
('5656ddaa-d8cf-40e0-a50d-3f61cee2ba6e','趙湖州東園雜詠和人韵 邀月','陳文蔚','宋','宋诗','song-poetry','','[]','遠樂數聲聞玉簫，酒酣起舞月中宵。',32,'全唐诗/poet.song.173000.json','["遠樂數聲聞玉簫，酒酣起舞月中宵。", "謫仙當日真豪放，明鏡飛空許見邀。"]'),
('a03f8683-cabf-4d8a-960c-13e11572b047','趙湖州東園雜詠和人韵 賓日','陳文蔚','宋','宋诗','song-poetry','','[]','著眼高時四海空，何須服日臉霞紅。',32,'全唐诗/poet.song.173000.json','["著眼高時四海空，何須服日臉霞紅。", "清朝坐對升暘谷，萬里雲煙在古風。"]'),
('d595b142-9f23-4a5b-b4da-08a3e1c0d55d','趙湖州東園雜詠和人韵 一勺','陳文蔚','宋','宋诗','song-poetry','','[]','吞夢胸襟納九江，等閒領客醉壺觴。',32,'全唐诗/poet.song.173000.json','["吞夢胸襟納九江，等閒領客醉壺觴。", "愛將萬事尋源委，鋤到雲間得祕藏。"]'),
('d4aa254d-e13c-4452-9f90-dc19369e8cdd','趙湖州東園雜詠和人韵 雋遊','陳文蔚','宋','宋诗','song-poetry','','[]','亭據高峰上上頭，登臨人世一漚浮。',32,'全唐诗/poet.song.173000.json','["亭據高峰上上頭，登臨人世一漚浮。", "囂塵到此都遺盡，直欲乘風跨鶴遊。"]'),
('eacb1566-08c1-4720-b567-7b0db0024c17','趙湖州東園雜詠和人韵 矍圃','陳文蔚','宋','宋诗','song-poetry','','[]','剔攘取予見經綸，中的工人又日新。',32,'全唐诗/poet.song.173000.json','["剔攘取予見經綸，中的工人又日新。", "一醉使君豪氣發，頗思三箭定胡人。"]'),
('08bb1a9e-9035-400a-a829-32e4e3425ee6','和傅巖叟病中見寄','陳文蔚','宋','宋诗','song-poetry','','[]','平時安樂病中知，多少人間未發機。',32,'全唐诗/poet.song.173000.json','["平時安樂病中知，多少人間未發機。", "若把此身常似病，分明四十九年非。"]'),
('64cffcdb-f4b3-48f7-98aa-b07e146b20e1','雨不止和族叔韵','陳文蔚','宋','宋诗','song-poetry','','[]','小齋容膝足遲回，世路羊腸不用猜。',64,'全唐诗/poet.song.173000.json','["小齋容膝足遲回，世路羊腸不用猜。", "久矣此心冥進取，翩然何日賦歸來。", "新篘半熟甕頭酒，小摘微黄葉底梅。", "盡日北窗聽雨卧，任他門巷長蒿萊。"]'),
('c37f5316-c2be-457a-a0cb-4f4a9792a7c1','戊午正月送趙工部赴江東參謀','陳文蔚','宋','宋诗','song-poetry','','[]','設門大字題嘉遁，買宅浩然歸去來。',64,'全唐诗/poet.song.173000.json','["設門大字題嘉遁，買宅浩然歸去來。", "十畝清溪千箇竹，一庭春意半窗梅。", "漁樵正伴詩翁樂，鷗鷺俄驚詔墨催。", "底事此中留不住，釣磻知有濟時才。"]'),
('1841d399-6433-44b9-a32e-0dfa4426a246','許世卿孝亭邂逅爲予修琴臨別求詩爲賦長句','陳文蔚','宋','宋诗','song-poetry','','[]','邂逅相逢不記春，未知此際得情親。',64,'全唐诗/poet.song.173000.json','["邂逅相逢不記春，未知此際得情親。", "一溪雲月閒中計，三尺絲桐物外身。", "未有清尊酬痛飲，已驚明日是行人。", "抱琴歸去無餘恨，大呂黄鍾一味醇。"]'),
('0bdebd55-0847-4154-b7f5-0b7a8311209d','雪中約嘉言叔','陳文蔚','宋','宋诗','song-poetry','','[]','沒曉園林玉萬株，最宜梅竹與茅廬。',32,'全唐诗/poet.song.173000.json','["沒曉園林玉萬株，最宜梅竹與茅廬。", "高人想見詩肩聳，乘興還能訪戴無。"]'),
('f2b5989c-5578-4143-8114-16ba9f17a46c','送傅君玉赴廷對','陳文蔚','宋','宋诗','song-poetry','','[]','自嘆忠腸皎日星，致身無地老巖坰。',32,'全唐诗/poet.song.173000.json','["自嘆忠腸皎日星，致身無地老巖坰。", "君今有策奏天子，要使讒邪縮項聽。"]'),
('4fb41955-e52a-4351-85db-b5858c5a98dd','讀書傅氏揖桂林外一山恍如徐子融書閣所見書閣見山之陰揖桂見山之陽戲成一絕呈子融','陳文蔚','宋','宋诗','song-poetry','','[]','自昔桂陽名此山，登樓恍若見林端。',32,'全唐诗/poet.song.173000.json','["自昔桂陽名此山，登樓恍若見林端。", "山中固有誅茅地，却許吾人背面看。"]'),
('d05d7e77-af39-4cd5-9a4a-e7c7b05e5034','子融和答三首再用韵賦一絕以謝','陳文蔚','宋','宋诗','song-poetry','','[]','登樓觸目皆詩料，難寫風煙盡筆端。',32,'全唐诗/poet.song.173000.json','["登樓觸目皆詩料，難寫風煙盡筆端。", "不但綠陰晴後好，亦便山色雨中看。"]'),
('de29f906-9d01-4775-96ec-e9c59ec6653a','傅材甫窗前白月桂開材甫索詩戲作  其一','陳文蔚','宋','宋诗','song-poetry','','[]','天然容貌本施朱，喜異羞同世不趨。',32,'全唐诗/poet.song.173000.json','["天然容貌本施朱，喜異羞同世不趨。", "化得丹砂成玉雪，也知人著半工夫。"]'),
('02a17705-c7da-4ee6-93c8-71534069b7e3','傅材甫窗前白月桂開材甫索詩戲作  其二','陳文蔚','宋','宋诗','song-poetry','','[]','冰姿冷淡不求知，却有同心爲賦詩。',32,'全唐诗/poet.song.173000.json','["冰姿冷淡不求知，却有同心爲賦詩。", "更約東君同管領，一尊相對晚凉時。"]'),
('2c8b816c-a3d1-406e-bf27-0f158a74ba0b','中秋雨作中夜月明余方叔留寓齋宿酒闌隨水縱步方叔有詩用韵同賦','陳文蔚','宋','宋诗','song-poetry','','[]','瓊樓玉宇不勝秋，把酒臨風味轉優。',64,'全唐诗/poet.song.173000.json','["瓊樓玉宇不勝秋，把酒臨風味轉優。", "雲雨自爲朝暮變，歌詩不盡古今愁。", "誰知明月天心到，却有佳賓水際留。", "無限醉眠呼不醒，步隨清影只搔頭。"]'),
('f98e09df-650e-4467-847d-b997f292d13f','方叔再用前韵約同賦','陳文蔚','宋','宋诗','song-poetry','','[]','坐談冰雪滿懷秋，珍重余君學素優。',64,'全唐诗/poet.song.173000.json','["坐談冰雪滿懷秋，珍重余君學素優。", "每有詩情并酒興，爲平月恨與花愁。", "支頤萬事從渠變，拂榻今宵爲我留。", "何處青山堪卜築，約君歸種菊千頭。"]'),
('cad34f7b-caa3-448b-8155-7b90a0da67fd','同余方叔龔南才納凉於筠谷竹間題五十六字','陳文蔚','宋','宋诗','song-poetry','','[]','躡險捫蘿策短藜，翠微深處有幽棲。',64,'全唐诗/poet.song.173000.json','["躡險捫蘿策短藜，翠微深處有幽棲。", "風常拂面炎凉變，事不關心得喪齊。", "白酒携來雲外飲，新詩留向竹間題。", "相陪盡日餘清興，猶自徜徉玩碧溪。"]'),
('a2c2a398-cbed-448e-8368-10e0af06c167','侍嘉言叔溪行和其韵','陳文蔚','宋','宋诗','song-poetry','','[]','山下江清水見沙，杖頭沽醉酒旗家。',32,'全唐诗/poet.song.173000.json','["山下江清水見沙，杖頭沽醉酒旗家。", "多情黄菊知人意，故放籬邊三四花。"]'),
('76141593-5250-4e3d-aaaf-1a709d9be792','和趙國興訪蕭氏草堂','陳文蔚','宋','宋诗','song-poetry','','[]','四野山圍面面屏，何人結屋趣方成。',64,'全唐诗/poet.song.173000.json','["四野山圍面面屏，何人結屋趣方成。", "好風吹過半湖碧，白鳥飛邊一點明。", "乘興半春携酒約，隔山遥夜讀書聲。", "買鄰爲愛茅齋近，試倩詩人狀此情。"]'),
('5190a2c3-41e7-4213-b862-9e9f0c2e4018','庚申清明日子融出遊寄示紀遊十絕以長句謝之','陳文蔚','宋','宋诗','song-poetry','','[]','浴沂天氣出郊坰，所至題詩取次成。',64,'全唐诗/poet.song.173000.json','["浴沂天氣出郊坰，所至題詩取次成。", "花塢風煙俱入詠，雲巖泉石屢增名。", "摩挲硤石舊題字，展轉東山未盡情。", "不出祗尋窗下計，春光隨處亦清明。"]'),
('9cc9b233-7f74-4e4c-ab14-fa691d978630','晚步清暉不見主人題竹間','陳文蔚','宋','宋诗','song-poetry','','[]','飽食無餘事，逍遥散步行。',24,'全唐诗/poet.song.173000.json','["飽食無餘事，逍遥散步行。", "清暉人不見，鷗鷺自相迎。"]'),
('5491d210-4388-4519-b424-07455dc4131f','送趙國宜赴筠州戶掾','陳文蔚','宋','宋诗','song-poetry','','[]','苦無多路旅程寬，正是江南綠打團。',64,'全唐诗/poet.song.173000.json','["苦無多路旅程寬，正是江南綠打團。", "欲濕征衫梅雨細，不成客夢麥秋寒。", "官閒詩可頻搜句，親近書宜月問安。", "自笑無才愧之子，明時君祿詎能干。"]'),
('89466964-20bd-47d2-86ca-339f96a51a8d','送趙國開赴湘陰','陳文蔚','宋','宋诗','song-poetry','','[]','聽取閩山父老謠，屢曾游戲試牛刀。',64,'全唐诗/poet.song.173000.json','["聽取閩山父老謠，屢曾游戲試牛刀。", "雙鳬澤國翩翩去，一鶚秋風漸漸高。", "書至未忘千樹橘，政成須種滿城桃。", "早歸宣室膺前席，莫漫江頭賦廣騷。"]'),
('5e27e227-0862-4651-b031-e7084e52425a','和茂嘉郎中催梅韵','陳文蔚','宋','宋诗','song-poetry','','[]','快讀新詩似見梅，昏昏醉眼爲君開。',64,'全唐诗/poet.song.173000.json','["快讀新詩似見梅，昏昏醉眼爲君開。", "枝頭未見粉苞露，句裏先傳春信來。", "試問花神緣底晚，政須羯鼓爲渠催。", "前枝見說南枝早，合取彭溪溪上栽。"]'),
('5c747b9e-608b-460b-bc01-f69b7aee0bfa','二月廿一日遊藏勝有感','陳文蔚','宋','宋诗','song-poetry','','[]','柴門終日掩荒苔，記得年時把酒杯。',32,'全唐诗/poet.song.173000.json','["柴門終日掩荒苔，記得年時把酒杯。", "幸有春風到桃李，一年一度看花來。"]'),
('b1f23ec1-74be-4074-9602-2e60be321f7f','和趙國宜轉寄傅巖叟詩韵時歲歉人艱食聞國宜有發粟意因有以勸相之','陳文蔚','宋','宋诗','song-poetry','','[]','雲章華閣照明時，朝野如今尚採詩。',64,'全唐诗/poet.song.173000.json','["雲章華閣照明時，朝野如今尚採詩。", "紫府祗因通夕夢，永平從此失朝饑。", "似聞令子心傳印，便有行人口似碑。", "還許秫田分靖節，黄花重九醉東籬。"]'),
('3997074d-6bda-41d9-a106-caab946c85a0','和趙忠州見寄','陳文蔚','宋','宋诗','song-poetry','','[]','道義雖同趣，窮通奈兩途。',48,'全唐诗/poet.song.173000.json','["道義雖同趣，窮通奈兩途。", "蜀閩歌召杜，莘野樂唐虞。", "世上風波惡，胸中矛盾無。", "交情歲寒見，故我即今吾。"]'),
('106b2841-1de6-4de5-a22c-da1975e1dc7f','趙河源幼子種蓮於盆池一幹開雙葉戲作小詩時河源二幼子一受命矣','陳文蔚','宋','宋诗','song-poetry','','[]','穉子堂前戲綵時，種蓮積水作盆池。',64,'全唐诗/poet.song.173000.json','["穉子堂前戲綵時，種蓮積水作盆池。", "間聞並萼窺紅影，誰識雙柯媚綠漪。", "莫謂微荄無妙意，也知造物等兒嬉。", "看看膝下成雙綠，爲應君家此段奇。"]'),
('aaaebb2c-a6c0-4465-b5cf-e2f5ebac9020','賀趙及卿黄定甫主賓聯名登第','陳文蔚','宋','宋诗','song-poetry','','[]','人傑須知本地靈，鵝峰挺拔湛溪清。',64,'全唐诗/poet.song.173000.json','["人傑須知本地靈，鵝峰挺拔湛溪清。", "新添九桂叢芳茂，旁發一枝花更榮。", "文社只今傳盛事，宦途從此展修程。", "歸耕媿我猶無地，僅有青山一笑迎。"]'),
('4dce022d-3def-4b08-b2f3-2175f77c5fc2','送趙局之官','陳文蔚','宋','宋诗','song-poetry','','[]','琴書結束定何時，折贈新年梅一枝。',64,'全唐诗/poet.song.173000.json','["琴書結束定何時，折贈新年梅一枝。", "詩過釣臺天欲雪，春歸湖岸柳成絲。", "交遊文社頓成闊，富貴帝鄉今可期。", "小試活民醫國手，眼明諸老會相知。"]'),
('b7a45306-d639-4730-81ee-a7b1ef509831','十二月十二日踏雪度崧嶺  其一','陳文蔚','宋','宋诗','song-poetry','','[]','何事隆冬震地雷，天公補過令方回。',64,'全唐诗/poet.song.173000.json','["何事隆冬震地雷，天公補過令方回。", "玉裝庭樹三番白，花間江梅六出開。", "豈止爲民除瘴癘，且欣無地不瓊瑰。", "到家未說豐年事，喜奉慈親酒一杯。"]'),
('403e0e63-eef6-4380-b2e4-23fa0072cc53','十二月十二日踏雪度崧嶺  其二','陳文蔚','宋','宋诗','song-poetry','','[]','雪行崧嶺歲華新，又作殘年踏雪人。',64,'全唐诗/poet.song.173000.json','["雪行崧嶺歲華新，又作殘年踏雪人。", "茅屋畫簷俱富貴，穉松枯木總精神。", "哦詩未怕寒生粟，舉酒惟知暖欲春。", "自說到家貧亦好，兩峰門外玉璘珣。"]'),
('b965a12c-97c7-4503-85ef-f3a0027d6323','十二月廿三日舉故事訪黄岡梅','陳文蔚','宋','宋诗','song-poetry','','[]','歲披草棘訪槎牙，爲愛凌霜傲雪花。',32,'全唐诗/poet.song.173000.json','["歲披草棘訪槎牙，爲愛凌霜傲雪花。", "不學春花嬌女面，朱簾翠幕幾重遮。"]'),
('331031fa-7dc0-4928-8bcd-4b6b05a61449','壬申春社前一日晚步欣欣園','陳文蔚','宋','宋诗','song-poetry','','[]','何必遊園問主人，只尋花柳閙中春。',64,'全唐诗/poet.song.173000.json','["何必遊園問主人，只尋花柳閙中春。", "都無揀擇行隨意，不費思量句有神。", "是處林園明紫翠，晚晴樓閣倚嶙峋。", "村村鷄酒相招喚，安得便爲同社鄰。"]'),
('c5207a49-1f1d-4b02-ab76-0d48cbe12a0f','和趙忠州歸耕之賦','陳文蔚','宋','宋诗','song-poetry','','[]','壯年學易計非疏，晚讀人間種樹書。',64,'全唐诗/poet.song.173000.json','["壯年學易計非疏，晚讀人間種樹書。", "不向雲霄羨鴻鵠，却來江海伴舂鋤。", "感君綠野成歸計，令我青山思故居。", "只恐奇謀未施設，折秦强趙要相如。"]'),
('7c59c100-c05f-4e7a-a28d-f2f2f160a01b','三月八日晚步溪上二絕  其一','陳文蔚','宋','宋诗','song-poetry','','[]','綠楊芳草兩邊洲，不礙晴川日夜流。',32,'全唐诗/poet.song.173000.json','["綠楊芳草兩邊洲，不礙晴川日夜流。", "我到忘機每終日，爲誰飛去怪沙鷗。"]'),
('3cadac78-42bd-426a-8dea-ede272dc5c25','三月八日晚步溪上二絕  其二','陳文蔚','宋','宋诗','song-poetry','','[]','畫筆難描蘋渚意，詩情難狀柳堤風。',32,'全唐诗/poet.song.173000.json','["畫筆難描蘋渚意，詩情難狀柳堤風。", "若令妙處人皆會，甘把漁竿伴釣翁。"]'),
('fc9ce070-422b-41db-bafb-60217fd5f396','天王寺佛塔燈隔林見之奇絕因成口占','陳文蔚','宋','宋诗','song-poetry','','[]','上元燈火九衢中，何似金蓮下半空。',32,'全唐诗/poet.song.173000.json','["上元燈火九衢中，何似金蓮下半空。", "要識隔林奇絕處，星毬带葉荔枝紅。"]'),
('0bbecb99-69e9-4fc0-a88b-dce0de439b77','賦葉茂卿泉石軒','陳文蔚','宋','宋诗','song-poetry','','[]','郭外多佳士，溪南好結廬。',48,'全唐诗/poet.song.173000.json','["郭外多佳士，溪南好結廬。", "因君愛泉石，令我想風雩。", "既有琴書樂，應無世俗拘。", "誰能厭朝市，來此共須臾。"]'),
('db0c0734-a77f-4cb9-824e-515658658c7e','行崧嶺將半下瞰山中一人家似不與世接者凝佇久之因成一絕','陳文蔚','宋','宋诗','song-poetry','','[]','幾曲青山一畝宮，前村惟有小溪通。',32,'全唐诗/poet.song.173000.json','["幾曲青山一畝宮，前村惟有小溪通。", "鷄鳴鳥宿知昏旦，水碓無人自在舂。"]'),
('8fa93b2d-3358-46b7-9fdb-71a0939dfed3','寄題張正國斗齋  其一','陳文蔚','宋','宋诗','song-poetry','','[]','幾人大厦室廬窘，之子數椽天地寬。',32,'全唐诗/poet.song.173000.json','["幾人大厦室廬窘，之子數椽天地寬。", "醉裏揮毫詩膽大，不懸金印老江干。"]'),
('4cf67c1b-2919-4e34-ae1f-b769e8628f77','寄題張正國斗齋  其二','陳文蔚','宋','宋诗','song-poetry','','[]','蒲團竹几炷熏爐，賸讀平生未見書。',32,'全唐诗/poet.song.173000.json','["蒲團竹几炷熏爐，賸讀平生未見書。", "酌古量今會文夜，清風明月四窗虛。"]'),
('853e9f2e-b400-4f32-a450-e8452a3e0d4c','寄題張正國斗齋  其三','陳文蔚','宋','宋诗','song-poetry','','[]','數年約我過溫溪，好趁雞黄秋黍炊。',32,'全唐诗/poet.song.173000.json','["數年約我過溫溪，好趁雞黄秋黍炊。", "添子江湖千頃意，勸於窗外作盆池。"]'),
('09ef17dc-759d-48fb-9239-5ac2ca820173','送會稽王君東歸','陳文蔚','宋','宋诗','song-poetry','','[]','人生相遇若雲萍，聽唱陽關酒暫停。',64,'全唐诗/poet.song.173000.json','["人生相遇若雲萍，聽唱陽關酒暫停。", "夜雨挑燈今昨恨，秋風吹夢短長亭。", "笑予衰鬢霜侵綠，喜子新功刃發硎。", "欲當馬檛何以贈，江邊猶有柳條青。"]'),
('72fe1312-9af2-4645-95df-ccfb6c10fa8a','視新買徐七塢田','陳文蔚','宋','宋诗','song-poetry','','[]','人說山田薄有收，不如平壤水交流。',32,'全唐诗/poet.song.173000.json','["人說山田薄有收，不如平壤水交流。", "深耕早種將勤補，亦勝當初無寸疇。"]'),
('15cc8034-4e32-4294-b0f9-3c0b1a90351b','和周次公韵送鄭恭叔歸城南并簡次公  其一','陳文蔚','宋','宋诗','song-poetry','','[]','三十年前識雅容，蹉跎人事各成翁。',32,'全唐诗/poet.song.173000.json','["三十年前識雅容，蹉跎人事各成翁。", "而今頭白燈明裏，有酒何妨一醉紅。"]'),
('c9d61a5f-1638-409f-be95-790f7f9a29bb','和周次公韵送鄭恭叔歸城南并簡次公  其二','陳文蔚','宋','宋诗','song-poetry','','[]','春山曾記別匆匆，多少傳言詩句中。',32,'全唐诗/poet.song.173000.json','["春山曾記別匆匆，多少傳言詩句中。", "遠目不窮天萬里，幾隨西日送征鴻。"]'),
('46e24297-fb9c-4000-b37e-7d310d079183','癸酉立春衝雪觀梅','陳文蔚','宋','宋诗','song-poetry','','[]','吾翁當日手親栽，今見芳英幾度開。',32,'全唐诗/poet.song.173000.json','["吾翁當日手親栽，今見芳英幾度開。", "把酒未能娛一醉，衝寒犯雪日須來。"]'),
('e349e27d-7a86-48aa-b1cb-f8d7e0ff463d','老人及兒輩皆和再用前韵','陳文蔚','宋','宋诗','song-poetry','','[]','不厠繁桃俗杏栽，詩懷端爲此花開。',32,'全唐诗/poet.song.173000.json','["不厠繁桃俗杏栽，詩懷端爲此花開。", "自緣祗結冰霜侶，花底渾無俗駕來。"]'),
('22d314c8-4cf6-4e67-8439-10afeb33857e','題趙守飛霞亭','陳文蔚','宋','宋诗','song-poetry','','[]','問津早似武陵溪，屋上鵝峰有遁肥。',64,'全唐诗/poet.song.173000.json','["問津早似武陵溪，屋上鵝峰有遁肥。", "醉臉丹時歌雪白，碧山深處染桃緋。", "林亭縹緲仙翁樂，酒盞交酬花片飛。", "逍遣箇中閒日月，賦詩應不送春歸。"]'),
('2862bdbc-a205-4a41-ae30-ad85f6ad3374','再用韵呈趙守','陳文蔚','宋','宋诗','song-poetry','','[]','不待漁舠喚隔溪，種桃千樹正紅肥。',64,'全唐诗/poet.song.173000.json','["不待漁舠喚隔溪，種桃千樹正紅肥。", "山圍曉障新圖畫，花押春班簇紫緋。", "池凈白鷗相對浴，客來青鳥故雙飛。", "寄詩爲問花前醉，何似天香滿袖歸。"]'),
('31c7ce7f-ddd6-4806-acac-d4997a131247','和趙忠州園亭落成宴客三首 自爲堂','陳文蔚','宋','宋诗','song-poetry','','[]','雙旌未逐詔書還，放適何妨且謝安。',64,'全唐诗/poet.song.173000.json','["雙旌未逐詔書還，放適何妨且謝安。", "地拔鵝峰長突兀，天教老子得蹣跚。", "病瘳不必維摩問，客醉誰知太守歡。", "更乞爲時推此意，要令宵旰九重寬。"]'),
('4c0d1750-4d5c-4f52-9c2e-770cf5d31488','和趙忠州園亭落成宴客三首 飛霞亭','陳文蔚','宋','宋诗','song-poetry','','[]','水香流出洞中花，曾閲秦朝與漢家。',32,'全唐诗/poet.song.173000.json','["水香流出洞中花，曾閲秦朝與漢家。", "咫尺不知塵世隔，漁郎回首鎖烟霞。"]'),
('8fed24fc-6ae3-4832-b253-8c15618e6054','和趙忠州園亭落成宴客三首 釣鼇','陳文蔚','宋','宋诗','song-poetry','','[]','自來名教屬吾曹，立極何須說斷鼇。',32,'全唐诗/poet.song.173000.json','["自來名教屬吾曹，立極何須說斷鼇。", "聊把經綸寄魚釣，豈無裴楷試仙濤。"]'),
('cb5c454e-db7a-412e-846d-8f70a73aee38','廬陵趙令君宅後有蓮濠月夕相拉觀蓮戲廬陵','陳文蔚','宋','宋诗','song-poetry','','[]','朱橋綠水夜深遊，滿載荷花萬斛舟。',32,'全唐诗/poet.song.173000.json','["朱橋綠水夜深遊，滿載荷花萬斛舟。", "多病近來常止酒，及無尊俎欠風流。"]'),
('4ad8aa4c-8410-49e1-b3ed-41832202d04d','廬陵呼酒再用韵','陳文蔚','宋','宋诗','song-poetry','','[]','令君領客作清遊，蕭散仙人蓮葉舟。',32,'全唐诗/poet.song.173000.json','["令君領客作清遊，蕭散仙人蓮葉舟。", "喚得酒來詩興發，浩歌和月吸黄流。"]'),
('7733d93e-d94e-40cb-9d7c-c62a55d19d8b','廬陵於兩池中作船亭名卧蘆取山谷滿船明月卧蘆花之句落成爲賦小詩','陳文蔚','宋','宋诗','song-poetry','','[]','路入芳池柳岸行，宛然野渡一舟橫。',64,'全唐诗/poet.song.173000.json','["路入芳池柳岸行，宛然野渡一舟橫。", "祗緣胸次規模別，便有江湖氣象生。", "雲影恍疑帆影度，嘯歌中有棹歌聲。", "天書恐逐銜蘆雁，未許花邊卧月明。"]'),
('de5e2843-c051-40b0-9312-08bb9bc5a18e','晚坐卧廬復與廬陵同用前韵','陳文蔚','宋','宋诗','song-poetry','','[]','待得巡簷有月行，梅仙無惜爲琴橫。',64,'全唐诗/poet.song.173000.json','["待得巡簷有月行，梅仙無惜爲琴橫。", "頻招野客耽詩興，祇恐東君費麯生。", "拄笏靜看山擁翠，凭欄閒聽水流聲。", "人生聚散無勞較，萬里青天白鳥鳴。"]'),
('a740e4e1-3532-4f65-b610-aa75dc16ccae','八月十日過松水','陳文蔚','宋','宋诗','song-poetry','','[]','拂石臨流幾歲秋，未嘗歷險究源頭。',32,'全唐诗/poet.song.173000.json','["拂石臨流幾歲秋，未嘗歷險究源頭。", "今朝拄上雲烟去，爲吸清泠最上流。"]'),
('8b9d5a84-d0a7-408f-b6fc-48a6b5eac1e2','以壽山石絛環寄趙昌甫將以廿八字','陳文蔚','宋','宋诗','song-poetry','','[]','連城價重雖非玉，千古名存壽此山。',32,'全唐诗/poet.song.173000.json','["連城價重雖非玉，千古名存壽此山。", "野服閒居頗相稱，無端因得玩如環。"]'),
('12d48213-dca2-4430-abfc-adf9c9dd2278','甲戌正月從君用弟覓月桂栽','陳文蔚','宋','宋诗','song-poetry','','[]','花發枝頭月月新，不妨分種過西鄰。',32,'全唐诗/poet.song.173000.json','["花發枝頭月月新，不妨分種過西鄰。", "琴書結束歸來日，要使門庭長有春。"]'),
('c47405f7-c618-438a-86e4-bbb4c7c5cd64','送葉味道赴南宮','陳文蔚','宋','宋诗','song-poetry','','[]','聖世宗儒重設科，名公碩德總搜羅。',64,'全唐诗/poet.song.173000.json','["聖世宗儒重設科，名公碩德總搜羅。", "近年底事摧頹甚，士氣都緣斲喪多。", "憂世情詞常懇惻，喜君事業久研磨。", "不才但有山林興，洗耳專聽奏凱歌。"]'),
('ac5e89dc-3d2f-4f62-909c-de1bffe17675','呈倉使覓官書','陳文蔚','宋','宋诗','song-poetry','','[]','歲月蹉跎髮已絲，埋頭自笑有書癡。',32,'全唐诗/poet.song.173000.json','["歲月蹉跎髮已絲，埋頭自笑有書癡。", "故人倘解憐清好，歸去山房補缺遺。"]'),
('ff8d08f4-718e-4ee6-9002-242cf69ce6a0','池陽地寒梅開甚晚上元後始見疏花一夕春雪曉起觀梅爲梅解嘲','陳文蔚','宋','宋诗','song-poetry','','[]','千林一夜散瓊瑰，莫誚亭前春後梅。',32,'全唐诗/poet.song.173000.json','["千林一夜散瓊瑰，莫誚亭前春後梅。", "未入紛紛紅紫隊，不妨曾是雪中開。"]'),
('f58b660f-18ab-4dac-9c26-b29823ba5be2','倉使亦爲梅著句適與予意相合和其韵','陳文蔚','宋','宋诗','song-poetry','','[]','六花如覺厭春遲，桃未敷紅柳未垂。',32,'全唐诗/poet.song.173000.json','["六花如覺厭春遲，桃未敷紅柳未垂。", "只有紅梅太孤寂，裁冰綴玉助清奇。"]'),
('856c9696-f3a5-4edd-ace6-fd1e08d67824','別倉使二首  其一','陳文蔚','宋','宋诗','song-poetry','','[]','千里江頭訪故人，事雖論舊道彌新。',64,'全唐诗/poet.song.173000.json','["千里江頭訪故人，事雖論舊道彌新。", "懸知一味憂勤意，要活九州窮困民。", "秋月洞明波底影，祥風潜有雪中春。", "荒山僻嶠雪深處，無惜遄驅六轡均。"]'),
('988c8d55-57ba-4512-8101-be0f8325ab88','別倉使二首  其二','陳文蔚','宋','宋诗','song-poetry','','[]','服膺師訓毅名齋，觀省無妨動與偕。',64,'全唐诗/poet.song.173000.json','["服膺師訓毅名齋，觀省無妨動與偕。", "只向此中窺所守，已知平日謹諸懷。", "器充宏博乾坤大，理析精微律呂諧。", "吾道古今窮不盡，一尊深夜講朋儕。"]'),
('d1961efd-2370-4890-8dec-fb0626a2ee84','歸途喜晴','陳文蔚','宋','宋诗','song-poetry','','[]','來時風雪亂紛紛，歸日川原處處春。',32,'全唐诗/poet.song.173000.json','["來時風雪亂紛紛，歸日川原處處春。", "因識發生真意思，雨餘花柳更精神。"]'),
('98781a4c-5d09-4308-81aa-9025c6dddf7e','追賦齊山','陳文蔚','宋','宋诗','song-poetry','','[]','興動齊山杖屨飛，可人遲日嫩晴暉。',64,'全唐诗/poet.song.173000.json','["興動齊山杖屨飛，可人遲日嫩晴暉。", "一堤烟柳連秋浦，萬里江山入翠微。", "泉石怪奇難盡究，古今題品待携歸。", "春來歌酒雖無禁，不與紅塵染是非。"]'),
('3b6643d9-0c6c-4228-9565-be08ebe751af','追賦臺治諸景有懷倉使','陳文蔚','宋','宋诗','song-poetry','','[]','日日花光展翠遊，芙蓉高樹壓城頭。',64,'全唐诗/poet.song.173000.json','["日日花光展翠遊，芙蓉高樹壓城頭。", "招邀風月新添竹，管領湖山數上樓。", "欲伴清琴庭舞鶴，不驚使節浦眠鷗。", "花開紅藕薰風細，恨不同撐柳外舟。"]'),
('0453e393-d5e2-44be-9f20-8d56bffab0ac','追賦西廟廣覺寺','陳文蔚','宋','宋诗','song-poetry','','[]','精藍同占一青山，遊子紛紛春自閒。',32,'全唐诗/poet.song.173000.json','["精藍同占一青山，遊子紛紛春自閒。", "要福乞靈從爾輩，獨携筇杖款松間。"]'),
('314d18fa-8518-4f10-9ad2-def012ca2718','晨興','陳文蔚','宋','宋诗','song-poetry','','[]','書窗欲曙夢初還，起坐披衣百慮間。',32,'全唐诗/poet.song.173000.json','["書窗欲曙夢初還，起坐披衣百慮間。", "誰識斯時會心處，靜聽鳥語樂相關。"]'),
('d2f270b4-7961-4c9a-8d7a-6562208b3652','送趙國呈赴金壇','陳文蔚','宋','宋诗','song-poetry','','[]','未成花柳種成堤，早有先聲到浙西。',64,'全唐诗/poet.song.173000.json','["未成花柳種成堤，早有先聲到浙西。", "待得已書馴雉績，不妨聊訪舊鸞棲。", "堂前風入琴三弄，江上春歸雨一犂。", "莫道催科能樣急，也分一念到羣黎。"]'),
('509a5e84-3565-48f9-94bf-6af890031b8d','與周希顔遊靈泉歸途偶作','陳文蔚','宋','宋诗','song-poetry','','[]','花日遲遲暖似烘，杖藜飛舞趁東風。',64,'全唐诗/poet.song.173000.json','["花日遲遲暖似烘，杖藜飛舞趁東風。", "野橋傍水柳先綠，山寺留春桃正紅。", "信步哦詩忘日晚，因言契理覺春融。", "莆田遠在千山外，長使靈泉信息通。"]'),
('e57e10cb-5288-4791-91dd-9db82c42858c','和昌甫見寄韵','陳文蔚','宋','宋诗','song-poetry','','[]','每日相親一卷書，席門猶是昔年如。',32,'全唐诗/poet.song.173000.json','["每日相親一卷書，席門猶是昔年如。", "似公長者今時少，花外何時見小車。"]'),
('f18d9ac2-48ab-45f2-a436-63b63d0da955','清明上冢見杜鵑花','陳文蔚','宋','宋诗','song-poetry','','[]','春來未聽杜鵑啼，但見青山花滿枝。',32,'全唐诗/poet.song.173000.json','["春來未聽杜鵑啼，但見青山花滿枝。", "俗禮不違聊上冢，他鄉寒食嘆年時。"]'),
('f326834d-6e92-4ca6-b6f8-e33da2b081ff','希顔見寄二絕和韵  其一','陳文蔚','宋','宋诗','song-poetry','','[]','海棠带雨淺深紅，共憇閒亭拂面風。',32,'全唐诗/poet.song.173000.json','["海棠带雨淺深紅，共憇閒亭拂面風。", "識得春光隨處樂，鬢絲誰管已成翁。"]'),
('1cb23a49-9e46-4548-965c-70afb3c79e99','希顔見寄二絕和韵  其二','陳文蔚','宋','宋诗','song-poetry','','[]','乳燕將雛看學飛，絕勝對客麈頻揮。',32,'全唐诗/poet.song.173000.json','["乳燕將雛看學飛，絕勝對客麈頻揮。", "綠陰翠幄閒中好，誰道春隨紅紫歸。"]'),
('48397030-a75c-4ff5-b62a-e8beb1408533','周公美載酒見過以長句見謝意','陳文蔚','宋','宋诗','song-poetry','','[]','門前題鳳風何薄，雪夜回舟意未真。',64,'全唐诗/poet.song.173000.json','["門前題鳳風何薄，雪夜回舟意未真。", "誰似松溪弄明月，興來載酒訪幽人。", "扣舷牛渚盟當踐，落帽龍山約又新。", "况有梅花凉玉雪，暑窗容我日爲鄰。"]'),
('6f54b01e-125a-4d81-a063-ce8878093dde','中秋後一夕正望浮橋觀月','陳文蔚','宋','宋诗','song-poetry','','[]','省賦山間明月章，好風吹我上河梁。',64,'全唐诗/poet.song.173000.json','["省賦山間明月章，好風吹我上河梁。", "冰輪不带一分缺，玉鑑無如今夕光。", "正自凭欄觀水靜，不妨倚杖看人忙。", "有誰會得遲歸意，籟息天高午夜涼。"]'),
('b1addeea-97e3-4ae6-9f79-3f2b94c6b3b2','重九後一日同公美遊靈泉公美舉示蓮塘納凉之句後公美和予浮橋觀月之韵紀靈泉之遊予以老人不快不暇即賦老人既安用渠納凉韵爲謝','陳文蔚','宋','宋诗','song-poetry','','[]','寺訪靈泉山路長，賦詩因得話蓮塘。',64,'全唐诗/poet.song.173000.json','["寺訪靈泉山路長，賦詩因得話蓮塘。", "林間度竹風無暑，澗裏流花水带香。", "靜勝携筇終日款，閑來坐石滿襟凉。", "紀遊未暇牽人事，題品輸君第一章。"]'),
('16674a24-c3a5-428f-bb15-4eab0740cbfa','昌甫寄徐崇甫書并崇甫寄渠詩及渠兄弟和章因次其韵呈昌甫','陳文蔚','宋','宋诗','song-poetry','','[]','念作章泉去，川流日夜東。',48,'全唐诗/poet.song.173000.json','["念作章泉去，川流日夜東。", "一身長是客，雙鬢已成翁。", "霽想濂溪月，和思柳下風。", "平安毅齋信，多謝爲流通。"]'),
('8ab157c3-6021-477e-b271-33578a47d79b','十月九日同公美踐上林之約回途紀實','陳文蔚','宋','宋诗','song-poetry','','[]','景入小春方嫩寒，緩行不覺鳥間關。',64,'全唐诗/poet.song.173000.json','["景入小春方嫩寒，緩行不覺鳥間關。", "倚空疊嶂何崷崒，带石清溪屢繞環。", "政擬徘徊檀木嶺，且先點檢上林山。", "杖藜未作忙歸計，又喜臨清得釣灣。"]'),
('46b6e661-1bce-4170-9e36-81c5cf53ef15','壬午三月廿三日偕諸生携酒過公美家公美宅前山花爛開極可愛爲賦一絕','陳文蔚','宋','宋诗','song-poetry','','[]','青春深處每徘徊，爲愛花城錦繡堆。',32,'全唐诗/poet.song.173000.json','["青春深處每徘徊，爲愛花城錦繡堆。", "誰似君家奇絕處，坐迎春色入門來。"]'),
('92ef61e5-b49d-4251-964c-fa1b82da08e5','公美約同遊龍安寺僧留小飲歸途一絕','陳文蔚','宋','宋诗','song-poetry','','[]','幾年無便到招提，沙路徐行趁碧溪。',32,'全唐诗/poet.song.173000.json','["幾年無便到招提，沙路徐行趁碧溪。", "花竹禪房成小款，笑談不覺到斜西。"]'),
('b71b5b47-341d-4c77-abf4-0bb2f0debad3','十一日同諸友登南臺二絕  其一','陳文蔚','宋','宋诗','song-poetry','','[]','萬里秋風約我曹，俯觀闤闠總塵勞。',32,'全唐诗/poet.song.173000.json','["萬里秋風約我曹，俯觀闤闠總塵勞。", "躋攀不藉登山屐，身世從知本自高。"]'),
('dcdbbde7-e04a-463e-957f-da2c9c24c76c','十一日同諸友登南臺二絕  其二','陳文蔚','宋','宋诗','song-poetry','','[]','脚底雲山疊疊低，面前一带繞清溪。',32,'全唐诗/poet.song.173000.json','["脚底雲山疊疊低，面前一带繞清溪。", "秋光總可供吟筆，寫作登高第一題。"]'),
('f38b316c-1f59-487a-856c-df16980e9fac','登山却立俯視一村風物殊可人意二絕  其一','陳文蔚','宋','宋诗','song-poetry','','[]','桑柘陰中日日行，只聞犬吠與鷄鳴。',32,'全唐诗/poet.song.173000.json','["桑柘陰中日日行，只聞犬吠與鷄鳴。", "此時身在煙雲上，眼界不知如許明。"]'),
('93c063db-7ccd-42ce-8bfa-ad775b834f25','登山却立俯視一村風物殊可人意二絕  其二','陳文蔚','宋','宋诗','song-poetry','','[]','竹樹誰家跨小橋，清溪一带抱山腰。',32,'全唐诗/poet.song.173000.json','["竹樹誰家跨小橋，清溪一带抱山腰。", "不須更倩王摩詰，水墨平鋪百尺綃。"]'),
('dbf4cd3a-7268-4975-acc3-182845fd24d9','重陽侍老人飲','陳文蔚','宋','宋诗','song-poetry','','[]','九十慈親鬢髮皤，今年菊早去年花。',32,'全唐诗/poet.song.173000.json','["九十慈親鬢髮皤，今年菊早去年花。", "一尊細說重陽事，似此清歡有幾家。"]'),
('c1027da5-fd7f-4155-bdfb-36fef3368b9f','節後赴傅巖叟之招望日同遊棲隠菴華嚴寺呈巖叟及同游者','陳文蔚','宋','宋诗','song-poetry','','[]','乘興聯翩渡小溪，輕車不怕日斜西。',64,'全唐诗/poet.song.173000.json','["乘興聯翩渡小溪，輕車不怕日斜西。", "擬來古寺觀新扁，且向山齋讀舊題。", "茆屋起烟歸路暝，秋雲閣雨暮天低。", "人生適意惟行樂，不較毫芒寵辱齊。"]'),
('24f7176c-4767-4bf6-aab0-e2ff30374c68','巖叟用前韵相留踐雲巖之約和韵以謝','陳文蔚','宋','宋诗','song-poetry','','[]','屢陪軒騎過橫溪，每想雲巖望眼西。',64,'全唐诗/poet.song.173000.json','["屢陪軒騎過橫溪，每想雲巖望眼西。", "酬約再尋山下路，賦詩留與石間題。", "吟風弄月計爲上，競利爭名著總低。", "明日杖藜歸故隠，人生離合信難齊。"]'),
('fc35949b-8752-472f-8bb2-aee6d987d36a','贈說相道人','陳文蔚','宋','宋诗','song-poetry','','[]','我生本是山澤癯，只愛竹林癡讀書。',32,'全唐诗/poet.song.173000.json','["我生本是山澤癯，只愛竹林癡讀書。", "道人相遇說心相，我亦無心更問渠。"]'),
('6424cfbc-c8ba-4dad-a687-fbc6f6a501f5','齋前梅開','陳文蔚','宋','宋诗','song-poetry','','[]','每歲衝寒出探梅，如今花向屋簷開。',32,'全唐诗/poet.song.173000.json','["每歲衝寒出探梅，如今花向屋簷開。", "玉顔相見無朝晚，繞樹須拚日百回。"]'),
('c6b8cc31-2c40-42a1-8542-82277d7cf78c','癸未二月廿五日訪周道人西菴戲題','陳文蔚','宋','宋诗','song-poetry','','[]','道人邀我飯胡麻，半日清閒得遠家。',32,'全唐诗/poet.song.173000.json','["道人邀我飯胡麻，半日清閒得遠家。", "多少欲來無路問，空於洞口覓桃花。"]'),
('44f78085-d35f-4395-a538-ce16ba907180','清明前二日同周公美黄子京郊行和子京韵  其一','陳文蔚','宋','宋诗','song-poetry','','[]','武夷雲會總儒衣，今似晨星漸覺稀。',32,'全唐诗/poet.song.173000.json','["武夷雲會總儒衣，今似晨星漸覺稀。", "晚節喜君同臭味，不嫌枯淡肯來歸。"]'),
('f935e1d6-bb52-4083-9426-2b2146595043','清明前二日同周公美黄子京郊行和子京韵  其二','陳文蔚','宋','宋诗','song-poetry','','[]','尋春杖屨偶乘閒，多謝詩囊肯破慳。',32,'全唐诗/poet.song.173000.json','["尋春杖屨偶乘閒，多謝詩囊肯破慳。", "坐石有言盟白石，愛山隨意買青山。"]'),
('19890add-5783-4952-9bba-e875dc363359','清明前二日同周公美黄子京郊行和子京韵  其三','陳文蔚','宋','宋诗','song-poetry','','[]','大道公行居廣居，敢將仁義作蘧廬。',32,'全唐诗/poet.song.173000.json','["大道公行居廣居，敢將仁義作蘧廬。", "直須至理超然會，不在陳編細字書。"]'),
('eff63bda-3e8e-4ebb-8ca4-ca58ca1ab136','後一日因展省歸途口占  其一','陳文蔚','宋','宋诗','song-poetry','','[]','千丈摳衣記武夷，家山今日屢攀躋。',32,'全唐诗/poet.song.173000.json','["千丈摳衣記武夷，家山今日屢攀躋。", "春風拍拍滿懷處，况是花開更鳥啼。"]'),
('2052e895-08da-4fe3-aa80-cbd94ea775ec','後一日因展省歸途口占  其二','陳文蔚','宋','宋诗','song-poetry','','[]','春光休道屬誰家，造化平鋪無等差。',32,'全唐诗/poet.song.173000.json','["春光休道屬誰家，造化平鋪無等差。", "不問世間凡草木，得春隨意總皆花。"]'),
('addd4cb1-4837-478e-9350-032a6cf83868','寄題黄子京貧樂齋','陳文蔚','宋','宋诗','song-poetry','','[]','羞逐紛紛世所趨，東溪風月未嘗孤。',64,'全唐诗/poet.song.173000.json','["羞逐紛紛世所趨，東溪風月未嘗孤。", "閉門蒿藋從渠長，堆案簡編聊自娛。", "機括要須明活法，簞瓢非但守枯株。", "不觀點也風雩意，灑落胸中一累無。"]'),
('4dd29f01-2ce3-4b30-8a1d-5d478ab75b84','又謝子京惠贄見','陳文蔚','宋','宋诗','song-poetry','','[]','少日深期造孔門，于今老矣嘆無聞。',64,'全唐诗/poet.song.173000.json','["少日深期造孔門，于今老矣嘆無聞。", "自憐大業乖傳授，頼有遺編可討論。", "君贈名章多過譽，我慚衰朽不勝文。", "誓言願畢餘生力，細與窮源探本根。"]'),
('9ec7e1a1-e868-4cb6-9777-1b8996ff94e7','集著尚書偶成','陳文蔚','宋','宋诗','song-poetry','','[]','水飲已忘三月味，囊空真乏一錢儲。',32,'全唐诗/poet.song.173000.json','["水飲已忘三月味，囊空真乏一錢儲。", "屢空本是吾家事，贏得閒身且著書。"]'),
('2a1f8f69-bc81-486f-b3ff-471b77f87004','灌圃','陳文蔚','宋','宋诗','song-poetry','','[]','少日嘗嗤稼圃非，近來閒聽老農知。',32,'全唐诗/poet.song.173000.json','["少日嘗嗤稼圃非，近來閒聽老農知。", "世間機械從來耻，不憚晨昏抱甕疲。"]'),
('c25c4d24-14f5-42d8-8551-507efb5018dd','賦决明','陳文蔚','宋','宋诗','song-poetry','','[]','每薦盤餐自覺清，嘗於雨後擷其英。',32,'全唐诗/poet.song.173000.json','["每薦盤餐自覺清，嘗於雨後擷其英。", "未言服餌收奇效，翠葉黄花眼早明。"]'),
('e8575cf7-de4f-4ea2-81d4-9a8c736c40d2','永豐祝子益和予詩見寄許見訪以長句謝之且堅其約','陳文蔚','宋','宋诗','song-poetry','','[]','反關甘與世情暌，綠遍閒庭草欲齊。',64,'全唐诗/poet.song.173000.json','["反關甘與世情暌，綠遍閒庭草欲齊。", "何處客來談列岫，有人雪踏自東溪。", "坐低流俗幾千輩，已見新詩第一題。", "他日竹林如肯過，聖門相與探端倪。"]'),
('105e30bd-df03-43d9-8cb1-a53fbe93c08f','寄題列岫','陳文蔚','宋','宋诗','song-poetry','','[]','面面青山不記名，想知宜雨亦宜晴。',64,'全唐诗/poet.song.173000.json','["面面青山不記名，想知宜雨亦宜晴。", "去來自在雲千疊，高下無多屋數楹。", "晨誦晝絃俱樂事，春光秋月總詩情。", "箇中真樂誰能識，不問人間枯與榮。"]'),
('6fb8bd1d-d7f0-47ac-a642-3a6ae951634b','葉茂卿寄詩卷賦此以謝之','陳文蔚','宋','宋诗','song-poetry','','[]','正念交情舊，忽來詩卷新。',48,'全唐诗/poet.song.173000.json','["正念交情舊，忽來詩卷新。", "既能賒酒飲，寧作賣書貧。", "計想尋窗下，閒須過澗濱。", "爲言田舍樂，花鳥亦情真。"]'),
('61789cb5-cbcf-492d-8672-8c1c46595759','送趙國宜之官武林','陳文蔚','宋','宋诗','song-poetry','','[]','自從棲隠入山深，間闊真同金玉音。',64,'全唐诗/poet.song.173000.json','["自從棲隠入山深，間闊真同金玉音。", "已謂清光依日月，不知幽趣尚園林。", "暫違陶徑菊松面，喜動蘇堤梅柳心。", "聞道專留薦賢牘，知音當在伯牙琴。"]'),
('d6125b6f-fb66-4ab1-9da2-89f112c7ead5','送趙惠卿赴玉沙法曹','陳文蔚','宋','宋诗','song-poetry','','[]','不辭艱險涉江湖，素志惟期欲展舒。',64,'全唐诗/poet.song.173000.json','["不辭艱險涉江湖，素志惟期欲展舒。", "平允外應無別法，坦夷中自有亨衢。", "雖云天遠雁行近，未至風高魚素疏。", "見說民淳須事簡，不妨宦學進工夫。"]'),
('ccddeba5-ecae-48a0-83f5-15e97759b25d','昌甫前詩見簡方和去未達間再於巖叟處見後詩和韵以謝','陳文蔚','宋','宋诗','song-poetry','','[]','章泉相去每相思，多謝交情不見遺。',64,'全唐诗/poet.song.173000.json','["章泉相去每相思，多謝交情不見遺。", "繾綣方賡前日句，聯翩又讀後來詩。", "梅方迎臘多投好，菊已凌霜不入時。", "大抵世情皆若此，吾儕真結歲寒知。"]'),
('1932a882-841e-42c0-b7a5-af40312b6b32','一夕夢中得絕句覺時惟記後二句最真因潤色足成之','陳文蔚','宋','宋诗','song-poetry','','[]','歲月苦爲身口累，風霜無奈鬢毛侵。',32,'全唐诗/poet.song.173000.json','["歲月苦爲身口累，風霜無奈鬢毛侵。", "中間一事却奇特，存得當時一片心。"]'),
('1bb7bb2f-297e-4362-beb4-0f6a092036a4','甲申正月答昌甫見寄韵代書','陳文蔚','宋','宋诗','song-poetry','','[]','負米嘗漂迹，關心爲倚門。',48,'全唐诗/poet.song.173000.json','["負米嘗漂迹，關心爲倚門。", "盡歡惟啜菽，奉旨屢空尊。", "溫劑勞分給，新詩且記存。", "開緘細吟諷，小立近黄昏。"]'),
('71c66ce4-e542-4641-8a87-cf1cc2254c5a','周公美嘗年有紅梅之約今花時雨雪公美以詩遣花酒和韵以謝','陳文蔚','宋','宋诗','song-poetry','','[]','紅梅高賞趁春晴，不記年華幾甲庚。',32,'全唐诗/poet.song.173000.json','["紅梅高賞趁春晴，不記年華幾甲庚。", "花酒一時雙遣至，却愁不似對梅清。"]'),
('197c996d-4440-4998-8b53-e610039cb806','清明資福僧遣詩賦此以答之','陳文蔚','宋','宋诗','song-poetry','','[]','清明恰值雨晴時，賸喜鄰僧福有詩。',64,'全唐诗/poet.song.173000.json','["清明恰值雨晴時，賸喜鄰僧福有詩。", "十里懶尋沽酒旆，一編深下讀書帷。", "放懷是處青春好，無事於中白日遲。", "况是精藍去家近，興來何惜瘦藤支。"]'),
('4db9fb07-a31e-4f6c-b115-a43f6092fb5e','和公美一絕','陳文蔚','宋','宋诗','song-poetry','','[]','欺人一任雪堆頭，豈復長懷身外愁。',32,'全唐诗/poet.song.173000.json','["欺人一任雪堆頭，豈復長懷身外愁。", "涉世自知今已慣，風波應不覆虛舟。"]'),
('4d3f405f-909d-41cd-acf0-3749c30a02e0','四月二日往檀林登車遇雨度鵝湖嶺漸覺開霽一路晴快野花滿山賦二絕  其一','陳文蔚','宋','宋诗','song-poetry','','[]','出門正爾值淋漓，決策登車不自疑。',32,'全唐诗/poet.song.173000.json','["出門正爾值淋漓，決策登車不自疑。", "一路新晴天借與，花香鳥語却撩詩。"]'),
('11cafa1b-e5e6-42fa-ad4d-ba72ce4b4714','四月二日往檀林登車遇雨度鵝湖嶺漸覺開霽一路晴快野花滿山賦二絕  其二','陳文蔚','宋','宋诗','song-poetry','','[]','塊坐蕭齋廢短筇，一春長在雨聲中。',32,'全唐诗/poet.song.173000.json','["塊坐蕭齋廢短筇，一春長在雨聲中。", "野花留得春光在，無數青山玉雪叢。"]'),
('02e6913d-78d1-4b1d-986b-97dde8189647','問塵清坐久之歸途偶得絕句','陳文蔚','宋','宋诗','song-poetry','','[]','問塵清坐興悠哉，小立朱橋未忍回。',32,'全唐诗/poet.song.173000.json','["問塵清坐興悠哉，小立朱橋未忍回。", "好景吟情忽相契，小溪流出柳陰來。"]'),
('b5705f8a-737e-4dd3-845b-c67cd9271a3e','崧嶺石泉','陳文蔚','宋','宋诗','song-poetry','','[]','高城石井下成池，對自初分混沌時。',32,'全唐诗/poet.song.173000.json','["高城石井下成池，對自初分混沌時。", "雖小古今無涸溢，却憐江海有盈虧。"]'),
('bdc12cd1-2cb5-4e49-a029-a0e0628adcc0','家園偶聞野花香','陳文蔚','宋','宋诗','song-poetry','','[]','杖藜曾是爲春忙，紫陌青山到處芳。',32,'全唐诗/poet.song.173000.json','["杖藜曾是爲春忙，紫陌青山到處芳。", "不謂竹林棲隠地，好風時遶野花香。"]'),
('0a9da2ff-84ac-45b3-b0b0-50c7296fa27e','六月十二日喜雨','陳文蔚','宋','宋诗','song-poetry','','[]','麟經書雨意何如，可喜非常故可書。',64,'全唐诗/poet.song.173000.json','["麟經書雨意何如，可喜非常故可書。", "膏澤未觀南畝遍，嫩涼且覺北窗虛。", "採詩好入豐年頌，把酒聊娛化日舒。", "懷抱一時寬畝𤱶，微痾勿藥頓消除。"]'),
('22c14a16-e9d5-4a9a-b3dd-38c70a038cdf','賤生諸友有祝頌語以五十六字謝之','陳文蔚','宋','宋诗','song-poetry','','[]','庸庸不作世間奇，空負生成造化機。',64,'全唐诗/poet.song.173000.json','["庸庸不作世間奇，空負生成造化機。", "歲月漫驚多髮積，功程殊未進毫微。", "不貪腰下懸金印，且自尊前戲綵衣。", "多謝諸君借輝潤，一朝盈篋盡珠璣。"]'),
('6dd6203c-0ab7-4d22-b588-819665b5f83c','縱步過資福寺僧留飲出示凈度文三教一理論戲書時寺門桂花爛開','陳文蔚','宋','宋诗','song-poetry','','[]','一編凈度出玄文，因憇書窗醉酒尊。',32,'全唐诗/poet.song.173000.json','["一編凈度出玄文，因憇書窗醉酒尊。", "儒釋未須談一二，且於花下立黄昏。"]'),
('8788ca31-8bc1-4def-a877-361dee45d6f9','九月十八日自雙溪還寺車中偶得','陳文蔚','宋','宋诗','song-poetry','','[]','太初元有此山川，往古來今幾許年。',64,'全唐诗/poet.song.173000.json','["太初元有此山川，往古來今幾許年。", "合是地靈神降嶽，爲生人傑柱驚天。", "遺民但抱羲農朴，正學誰知孔孟傳。", "要識碧溪流不斷，後人須看石崖鎸。"]'),
('befd50b0-a5b4-4c09-94c0-851e01b4203e','隠將峽口占二絕  其一','陳文蔚','宋','宋诗','song-poetry','','[]','小似武夷深更幽，地盤九曲一溪流。',32,'全唐诗/poet.song.173000.json','["小似武夷深更幽，地盤九曲一溪流。", "誅茆結屋雖成左，贏得青山自在遊。"]'),
('8494df56-f523-45d8-9ade-e4411fb05c4a','隠將峽口占二絕  其二','陳文蔚','宋','宋诗','song-poetry','','[]','四顧青山數畝餘，豈無閑地可耕鋤。',32,'全唐诗/poet.song.173000.json','["四顧青山數畝餘，豈無閑地可耕鋤。", "有人肯辦入山苦，滿谷桑麻繞舍蔬。"]'),
('4765550b-c11c-44af-9bc2-561625ac7d87','謝昌甫以詩惠藥牋','陳文蔚','宋','宋诗','song-poetry','','[]','藥裹屢蒙扶病親，一番書至一情真。',64,'全唐诗/poet.song.173000.json','["藥裹屢蒙扶病親，一番書至一情真。", "人言莫急晨昏奉，我嘆尚爲萍梗身。", "棲隠重曾定要約，章泉一見話悲辛。", "吳牋况拜慇懃賜，且續新詩爲縷陳。"]'),
('43e45291-8668-47c1-8777-ec78ccb333a8','和張元德寄昌甫末章見及之韵','陳文蔚','宋','宋诗','song-poetry','','[]','江南目斷短長亭，會面無由見德星。',64,'全唐诗/poet.song.173000.json','["江南目斷短長亭，會面無由見德星。", "所及交情無皂白，且欣師訓炳丹青。", "君將偃室春鳴瑟，我但萊衣日過庭。", "多謝新詩相勉進，敢忘圭復識中扃。"]'),
('55dbcb48-5bf4-4664-8c6e-4bc9a4a8692c','用前韵寄昌甫','陳文蔚','宋','宋诗','song-poetry','','[]','幾欲來觀魚計亭，未酬此約已星星。',64,'全唐诗/poet.song.173000.json','["幾欲來觀魚計亭，未酬此約已星星。", "自從蕭寺一回別，不記春山幾度青。", "尚友古人長閉戶，喜聞新命忽揚庭。", "興來會作扁舟去，剝啄應勞爲啟扃。"]'),
('3cb35994-1756-41d1-a629-a2d4bc8e3b50','和周公美韵','陳文蔚','宋','宋诗','song-poetry','','[]','風光報答可無詩，漸喜春風熟燕泥。',64,'全唐诗/poet.song.173000.json','["風光報答可無詩，漸喜春風熟燕泥。", "客至甚思留竹隠，書來無奈趣巖棲。", "幸同故國雲雖暮，朗誦新吟日未西。", "自愧續貂才不敏，徘徊月已在榱題。"]'),
('0bef744d-a005-4943-8daa-a09805ea110b','趙忠州雨中賞海棠','陳文蔚','宋','宋诗','song-poetry','','[]','問春何事苦晴慳，春意惜花留嫩寒。',32,'全唐诗/poet.song.173000.json','["問春何事苦晴慳，春意惜花留嫩寒。", "共到花前細商畧，精神最好雨中看。"]'),
('a854f049-ceac-4d9a-99e8-6e7e9bc0a0dc','賦蕭爽薝蔔戲巖叟','陳文蔚','宋','宋诗','song-poetry','','[]','且喜花時雨不妨，凭闌閒與細平章。',64,'全唐诗/poet.song.173000.json','["且喜花時雨不妨，凭闌閒與細平章。", "一池交映月添白，六出同妍雪遜香。", "素有書癡緣病懶，不知詩興爲渠忙。", "道人雅好惟清供，却恐花神索酒觴。"]'),
('1d5a11e9-929a-4c96-b016-32310f8a930b','月夜觀花','陳文蔚','宋','宋诗','song-poetry','','[]','底事更深睡不感，惜花愛月兩關情。',32,'全唐诗/poet.song.173000.json','["底事更深睡不感，惜花愛月兩關情。", "黑甜一枕雖云美，未省人間有此清。"]'),
('f348c256-1a3b-44f8-bd43-f12ee223338a','巖叟約觀棲隠薝蔔雨阻和前韵送酒再用韵答之','陳文蔚','宋','宋诗','song-poetry','','[]','暫輟書程業未妨，倚欄高誦杜陵章。',64,'全唐诗/poet.song.173000.json','["暫輟書程業未妨，倚欄高誦杜陵章。", "不知雨意將詩意，但覺花香带酒香。", "散破苦嫌饑雀下，爭喧閒看蜜蜂忙。", "也知棲隠如蕭爽，恨不花前共舉觴。"]'),
('239f206e-1b2c-4160-9b6e-0457b8681e13','六月十七夜待月','陳文蔚','宋','宋诗','song-poetry','','[]','凝佇虛亭未愜心，清光隠隠隔疏林。',32,'全唐诗/poet.song.173000.json','["凝佇虛亭未愜心，清光隠隠隔疏林。", "欲觀玉鑑呈全體，獨倚朱欄到夜深。"]'),
('c5ad6512-2f9d-425b-a173-82d64f3551e8','黄子京見訪值予未還留詩和韵以謝  其一','陳文蔚','宋','宋诗','song-poetry','','[]','自從別去竹林居，暇日尋詩每念渠。',32,'全唐诗/poet.song.173000.json','["自從別去竹林居，暇日尋詩每念渠。", "疾讀新編慰牢落，清風習習滿襟裾。"]'),
('0b4d08ce-a570-484c-937a-f07fa5dd138b','黄子京見訪值予未還留詩和韵以謝  其二','陳文蔚','宋','宋诗','song-poetry','','[]','此去團溪百里餘，不須蹤跡嘆差殊。',32,'全唐诗/poet.song.173000.json','["此去團溪百里餘，不須蹤跡嘆差殊。", "平鋪此理元無間，曾驗工程進也無。"]'),
('b15b401f-96e3-4725-b3e1-5e1fbcc57b6b','子京又以長篇告別值予欲出一絕謝之','陳文蔚','宋','宋诗','song-poetry','','[]','二年不作上方游，一日重尋舊話頭。',32,'全唐诗/poet.song.173000.json','["二年不作上方游，一日重尋舊話頭。", "却恨嬋娟成兩處，清尊無分共中秋。"]'),
('7df6341f-071d-47bb-a8db-036414d8fb9d','又和胡應祥遊石井韵','陳文蔚','宋','宋诗','song-poetry','','[]','兩年再踏鉛山路，今日初嘗石井泉。',32,'全唐诗/poet.song.173000.json','["兩年再踏鉛山路，今日初嘗石井泉。", "碧玉巖邊論湯餠，全勝五鼎擊肥鮮。"]'),
('5cefdf2f-b84b-4f80-8e5c-a61008358726','題玲瓏山','章良能','宋','宋诗','song-poetry','','[]','短鍤長鑱出萬峰，鑿開混沌作玲瓏。',32,'全唐诗/poet.song.173000.json','["短鍤長鑱出萬峰，鑿開混沌作玲瓏。", "市朝可是無巇嶮，更向山林巧用工。"]'),
('42763a94-f0dd-4ee8-a7a5-10248c28e160','題李伯時飛騎習射圖','章良能','宋','宋诗','song-poetry','','[]','禁營貔虎天廐龍，技癢不奈芻粟豐。',256,'全唐诗/poet.song.173000.json','["禁營貔虎天廐龍，技癢不奈芻粟豐。", "聞道寶津嘗護駕，前期踴躍矜驍雄。", "紅綃低繫柳枝碧，滿滿彎弓斫鬉射。", "偶然穿葉未爲奇，截下紅綃方破的。", "綵繩長曳綵毬輕，閃爍眩轉如奔星。", "弦頭霹靂起馬脚，回看一箭落欃槍。", "烏紗帽穩春衫薄，交韉煥爛青絲絡。", "千步場深隔九關，畢景馳驅有餘樂。", "李侯應奉隨春官，日晏歸穿衛士班。", "平生抵死憐神駿，絕藝那能不細看。", "不學閻公伏池側，倉皇丹粉供宣索。", "他年乘興試追尋，妙處祇須憑子墨。", "十六蹄翻意態真，罄控應節顧眄親。", "當時騎士盡應爾，尚想元豐兵制新。", "慨今多事困供億，養兵殆且殫民力。", "未聞士歌馬騰槽，安得從容觀戲劇。"]'),
('0c1e9e7d-da51-4d51-ae9e-c17c493f218b','和林擇之齊山韵','蔡幼學','宋','宋诗','song-poetry','','[]','褰裳涉秋浦，散策上齊山。',108,'全唐诗/poet.song.173000.json','["褰裳涉秋浦，散策上齊山。", "盼往謝塵囂，瞻新得層巒。", "萬象翕呈露，跬步不可間。", "下巧瞰坤軸，高奇仰天剜。", "硿矼禹所穴，巀嶭秦開關。", "始探困傴僂，徐行快平寬。", "斲鳳扣危壁，登虬俯澄灣。", "突然出鰲背，但見江漫漫。", "匪特激愚懦，且以訂羣頑。"]'),
('ef985bc3-c471-4cf9-830a-f52fd1e9e0f7','早至湖心小園','蔡幼學','宋','宋诗','song-poetry','','[]','凉月在木末，我行出林坰。',72,'全唐诗/poet.song.173000.json','["凉月在木末，我行出林坰。", "林坰何所事，愛此朝氣清。", "池荇浥風露，洒洒醉夢醒。", "來禽俯清泚，相照臉色頳。", "悠然到瓜田，鈎蔓亦軒騰。", "萬物咸得宜，吾生亦何營。"]'),
('ea8ab449-8163-4880-b3c8-70681d806760','浮家','蔡幼學','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春風掃積素，春雨漲新綵。',168,'全唐诗/poet.song.173000.json','["春風掃積素，春雨漲新綵。", "再行適良願，及此嘉致足。", "溪桃綻腮紅，溪柳起膚粟。", "萬物欣向榮，吾生亦從欲。", "浮家信所之，懽意到僮僕。", "行樂人有言，未省我心曲。", "憶昔西湖春，安輿探芳谷。", "綵舫漾晴漪，名園玩清縟。", "星郎引羣雛，戲舞衣裻裻。", "歸來夜未央，清話屢更燭。", "只今天一涯，把酒遠相屬。", "富貴竟何時，一官乃覊束。", "法喜聞我言，低回若驚辱。", "一笑强相酬，歸裝宜早促。"]'),
('3b507e89-0e6d-4f88-8abf-73356e3ca531','月夜贈項子謙','蔡幼學','宋','宋诗','song-poetry','','[]','月色凈加水，奈此清興何。',72,'全唐诗/poet.song.173000.json','["月色凈加水，奈此清興何。", "誰人當領此，隔屋呼項佗。", "駕言先我出，追隨費經過。", "履聲適相逢，歡然憇亭荷。", "乾坤何浩蕩，水月光相磨。", "醉歸巷無人，羣兒自前呵。"]'),
('902d6133-2159-4541-9206-a440db230837','晚泊','蔡幼學','宋','宋诗','song-poetry','','[]','落日維舟處，沙頭望眼平。',48,'全唐诗/poet.song.173000.json','["落日維舟處，沙頭望眼平。", "牛羊分隴下，燈火隔林明。", "人散村墟靜，溪寒風浪生。", "漁翁醉眠穩，小艇任斜橫。"]'),
('24ef8067-d4a2-410d-b7c0-9b2436cedd9e','田園','蔡幼學','宋','宋诗','song-poetry','','[]','野水萍無主，清風草自香。',48,'全唐诗/poet.song.173000.json','["野水萍無主，清風草自香。", "庭陰新似染，物色去如忙。", "岸樹魚依綠，畦花蝶鬭黄。", "家園向來夢，靜數四年强。"]'),
('b99b19d7-64c7-4225-9224-87435b293e53','澤卿示蘭亭考作蕭翼取蘭亭辭','黄疇若','宋','宋诗','song-poetry','','[]','長廊睥睨來者誰，出門解后渠得知。',216,'全唐诗/poet.song.173000.json','["長廊睥睨來者誰，出門解后渠得知。", "不言使者求遺書，只言浴繭當及時。", "從容與語益款洽，論到翰墨尤瑰奇。", "山僧技癢不自禁，稍出脩禊蘭亭詞。", "啟函展玩未及竟，袖有黄紙天庭追。", "口呿氣褫僵欲死，一騎趣向咸陽馳。", "虬鬚天子喜折屐，詔許兩禁同觀之。", "龍騰鳳集在御榻，平生觸眼何曾窺。", "自從繭紙歸昭陵，寶氣夜夜光陸離。", "千年議論經幾手，極力追倣分毫釐。", "博聞强誌子桑子，上下纂輯無或遺。", "清臞不滿六尺長，中有文字無津涯。", "歸君此編忽自笑，山東學究真黠兒，而今御史還書癡。"]'),
('7f8d1034-d8d2-4f28-a7df-2963badcf32e','柴門春晝','吳柔勝','宋','宋诗','song-poetry','','[]','深巷寂無人，鳥聲花塢春。',24,'全唐诗/poet.song.173000.json','["深巷寂無人，鳥聲花塢春。", "蓽門長日掩，天地一閑身。"]'),
('fc61a099-c634-441d-948f-e9a3e9837a8c','唐人挾彈圖','吳柔勝','宋','宋诗','song-poetry','','[]','嚙膝嘶風徑奔駻，花前挾彈回頭看。',32,'全唐诗/poet.song.173000.json','["嚙膝嘶風徑奔駻，花前挾彈回頭看。", "一鳥不鳴春晝閑，野水清清綠陰暗。"]'),
('8704223a-ac2f-4905-b61b-29e46ad13b11','三友圖','吳柔勝','宋','宋诗','song-poetry','','[]','髯龍嘶風山石裂，玉人影斷橫斜月。',32,'全唐诗/poet.song.173000.json','["髯龍嘶風山石裂，玉人影斷橫斜月。", "一聲翠羽琅玕東，羅浮夢斷微茫中。"]'),
('e50a017c-1819-4543-b178-39352be59074','送林明府','吳柔勝','宋','宋诗','song-poetry','','[]','擬續宣城志，難忘令尹賢。',48,'全唐诗/poet.song.173000.json','["擬續宣城志，難忘令尹賢。", "庭空無獄訟，齋靜有詩篇。", "心比秋雲遠，政如霜月懸。", "活人最多處，饑歲作豐年。"]'),
('cd48477c-1a10-4423-b857-a0175e308f05','牧亭秋色','吳柔勝','宋','宋诗','song-poetry','','[]','丹楓酣霜壓林丘，黄葉老盡巖西頭。',32,'全唐诗/poet.song.173000.json','["丹楓酣霜壓林丘，黄葉老盡巖西頭。", "不應蔓草烟漠漠，併作粉繪蒼山秋。"]'),
('0e2a3be9-0bdc-40b6-bcc0-3a94bd859d94','句','商侑','宋','宋诗','song-poetry','','[]','地俯梅溪新棟宇，源通橘井近煙霞。',16,'全唐诗/poet.song.173000.json','["地俯梅溪新棟宇，源通橘井近煙霞。"]'),
('d06cad07-cc1e-4c3c-bb7b-2f938fbfeefa','隆州','趙善詔','宋','宋诗','song-poetry','','[]','三山高峭拔，鼎峙各爭雄。',24,'全唐诗/poet.song.173000.json','["三山高峭拔，鼎峙各爭雄。", "秀氣鍾英物，衣冠盛蜀中。"]'),
('2275d418-c053-42b9-8a9f-1b9273e93e17','句  其一','趙善詔','宋','宋诗','song-poetry','','[]','仁壽州如斗，分符愧罔功。',12,'全唐诗/poet.song.173000.json','["仁壽州如斗，分符愧罔功。"]'),
('52d7bf9f-97ea-47ce-82b2-913e07887fa2','句  其二','趙善詔','宋','宋诗','song-poetry','','[]','誰謂山城僻，倫魁此破荒。',12,'全唐诗/poet.song.173000.json','["誰謂山城僻，倫魁此破荒。"]'),
('af8beba5-17eb-42e6-9bcd-ebe9b8c9edf1','釋宗顯重修寶梵院','陳祖仁','宋','宋诗','song-poetry','','[]','身浮漚□草頭露，實見卓立中流柱。',128,'全唐诗/poet.song.173000.json','["身浮漚□草頭露，實見卓立中流柱。", "世網走逃如脫兔，菩提了了無他路。", "迷人捐軀大火聚，自灼自焚甘自苦。", "諸佛菩薩慈憫故，教以一舍無復取。", "顯公超然知落處，功德銷磨貲萬數。", "一簞一鉢朝昏度，佛事日富貧非慮。", "如是降心如是住，嘔噦自蓄與蟲蠹。", "風清松竹相爾汝，誰其嗣之需一悟。"]'),
('f9fdbb7e-c7a1-4616-adf2-9c00e8567cec','句  其一','顔棫','宋','宋诗','song-poetry','','[]','未厭慇懃達曙看。',8,'全唐诗/poet.song.173000.json','["未厭慇懃達曙看。"]'),
('604bbe32-17e5-4aac-9556-371dc6c1f983','句  其二','顔棫','宋','宋诗','song-poetry','','[]','眼明喜見曉光舒。',8,'全唐诗/poet.song.173000.json','["眼明喜見曉光舒。"]'),
('a4038189-570f-4f05-b4f4-00952f90f216','句  其三','顔棫','宋','宋诗','song-poetry','','[]','衰草連天慘淡黄。',8,'全唐诗/poet.song.173000.json','["衰草連天慘淡黄。"]'),
('bee73009-bd09-4a84-acbe-39d46a7e5f8e','句  其四','顔棫','宋','宋诗','song-poetry','','[]','一带溪山畫不如。',8,'全唐诗/poet.song.173000.json','["一带溪山畫不如。"]'),
('f4d2f91d-eccc-43d6-8e0e-7474523956d8','遣懷五首寄致道  其一','謝直','宋','宋诗','song-poetry','','[]','貧者士之常，富亦我所欲。',60,'全唐诗/poet.song.173000.json','["貧者士之常，富亦我所欲。", "得常詎可厭，逐欲何由足。", "荒哉化蝶翁，微歟監河粟。", "人生命如綫，日須不盈匊。", "俯仰天地間，何由謝羈束。"]'),
('42743712-b444-4ead-b104-a0b0c59cbc21','遣懷五首寄致道  其二','謝直','宋','宋诗','song-poetry','','[]','時命各有遇，何言富與貧。',60,'全唐诗/poet.song.173000.json','["時命各有遇，何言富與貧。", "有來疾雷電，決去微埃塵。", "坐令區區者，視此爲鬼神。", "既有得失患，自忘情性真。", "所以首陽山，昔有餓死人。"]'),
('745f9829-8f69-4069-93ce-89a1c173568e','遣懷五首寄致道  其三','謝直','宋','宋诗','song-poetry','','[]','君子不謀食，士固食於人。',60,'全唐诗/poet.song.173000.json','["君子不謀食，士固食於人。", "饑餓自有責，何足煩吾神。", "拂几展我書，熟讀困蹇屯。", "羲文與周孔，可鑒道屈信。", "歎歎眼中事，悠悠塵間身。"]'),
('775c9e36-9e77-45e8-9953-e203f89937ac','遣懷五首寄致道  其四','謝直','宋','宋诗','song-poetry','','[]','生當益於人，爲道固不同。',60,'全唐诗/poet.song.173000.json','["生當益於人，爲道固不同。", "賜也乃結駟，回也乃屢空。", "憶昔年少壯，未知理窮通。", "收身百憂餘，自置寂寞中。", "饘粥儻可繼，當爲七十翁。"]'),
('a411b022-573e-47a0-8380-f9cb71b235db','遣懷五首寄致道  其五','謝直','宋','宋诗','song-poetry','','[]','在昔營居巢，首尾三十年。',60,'全唐诗/poet.song.173000.json','["在昔營居巢，首尾三十年。", "高鄰念羈旅，分我佳林泉。", "自從倉幕歸，亦買半頃田。", "坐念顔太師，粥竭祇益煎。", "不如邊孝先，晝眠腹便便。"]'),
('b840ed96-f35e-4420-b028-c78568aba9cb','辰十月八日同希周掃松靈石晚步松下愴然有懷以數詩示兒姪輩邀希周同賦時阿同在新城他日當寄之  其一','謝直','宋','宋诗','song-poetry','','[]','寒光轉南陸，夕景上喬木。',60,'全唐诗/poet.song.173000.json','["寒光轉南陸，夕景上喬木。", "層柯蔭脩徑，疏密散金綠。", "緬懷載酒人，蘿蔓記遐躅。", "行行出林表，煙莽際童牧。", "時有種麥兒，揮鉏電翻覆。"]'),
('6aaeb960-adb5-40ba-a94c-b3ee3a209b1e','辰十月八日同希周掃松靈石晚步松下愴然有懷以數詩示兒姪輩邀希周同賦時阿同在新城他日當寄之  其二','謝直','宋','宋诗','song-poetry','','[]','老樹誰所栽，及茲上交蓋。',60,'全唐诗/poet.song.173000.json','["老樹誰所栽，及茲上交蓋。", "崢嶸仰巨樟，秀發憐稚檜。", "悠然攪心思，慨我百年外。", "我懷引以長，天色慘欲晦。", "投牀聞夕鐘，擁衾不成醉。"]'),
('bbf67255-b17e-4964-945f-d0be0f1408f6','辰十月八日同希周掃松靈石晚步松下愴然有懷以數詩示兒姪輩邀希周同賦時阿同在新城他日當寄之  其三','謝直','宋','宋诗','song-poetry','','[]','長懷邴曼容，遠慕蘧伯玉。',60,'全唐诗/poet.song.173000.json','["長懷邴曼容，遠慕蘧伯玉。", "養志則安能，寡過亦所欲。", "邈哉誤儒冠，坐使衣食促。", "籝書不論金，終身未易讀。", "灑掃慚老僧，日食纔一粥。"]'),
('de03545b-33c4-4628-9213-692ab9537f7d','辰十月八日同希周掃松靈石晚步松下愴然有懷以數詩示兒姪輩邀希周同賦時阿同在新城他日當寄之  其四','謝直','宋','宋诗','song-poetry','','[]','先公爲直言，蔡林古無書。',60,'全唐诗/poet.song.173000.json','["先公爲直言，蔡林古無書。", "家貧賣窗箔，編籜聚所餘。", "取之寫文字，瑣細行蟲蛆。", "遂令後奕世，衣冠出門閭。", "今爲執政孫，學與不學歟。"]'),
('f2174868-4862-4846-b5de-3e4ef946fa07','辰十月八日同希周掃松靈石晚步松下愴然有懷以數詩示兒姪輩邀希周同賦時阿同在新城他日當寄之  其五','謝直','宋','宋诗','song-poetry','','[]','小夫智解短，錐刀競其身。',60,'全唐诗/poet.song.173000.json','["小夫智解短，錐刀競其身。", "養志與養體，孰爲能事親。", "堂堂父母軀，浩浩仁義貧。", "此貧不以道，此樂豈非真。", "我知我天分，人言葛天民。"]'),
('90e4f4fd-1e15-43a1-b2c0-4f1e003d60ad','辰十月八日同希周掃松靈石晚步松下愴然有懷以數詩示兒姪輩邀希周同賦時阿同在新城他日當寄之  其六','謝直','宋','宋诗','song-poetry','','[]','昔在井田日，一民本非四。',60,'全唐诗/poet.song.173000.json','["昔在井田日，一民本非四。", "農隙或工商，其秀乃稱士。", "是知桑禾間，可以寄書史。", "時非長桀耦，時得伊傅事。", "卒歲優游哉，吾道甚簡易。"]'),
('df9d6e69-fa79-40a6-9679-2d0f0551a483','辰十月八日同希周掃松靈石晚步松下愴然有懷以數詩示兒姪輩邀希周同賦時阿同在新城他日當寄之  其七','謝直','宋','宋诗','song-poetry','','[]','淵明真學者，餘事聊爲詩。',60,'全唐诗/poet.song.173000.json','["淵明真學者，餘事聊爲詩。", "我讀命子篇，愴彼已焉辭。", "後來杜陵翁，自笑身長兒。", "我昔過庭日，教誨真嚴師。", "哀哀蓼莪淚，灑灑墳樹枝。"]'),
('ead554ef-4ab3-4316-aafb-fe41015090e3','辰十月八日同希周掃松靈石晚步松下愴然有懷以數詩示兒姪輩邀希周同賦時阿同在新城他日當寄之  其八','謝直','宋','宋诗','song-poetry','','[]','長懷際天淵，短懷在眉睫。',60,'全唐诗/poet.song.173000.json','["長懷際天淵，短懷在眉睫。", "吾門起典午，台徙今五葉。", "中原氣象屬，前輩風流接。", "柰何不竟書，而欲事作業。", "感此懷短長，賦詩寫胸脅。"]'),
('296ec96a-4311-457c-b31b-af94619c3f4b','詩一首','謝直','宋','宋诗','song-poetry','','[]','上有皇天下后土，此身不患無歸所。',32,'全唐诗/poet.song.173000.json','["上有皇天下后土，此身不患無歸所。", "憑誰說與清河公，何苦爲人作黄祖。"]'),
('0c1e2c0f-0264-4b57-afcf-8a091820be81','山居二首寄朝中故舊  其一','謝直','宋','宋诗','song-poetry','','[]','苒苒年華漸向西，可能回脚下塗泥。',64,'全唐诗/poet.song.173000.json','["苒苒年華漸向西，可能回脚下塗泥。", "靜收營慮還書卷，少有工夫入菜畦。", "潔甚水蒲邊白鳥，翩然風柳下黄鸝。", "猶嫌宿處聞雞犬，更待移深過虎蹊。"]'),
('29847db2-4da3-472d-9df9-ccf33fcde8b2','山居二首寄朝中故舊  其二','謝直','宋','宋诗','song-poetry','','[]','造化涵洪靡不容，近分一谷著愚公。',64,'全唐诗/poet.song.173000.json','["造化涵洪靡不容，近分一谷著愚公。", "地因沙漲偏宜竹，山爲巖多却礙松。", "夜靜圖書天曉睡，臘寒薪火暑天風。", "獨慚道學工夫淺，却比先師不屢空。"]'),
('b8479585-ceba-4821-b343-feb76e1cd541','挽劉省庵','謝直','宋','宋诗','song-poetry','','[]','敢謂曾同學，巍科尚累君。',48,'全唐诗/poet.song.173000.json','["敢謂曾同學，巍科尚累君。", "世須存我輩，天乃誤斯文。", "鄉國緣當盡，衣冠哭忍聞。", "何當車挽什，刻石累高墳。"]'),
('3a2985b1-b76e-4f9a-9edc-0c52924aba50','陪邑大夫登西峴峰','許中應','宋','宋诗','song-poetry','','[]','晴暾發輕暑，惠風蕩繁林。',144,'全唐诗/poet.song.173000.json','["晴暾發輕暑，惠風蕩繁林。", "驅車青郊路，舉跐西山岑。", "隨流翫回轉，就陰便清深。", "子規續哀響，倉庚流好音。", "側徑既窈窕，層崖亦嶇嶔。", "石泉潄瓊瑶，松風戞璆琳。", "雲間渺虛曠，恍若韶濩臨。", "水樂名其亭，上有坡仙吟。", "泉甘瀹新茗，芹香侑清斟。", "攀躋豈不勞，景勝忘所任。", "夕陽忽在山，清興浩難禁。", "山靈應有約，何時重來尋。"]'),
('8fc9cd29-cc7c-4631-ba15-3220413968ee','涵碧亭','許中應','宋','宋诗','song-poetry','','[]','清泚何妨一整巾，蒼崖先自怯登臨。',64,'全唐诗/poet.song.173000.json','["清泚何妨一整巾，蒼崖先自怯登臨。", "汎現人物幾榮悴，祗有林泉無古今。", "萬个倘容參直節，一泓端欲印無心。", "蒼顔還許交同老，羅隠書堂尚可尋。"]'),
('a2b8120c-1046-4688-a7a9-4e2cd9ca8fa7','題資福院平綠軒','王益祥','宋','宋诗','song-poetry','','[]','丈室無餘地，生涯小有天。',48,'全唐诗/poet.song.173000.json','["丈室無餘地，生涯小有天。", "推窗成曠闊，俯檻遶清漣。", "載酒日邊客，聞歌柳外船。", "隔牆人易與，賸著買山錢。"]'),
('c9ebe08c-d3be-4607-b948-5903f54af029','入餘杭縣','高似孫','宋','宋诗','song-poetry','','[]','明發遵西陸，驅車月流光。',96,'全唐诗/poet.song.173000.json','["明發遵西陸，驅車月流光。", "佳山迎車來，知是古餘杭。", "危樹露如雨，平野日未陽。", "支流滀清源，弱羽無高翔。", "人家叢灌下，世載山水鄉。", "扣門作午憩，白飯羞文魴。", "邂逅有足歡，離合非其常。", "主人不予鄙，予留亦徜徉。"]'),
('3b3fe07a-0345-4789-b186-408bd3f427af','憩昌化民家','高似孫','宋','宋诗','song-poetry','','[]','晚程息勞轍，白日流西暉。',132,'全唐诗/poet.song.173000.json','["晚程息勞轍，白日流西暉。", "水鳥得魚去，耘夫荷鋤歸。", "川原杳仟綿，林野雜依霏。", "一來扣竹館，相邀入荆扉。", "重巖吐清溜，澄陰布殘菲。", "曰予考此室，十世相因依。", "左右桑果足，歲日雞豚肥。", "豐猶未至裕，歉亦無能饑。", "予聞良自愜，欲謀北山薇。", "有田可同耕，有蠶當共衣。", "車夫猝無情，此志仍重違。"]'),
('cbd2c60f-4a48-40aa-bdd9-d78077d4b203','答李才翁','高似孫','宋','宋诗','song-poetry','','[]','素意杳難尋，殘鑪屬晚陰。',48,'全唐诗/poet.song.173000.json','["素意杳難尋，殘鑪屬晚陰。", "花知西洛事，雁叫北人心。", "客共艱難盡，詩隨老大深。", "金陵書不到，消息又沉沉。"]'),
('fa316435-44a2-48ff-8b4b-045c13b3c2cc','宋江都研','高似孫','宋','宋诗','song-poetry','','[]','數寸清純玉不如，入波陶髮冷蕭疏。',64,'全唐诗/poet.song.173000.json','["數寸清純玉不如，入波陶髮冷蕭疏。", "千金爛抵荆山鵲，一璞深刳渭水魚。", "墨带花香臨近澗，泓沉燈影了殘書。", "從來端歙難優劣，名下真成士不虛。"]'),
('63f5e29b-f755-4389-9261-46b4234949c9','答宇文文學','高似孫','宋','宋诗','song-poetry','','[]','無能應俗苦皇皇，詩不驚人筆事荒。',64,'全唐诗/poet.song.173000.json','["無能應俗苦皇皇，詩不驚人筆事荒。", "天下無山如飯顆，人間有水自滄浪。", "左杯右蟹一舟足，早韭晚菘三畝强。", "莫謂覺來亡可嗜，逢人猶自覓花忙。"]'),
('ed29de5d-c087-4a33-ae3f-8f8a24d1c7e0','燕文貴山水圖','高似孫','宋','宋诗','song-poetry','','[]','道山堂上御府畫，展卷猶能記老燕。',64,'全唐诗/poet.song.173000.json','["道山堂上御府畫，展卷猶能記老燕。", "十日何由辦水石，千金乃可分江天。", "楚湘兩岸風落木，海嶽三秋雁度川。", "大山小山俱好隠，江南夢去曲肱眠。"]'),
('00be427f-8ffb-445d-bd64-74fd87d099df','答武昌吳廣文','高似孫','宋','宋诗','song-poetry','','[]','平生不識武昌樓，官柳青青好在不。',64,'全唐诗/poet.song.173000.json','["平生不識武昌樓，官柳青青好在不。", "庾亮笛吹黄鵠月，簡栖碑駁碧苔秋。", "山橫赤壁含情斷，水出瞿唐快意流。", "何處叫君同一醉，並舟秦女擘箜篌。"]'),
('c06da8c5-56ad-4d10-b010-eb2769771ae4','丹砂歌謝胡史君惠砂床','高似孫','宋','宋诗','song-poetry','','[]','宜州丹砂産暘谷，不比辰溪攢箭鏃。',96,'全唐诗/poet.song.173000.json','["宜州丹砂産暘谷，不比辰溪攢箭鏃。", "素霓深抱赤城霞，斬猩半染于闐玉。", "海日下照珊瑚紅，化爲姹女金芙蓉。", "一從擘華分禹璞，猶有絳氣埋雲峰。", "鑄鼎泥壇有消息，坐看光輝成五色。", "淮南雞犬亦同升，九轉真能生羽翼。"]'),
('75e07c6f-ed20-4ebf-af2f-0b5986b77392','琵琶引','高似孫','宋','宋诗','song-poetry','','[]','人生聚散難爲別，何况匆匆作胡越。',128,'全唐诗/poet.song.173000.json','["人生聚散難爲別，何况匆匆作胡越。", "梅梢带雪下昭陽，明朝便隔關山月。", "長城不戰四夷平，臣妾一死鴻毛輕。", "回憑漢使報天子，爲妾奏此琵琶聲。", "長安城中百萬戶，家家競學琵琶譜。", "酸聲苦調少人知，食雪天山憶蘇武。", "西風吹霜雁飛飛，漢宮月照秋砧衣。", "嫖姚已死甲兵老，公主公主何時歸。"]'),
('e7e15eb1-5724-4e01-9f54-df5f1ed9b25b','銅雀硯歌','高似孫','宋','宋诗','song-poetry','','[]','曹公夜讌凌雲臺，一言契闊含餘哀。',128,'全唐诗/poet.song.173000.json','["曹公夜讌凌雲臺，一言契闊含餘哀。", "分香老伎各雲雨，歌舞不盡埋蒿萊。", "漠漠頹基鄴山下，萬里煙塵無一瓦。", "井幹罇酒自平生，烏鵲飛南播遺雅。", "老農墾雨開荒寒，一礫千金苔未乾。", "世人好奇不好近，直比周簋仍商盤。", "老璞渾渾殊質魯，得水猶能發妍嫵。", "更與人間作瓌古，月明夜盜西陵土。"]'),
('c6489981-72e8-411b-9a73-f45f040ad70d','黄居中瀟湘圖歌','高似孫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','天晴而雨斷兮，作蒼梧九疑之高。',126,'全唐诗/poet.song.173000.json','["天晴而雨斷兮，作蒼梧九疑之高。", "秋風行而川怒兮，泄瀟湘洞庭之奔流。", "樹不知名兮山抱複嶺，沙不計程兮水趨它洲。", "波作止兮蛟舞蛟蟄，雲晦明兮猿呼猿愁。", "原不可作兮蘭亦塵土，賈傅歸漢兮鵩其何尤。", "誰呼魚兮北澨有酒，誰鼓枻兮南津有舟。", "懷斯人兮杳靄千里，目悵望兮吾其歸休。"]'),
('873ab051-5ea1-4ee8-9e7b-97a6e920f24d','寄吳鈐幹','高似孫','宋','宋诗','song-poetry','','[]','有偉千人傑，能爲萬里遊。',144,'全唐诗/poet.song.173000.json','["有偉千人傑，能爲萬里遊。", "挂帆春背雁，問驛夜驚鷗。", "道路空留滯，文章莫暗投。", "九疑生雨遍，三峽带寒流。", "采藥青神觀，題詩白帝樓。", "乾坤供爛醉，星斗照閑愁。", "漢已歸蕭相，天難壽武侯。", "詞人頭欲雪，壯士淚如秋。", "中下猶須策，西南夙倚籌。", "有錢書盡買，滅虜志終酬。", "猿破高唐夢，龍馴灧澦舟。", "行人定安穩，夏近可歸不。"]'),
('1efb08ee-2511-4075-9493-844e6c4dc380','騎鸞引贈句曲山吳道士','高似孫','宋','宋诗','song-poetry','','[]','夜騎白鸞出琳闕，三萬仙官鏘珮玦。',128,'全唐诗/poet.song.173000.json','["夜騎白鸞出琳闕，三萬仙官鏘珮玦。", "雲雷帖妥過剛風，左推日九右扶月。", "一息瑶池翠水家，阿母迎謁龍驅車。", "青娥彈絲玉妃酒，坼盡蟠桃紅玉花。", "九天丈人來問道，太極之前天不老。", "丹霞一氣玉樞宮，寶笈繩金容探討。", "井君沐浴波五色，洞房光芒上奔日。", "天上傳呼六丁直，星斗離離礙鸞翼。"]'),
('cd645cb8-ddfe-44ce-88a4-386fc24c2b28','聚景園','高似孫','宋','宋诗','song-poetry','','[]','翠華不向苑中來，可是年年惜露臺。',32,'全唐诗/poet.song.173000.json','["翠華不向苑中來，可是年年惜露臺。", "水際春風寒漠漠，官梅却作野梅開。"]'),
('6362dc03-c66e-4cfb-bfa4-950359cbd310','四聖觀','高似孫','宋','宋诗','song-poetry','','[]','水明一色抱神州，雨壓輕塵不敢浮。',64,'全唐诗/poet.song.173000.json','["水明一色抱神州，雨壓輕塵不敢浮。", "山北山南人喚酒，春前春後客凭樓。", "射熊館暗花投扆，下鵠池深柳拂舟。", "白髮邦人能道舊，君王曾奉上皇遊。"]'),
('1b10ea32-5f7a-4157-9990-cea0955a0404','石楠','高似孫','宋','宋诗','song-poetry','','[]','自隨野意訂山行，香浸楠花白水生。',32,'全唐诗/poet.song.173000.json','["自隨野意訂山行，香浸楠花白水生。", "借得風來帆便飽，隔溪新度一聲鶑。"]'),
('c36e530b-21c2-41fb-a72a-fc181e3204ca','木香','高似孫','宋','宋诗','song-poetry','','[]','下簾深與意商量，無酒何如此夜長。',32,'全唐诗/poet.song.173000.json','["下簾深與意商量，無酒何如此夜長。", "一樹木絲仙有分，依然只作秘書香。"]'),
('ab74b3be-2e6b-4722-a9ac-d76b6f2ed3c1','梅','高似孫','宋','宋诗','song-poetry','','[]','舍南舍北雪猶存，山外斜陽不到門。',32,'全唐诗/poet.song.173000.json','["舍南舍北雪猶存，山外斜陽不到門。", "一夜冷香清入夢，野梅千樹月明村。"]'),
('089ee0d1-658f-47eb-bca6-2bd99b82ece6','紀夢','高似孫','宋','宋诗','song-poetry','','[]','翠峰嵯峨三十六，寒泉落空響哀玉。',272,'全唐诗/poet.song.173000.json','["翠峰嵯峨三十六，寒泉落空響哀玉。", "岩花石路勢縈紆，玉闌干護脩筠綠。", "雪髯老人負紫瓢，金絲麈尾遥相招。", "紅螺酌酒湛湛碧，坐倚蒼石吹洞簫。", "孤鶴來傳天上詔，老人挽予偕一到。", "飄飄高舉淩青冥，直過罡風履黄道。", "祥光樓閣倚崢嶸，神虎守闕森衛兵。", "雙闔朱扉忽微啟，中有靈官來遠迎。", "絳衣持斧立丹陛，玉皇手中玉如意。", "雲璈風瑟自宮商，天聲清越非人世。", "帝旁青童傳帝宣，文華宮中呼謫仙。", "謫仙顧余笑且言，子宜亟返來他年。", "探懷贈我五色筆，子當寶之慎勿失。", "濃香氤氳迷帝所，長揖老人下西廡。", "身從日月上頭行，俯視斗杓分子午。", "雲氣相隨步武生，過耳但覺松風鳴。", "覺來握筆紀佳夢，月明樓鼓撾三更。"]'),
('282e3b23-0f95-415f-9f96-222ad88db513','蟹包','高似孫','宋','宋诗','song-poetry','','[]','妙手能誇薄樣梢，桂香分入蟹爲包。',32,'全唐诗/poet.song.173000.json','["妙手能誇薄樣梢，桂香分入蟹爲包。", "也知不枉持螯手，便是持螯亦草茅。"]'),
('f2471f3d-d66f-4ef9-a678-a27e58a2c98f','富次律送蟳','高似孫','宋','宋诗','song-poetry','','[]','鱗甲錯夏物，懷青莫如蟳。',72,'全唐诗/poet.song.173000.json','["鱗甲錯夏物，懷青莫如蟳。", "蘇公今張華，何微不知音。", "入手巨螯健，斫雪雋莫禁。", "宛然如玠輩，曾是秉玉心。", "蟹因龜蒙傑，酒與畢郎深。", "二者不可律，食之當酌斟。"]'),
('5afd08f8-0a77-4523-92d1-e06768aa82bb','趙嘉甫致松江蟹','高似孫','宋','宋诗','song-poetry','','[]','雁知楓已落松江，催得書來急蟹綱。',64,'全唐诗/poet.song.173000.json','["雁知楓已落松江，催得書來急蟹綱。", "消一兩螯如斲雪，强三百橘未經霜。", "無詩莫學天隨子，有酒當呼吏部郎。", "不解持經聊戒殺，省嫌無板去燒湯。"]'),
('cc3b0a1b-903a-487f-a017-4701114c9ea9','李迅甫送蟹  其一','高似孫','宋','宋诗','song-poetry','','[]','小橘枚枚菊未黄，蟹肥全不待些霜。',32,'全唐诗/poet.song.173000.json','["小橘枚枚菊未黄，蟹肥全不待些霜。", "莫嫌草草相知少，猶是曾爲吏部郎。"]'),
('b12b399f-0bb9-493e-8d55-c42a590c03df','李迅甫送蟹  其二','高似孫','宋','宋诗','song-poetry','','[]','平生嗜此龜蒙蟹，便無錢也多多買。',32,'全唐诗/poet.song.173000.json','["平生嗜此龜蒙蟹，便無錢也多多買。", "瞥見風姿已瀟瀟，一呷橙虀酒如澥。"]'),
('48edd9ef-657d-4191-a6a7-a34ee6fa901c','誓蟹羹','高似孫','宋','宋诗','song-poetry','','[]','年年作誓蟹爲羹，倦不能支畧放行。',64,'全唐诗/poet.song.173000.json','["年年作誓蟹爲羹，倦不能支畧放行。", "但是草泥行郭索，莫愁豕腹脹膨亨。", "酒今到此都空了，詩亦隨渠太瘦生。", "吏部一生豪到底，此時得意孰爲爭。"]'),
('5180bdbf-d192-4ad7-930c-fbe8a76b1575','趙嘉父送松江蟹','高似孫','宋','宋诗','song-poetry','','[]','青天肯爲蟹飛霜，蟹亦貪詩老更狂。',64,'全唐诗/poet.song.173000.json','["青天肯爲蟹飛霜，蟹亦貪詩老更狂。", "楓葉已隨詩共冷，菊花能爲酒先忙。", "平生爾雅誰能熟，此去玄經孰敢荒。", "剪去吳淞半江水，漁翁不敢叫滄浪。"]'),
('1bd02649-331b-485f-abe4-6a058cf4f49d','同父送松江蟹','高似孫','宋','宋诗','song-poetry','','[]','人間寧有幾松江，蟹到强時橙也黄。',64,'全唐诗/poet.song.173000.json','["人間寧有幾松江，蟹到强時橙也黄。", "非是龜蒙無此雋，自從茂世孰爲忙。", "乾坤大半漁爲宅，雪月從頭筆做牀。", "不讀晉書誰了此，晉書曾讀也蒼茫。"]'),
('8fe5a5d6-5838-4e2d-9d8b-1065e1730dd6','趙廣德送松江蟹','高似孫','宋','宋诗','song-poetry','','[]','江空蟹急窘於蒐，滿腹清凉做盡秋。',64,'全唐诗/poet.song.173000.json','["江空蟹急窘於蒐，滿腹清凉做盡秋。", "茶竈筆牀新意思，寢香衛戟戰風流。", "生拚不入吳王鱠，死亦相尋越女舟。", "得一好詩無可憾，無詩也不作騷愁。"]'),
('b1747643-2462-4263-bfd1-987c2af1872f','趙崇暉送魚蟹','高似孫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秋驅雁至至猶稀，且饌新篘理舊衣。',64,'全唐诗/poet.song.173000.json','["秋驅雁至至猶稀，且饌新篘理舊衣。", "蟹爲龜蒙何惜死，鱸非張翰且休肥。", "五湖已去無遺恨，三徑方歸有昨非。", "更欲借渠茶竈火，蕭蕭葉滿洞庭蘆。"]'),
('153261a2-b21e-4aa1-b367-3cc36ecdec86','趙君海惠蟳','高似孫','宋','宋诗','song-poetry','','[]','早揮鱠手作雲鼇，雪带晴飛且拍熬。',64,'全唐诗/poet.song.173000.json','["早揮鱠手作雲鼇，雪带晴飛且拍熬。", "安得輪囷如此壯，也知郭索許多騷。", "翰林風月從來別，太史江山一味豪。", "今夜筆牀船上去，已輸吏部十分高。"]'),
('ce1a26d3-831f-4eec-99fb-98b4ba7fe99f','江寺丞送蟹','高似孫','宋','宋诗','song-poetry','','[]','苦無多雨便重陽，憶殺池頭煮蟹凉。',32,'全唐诗/poet.song.173000.json','["苦無多雨便重陽，憶殺池頭煮蟹凉。", "政用此時消幾輩，菊花先作故山香。"]'),
('699fe98a-ab8d-4508-ac8a-418054b320c1','吳中致蟹','高似孫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','天雨洞庭霜，寒驅蟹力忙。',48,'全唐诗/poet.song.173000.json','["天雨洞庭霜，寒驅蟹力忙。", "全然空俗味，只是作詩香。", "酒已方纔熟，橙猶未肯黄。", "讓渠茶竈火，和月煮滄浪。"]'),
('9b61ec04-de98-48be-a3ca-8a5e6f25cdca','汪彊仲郎中送蟹','高似孫','宋','宋诗','song-poetry','','[]','連日天街候駕歸，且呼酒對早梅飛。',32,'全唐诗/poet.song.173000.json','["連日天街候駕歸，且呼酒對早梅飛。", "從來吏部高情別，右手分將老蟹肥。"]'),
('30d7c1fe-8275-4673-a4d3-8c6cc95b62f3','答癯菴致糟蟹','高似孫','宋','宋诗','song-poetry','','[]','秋入丹楓聲怒號，吳兒得志飛輕舠。',160,'全唐诗/poet.song.173000.json','["秋入丹楓聲怒號，吳兒得志飛輕舠。", "緯以萬竹瀾寒濤，有法如兵勇於鏊。", "彼蟹甚武殊驛騷，一霜二霜如此膏。", "物生固忌風味高，最以風味無一逃。", "葬之酒鄉泣醨糟，一醉竟死俱陶陶。", "了我一身凡幾醪，死生大矣惟所遭。", "飲中諸公人中豪，左手酒杯右手螯。", "醉魂浩蕩不可招，爲君以酒博葡蔔。", "世間萬事真牛毛，一醉一死俱蓬蒿。", "恭惟不殺心忉忉，視民如蟹嗚呼饕。"]'),
('654dffac-6b48-47fb-a573-f4c16adc39c5','䤌蟹','高似孫','宋','宋诗','song-poetry','','[]','西風送冷出湖田，一夢酣春落酒泉。',64,'全唐诗/poet.song.173000.json','["西風送冷出湖田，一夢酣春落酒泉。", "介甲盡爲香玉軟，脂膏猶作紫霞堅。", "魂迷楊柳灘頭月，身老松花甕裏天。", "不是無腸貪麴糵，要將風味與人傳。"]'),
('7480754b-7e1a-4696-b22b-a52218ba93a5','九懷','高似孫','宋','宋诗','song-poetry','','[]','望九疑兮雲雨，心慘慘兮思君。',276,'全唐诗/poet.song.173000.json','["望九疑兮雲雨，心慘慘兮思君。", "冉冉兮愁痕，楚波深兮斑竹活。", "歷嵯峩兮極眺，訊遐心兮誰將。", "蛟何躍兮衝波，鴻何驚兮離網。", "湘有蘋兮渚有荃，欲將誠兮無能宣。", "蒼莽兮何之，孰亮余兮㛹娟。", "羽何音兮鏘鏘，鳳何儀兮濟濟。", "朝騰余軔兮梧陰，夕娛兮清澧。", "蹇躊躇兮自喜，遡清川兮如洗。", "植館兮雲中，樹之兮石磊。", "磊貝闕兮鱗堂，雜青楓兮始霜。", "芷路兮蘅薄，桂飛橑兮蘭房。", "相芰荷兮可衣，美秋菊兮曾糧。", "瑶華兮在席，江有蘺兮吐芳。", "被薜兮带蘿，表之兮以蘭香。", "彙衆卉兮揚徽，貯芳辛兮同薰。", "哀絃切兮入雲，靈來下兮繽紛。", "捐余璫兮中流，遺余玦兮北渚。", "儼奉君兮嘉薦，乃遺余兮芳杜。", "時契闊兮難再，聊歌風兮自語。"]'),
('3b1e31dc-e312-4e26-954d-9d8f0f90e968','九懷 蒼梧帝','高似孫','宋','宋诗','song-poetry','','[]','攬九州兮余憂，民將魚兮誰瘳。',263,'全唐诗/poet.song.173000.json','["攬九州兮余憂，民將魚兮誰瘳。", "水受令兮安流，菱芃芃兮方秋。", "老帝力兮茫茫，射神魚兮飛舟。", "朝帝君兮不下，莽故疆兮生埃。", "踏蒼龍兮倏東，棲靈游兮故宮。", "擢桂棟兮蘭房，蕙幬兮荃床。", "翳殘書兮罅𦉟，杳空山兮神揚。", "神揚兮何極，有人來兮爲之太息。", "濕刓石兮酒寒，隠懷君兮傷惻。", "蓀橈兮桂檝，海若兮獻月。", "采水碧兮紫淵，弄蠙珠兮冰穴。", "無一芳兮可酬，心難吐兮猶咽。", "砥柱兮湯湯，龍門兮阻長。", "事難古兮悲傷，迹蒼奔兮蹇余以何往。", "朝欲逝兮河津，夕濯衣兮西漵。", "花漲兮波惡，魚鬭兮雲舞。", "沐余冠兮嵯嵯，濯予璫兮楚楚。", "靈心懌兮來下，乃遺余兮芳杜。", "玩芳杜兮三嗅，時不來兮孰與。"]'),
('cc4558d1-a66d-45e8-85c5-14e14b273afc','九懷 思禹','高似孫','宋','宋诗','song-poetry','','[]','草長兮菲菲，越山青兮霏微。',102,'全唐诗/poet.song.173000.json','["草長兮菲菲，越山青兮霏微。", "玉在珮兮欲語，望故宮兮如歸。", "酒闊兮猶香，僾流光兮庭幃。", "芳俎進兮蘭藉，玉鱗寒兮牲肥。", "靈翺兮醉只，笙噓雲兮霑衣。", "鼓輕舠兮無留，月共載兮依依。", "樂莫樂兮知幾，哀莫哀兮別離。", "鷓鴣愁兮忘飛。"]'),
('dadb6024-8b5b-429c-b94c-b3637e5102c2','九懷 越王臺','高似孫','宋','宋诗','song-poetry','','[]','江欲冷兮丹楓，月將缺兮初鴻。',97,'全唐诗/poet.song.173000.json','["江欲冷兮丹楓，月將缺兮初鴻。", "天如仄兮沉波，檝有聲兮追風。", "易莫易兮謀功，難莫離兮圖終。", "東山兮誰作，若斯人兮猶窮。", "水下鷖兮溶溶，山插雲兮叢叢。", "叫夫君兮不聞，拊遺聲兮如空。", "君不來兮誰晤，余心憂兮沖沖。"]'),
('8de3f9d6-f3f8-449f-b551-dcd64f7c89c2','九懷 鴟夷子皮','高似孫','宋','宋诗','song-poetry','','[]','越山兮青青，江波兮噴薄。',197,'全唐诗/poet.song.173000.json','["越山兮青青，江波兮噴薄。", "萬里兮長風，引驚瀾兮去之。", "夫君兮以淵爲期，水何爲兮勞苦。", "越山兮升雲，江水兮未平。", "舉酒兮訊君，將與余兮心傾。", "若有人兮颭雲旗，舞神魚兮踏文螭。", "奏水星兮叫冰夷，橫壯氣兮海爲飛。", "麋臺兮生草，言如毛兮人杲杲。", "夕宿兮江臯，越兵西兮如拉槁。", "一沐浴兮九江，水揚波兮淙淙。", "飛余橈兮雁渚，舍余璫兮漁矼。", "望美人兮未來，心不怡兮難降。", "有酒兮如冰，呼膾具兮魚龍腥。", "澆磊塊兮洗磅礴，有老父兮愁偏醒。"]'),
('0aab6b0b-7180-4e3c-8a33-7557cbdcf9db','九懷 浙水府','高似孫','宋','宋诗','song-poetry','','[]','君之來兮鞭潮，令冰夷兮毋驕。',168,'全唐诗/poet.song.173000.json','["君之來兮鞭潮，令冰夷兮毋驕。", "撫余車兮安驅，海難填兮魂銷。", "龍翼輈兮既東，旌翠昏兮生埃。", "蛟抗刃兮波赤，嚥霧光兮蓬萊。", "樂莫樂兮佳游，哀莫哀兮忘歸。", "簫鍾兮鐃鼓，吳歌兮楚舞。", "魚飛兮雁奔，君之樂兮俁俁。", "憩蹕兮嵯峩，陳席兮楚楚。", "撰德兮蒼崖，秦夸聲兮豪詡。", "騎雜遝兮鑾玲瓏，窮禹迹兮窺踐宮。", "民如蟹兮誰能聰，海水作兮號魚龍。", "歡未殫兮樂未終，金母號兮漢旌紅。"]'),
('8a195806-7a9b-4b4f-8bed-b2ad7e04f761','九懷 秦遊','高似孫','宋','宋诗','song-poetry','','[]','江上兮青山，水既去兮復還。',190,'全唐诗/poet.song.173000.json','["江上兮青山，水既去兮復還。", "引微風兮無瀾，擢桂槳兮閑閑。", "望美人兮來下，靈翩翩兮從女。", "劈中流兮揚舲，雁邕邕兮遵渚。", "玉衣兮畫裳，御清氣兮前青鳳。", "穆川后兮靜波，湘君遺兮蘭芳。", "行貞兮昭昭，璫明兮玉娟。", "天門兮爲開，萬夫哀兮惟女賢。", "翠帷下兮沉沉，花飲露兮陰陰。", "素鱗寒兮不動，寄風瑟兮瑶音。", "涉江兮采蘋，剪綃兮蠲塵。", "奉瑶華兮結辭，靈不見兮愁人。", "愁人兮柰何，目眇眇兮微波。", "路杳靄兮脩長，其柰何兮夕歌。"]'),
('0af6aadf-8a50-44a4-b560-74a12acf302b','九懷 江夫人','高似孫','宋','宋诗','song-poetry','','[]','若有人兮山阿，樂莫樂兮在薖。',128,'全唐诗/poet.song.173000.json','["若有人兮山阿，樂莫樂兮在薖。", "絜余珮兮有蘭，愜余裳兮有蘿。", "凌八荒兮騁望，悵山河兮悲壯。", "倒天漢兮濯江淮，眇風雲兮晤懷。", "竹樹兮冥蒙，海月兮朣朧。", "君何爲兮山中，鴻奔南兮逼輕舟。", "歌聞天兮擊中流，氣浩浩兮橫九州。", "山冉冉兮生雨，水汪汪兮迷浦。", "鴂一叫兮花愁，期美人兮春渚。"]'),
('93c300f2-9ae4-412a-b256-bd74474cb5a4','九懷 東山','高似孫','宋','宋诗','song-poetry','','[]','砥蒼崖兮燕危磐，枕淵洄兮夏留寒。',216,'全唐诗/poet.song.173000.json','["砥蒼崖兮燕危磐，枕淵洄兮夏留寒。", "谷懷煙兮川引霧，出漁鄉兮入樵路。", "屋如懸兮石將危，蕩蘭舟兮揚桂旗。", "江有蘺兮溪有蓀，沙一抹兮雲垂垂。", "耒宜雨兮帆宜風，香在罏兮各爲功。", "村醪熟兮春無度，水羞香兮雪登俎。", "晴陰節兮花亂飛，老漁歌兮野巫舞。", "靈埃樂兮憺忘歸，人無忘兮雨而雨。", "維余舟兮款神關，石𦉟𦉟兮蘿漫漫。", "帷之褰兮風毳急，石可憇兮苔痕斑。", "潭中人兮夜漁急，神魚舞兮陰妃泣，報靈君兮千罟集。", "水如練兮月冥冥，若月絃兮作湘聲。", "舟欲去兮且復留，耿不寐兮空隠憂。"]'),
('6f03e7e2-c2cb-4646-8ff4-20c4491713ce','九懷 嶀山雨','高似孫','宋','宋诗','song-poetry','','[]','無詩文。',4,'全唐诗/poet.song.173000.json','["無詩文。"]'),
('4dc12f3e-ebcd-4622-a8a9-db48ffab9812','山中楚辭  其一','高似孫','宋','宋诗','song-poetry','','[]','山如罨兮栖柔煙，鳥徘徊兮翠如褰。',64,'全唐诗/poet.song.173000.json','["山如罨兮栖柔煙，鳥徘徊兮翠如褰。", "蔭松柏兮牽丹泉，猿在上兮鶴在前。", "拍浮丘兮延偓佺，話坎離兮生坤乾。", "問山月兮今何年，月得道兮玄之玄。"]'),
('b0e2457b-4d4d-4453-be73-b84f85948864','山中楚辭  其二','高似孫','宋','宋诗','song-poetry','','[]','月澄午兮收雲，嚼鮮芳兮予酒。',55,'全唐诗/poet.song.173000.json','["月澄午兮收雲，嚼鮮芳兮予酒。", "朝列宿兮將舉，炯其北兮惟斗。", "斡四令兮無惰，活元氣兮眑眑。", "一罍兮上訴，思超凡兮辭垢。"]'),
('bf87ff0c-6cd9-4819-9985-fe0720076dee','山中楚辭  其三','高似孫','宋','宋诗','song-poetry','','[]','穆東皇兮受命，樂山中兮俱春。',56,'全唐诗/poet.song.173000.json','["穆東皇兮受命，樂山中兮俱春。", "風引樹兮欣欣，雨生波兮粼粼。", "天有心兮康予，朝復朝兮趨新。", "春空勞兮又去，山青青兮予親。"]'),
('d75b36a0-0426-474a-8a68-7801ca08d9f3','山中楚辭  其四','高似孫','宋','宋诗','song-poetry','','[]','若古兮多奇，御夏兮高明。',82,'全唐诗/poet.song.173000.json','["若古兮多奇，御夏兮高明。", "蹇千山兮在下，石吐泉兮泠泠。", "采新果兮半熟，被疏絺兮全輕。", "非老子兮孰悟，亦晉人兮予盟。", "風來南兮洗琴，棋落落兮爭聲。", "心有官兮自玉，天相知兮同醒。"]'),
('c514c7c3-9a57-415d-88f8-affe5f7aec36','山中楚辭  其五','高似孫','宋','宋诗','song-poetry','','[]','桂樹兮團欒，籬菊兮可采。',87,'全唐诗/poet.song.173000.json','["桂樹兮團欒，籬菊兮可采。", "石磊磊兮沿荔，雁嗷嗷兮離靉。", "人心悽兮易凉，時令遷兮誰縡。", "攬古昔兮自悵，視彭殤兮何待。", "吁嗟秋兮，不以悲而能輕，不以愁而爲怠。", "若得意兮騷者，酒淋騷兮如海。"]'),
('ddc080bb-4ce5-40f8-9672-a9884c6927d8','山中楚辭  其六','高似孫','宋','宋诗','song-poetry','','[]','木蔌蔌兮皆冬，汛山林兮迎雪。',85,'全唐诗/poet.song.173000.json','["木蔌蔌兮皆冬，汛山林兮迎雪。", "匠此妙兮磅礴，信天人兮豪傑。", "當是時雁分黯淡之雲，花弄扶疏之月。", "酒涉雋兮少對，詩造微兮自悅。", "天山兮誰饑，蔡州兮誰决。", "眇斯人兮毋作，雪霏霏兮空潔。"]'),
('f465749c-658f-4df5-9111-674c791f63d1','欵乃辭','高似孫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','帝子降兮北渚，目眇眇兮愁予。',84,'全唐诗/poet.song.173000.json','["帝子降兮北渚，目眇眇兮愁予。", "嫋嫋兮秋風，洞庭波兮木葉下。", "揭揭兮寒菼，濊濊兮輕罛。", "有鵜兮在梁，鴻何爲兮離網。", "白蘋深兮騁望，水之清兮濯纓。", "翁不語兮嗔偏醒，欵乃一聲兮天水淥。"]'),
('af6bd4b3-c791-45c4-8097-6dd42eab30ba','後欵乃辭','高似孫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭瀟湘白雪中，中有雲氣隨飛龍。',96,'全唐诗/poet.song.173000.json','["洞庭瀟湘白雪中，中有雲氣隨飛龍。", "漁父天寒網罟凍，山木盡亞洪濤風。", "漁翁暝踏孤舟立，滄浪水深青冥闊。", "不見湘妃鼓瑟時，至今斑竹臨江活。", "漁翁夜傍西巖宿，曉汲清湘燃楚竹。", "煙銷日出不見人，欵乃一聲山水淥。"]'),
('de72c0be-d59d-4bfb-9bd7-6a270169f521','嶀臺神絃曲  其一','高似孫','宋','宋诗','song-poetry','','[]','迅雙槳兮刊中流，風與力兮帆無留。',96,'全唐诗/poet.song.173000.json','["迅雙槳兮刊中流，風與力兮帆無留。", "瞥逝鴻兮呵慵虯，芷泣香兮木鳴樛。", "宛有人兮山之幽，翠翦字兮旌柔柔。", "朝陽澨兮夕陰洲，月不動兮雪霜浮。", "期靈君兮一徠游，虛谷應兮寒颼颼。", "酒可醺兮蘋可羞，靈不鄙兮攄吾愁。"]'),
('f26cd6d3-5981-425c-97bd-1e5fee6425f3','嶀臺神絃曲  其二','高似孫','宋','宋诗','song-poetry','','[]','水清清兮石鑿鑿，浪攻崖兮風洗壑。',96,'全唐诗/poet.song.173000.json','["水清清兮石鑿鑿，浪攻崖兮風洗壑。", "天飛凉兮衆木作，元氣湧兮魚龍惡。", "若有人兮老叢崿，跨黄羆兮度蘅幄。", "夕鴻溟兮曉名嶽，懷霖雨兮時電雹。", "靈來娭兮瑟蘭勺，水光開兮煙罷漠。", "律予辭兮徵眇邈，林劃嘯兮靈歟樂。"]'),
('0580bc89-c9e5-4fa1-bbce-7a639b3e92f6','花飛引','高似孫','宋','宋诗','song-poetry','','[]','花少思兮離離，企佳人兮不來。',56,'全唐诗/poet.song.173000.json','["花少思兮離離，企佳人兮不來。", "風嫋嫋兮吹愁，綠滿樹兮香在苔。", "鴂哀兮山裂，芳菲兮今歇。", "杳新知兮誰悅，期佳人兮柰何別。"]'),
('5f12a041-ebce-4122-b2b0-f58ab805e499','蓬萊遊  其一','高似孫','宋','宋诗','song-poetry','','[]','綠連霧兮窈窕，翠生香兮輕浮。',56,'全唐诗/poet.song.173000.json','["綠連霧兮窈窕，翠生香兮輕浮。", "花得道兮無妍，鳥涉仙兮何愁。", "心太平兮太平，功如水兮先秋。", "喬松來兮樂余，蓬萊樂兮堪游。"]'),
('402a068e-d7e1-4615-b507-26cac91b66e9','蓬萊遊  其二','高似孫','宋','宋诗','song-poetry','','[]','木采采兮交蔭，靈飛來兮隨鶴。',56,'全唐诗/poet.song.173000.json','["木采采兮交蔭，靈飛來兮隨鶴。", "月欲去兮仍西，風吹花兮未落。", "花未落兮猶春，酒依依兮如昨。", "王與謝兮讓余，蓬萊游兮堪樂。"]'),
('acb6ad2f-adbe-485f-bdc6-41275e3d2a87','秋蘭辭','高似孫','宋','宋诗','song-poetry','','[]','秋蘭兮青青，得道兮如素。',197,'全唐诗/poet.song.173000.json','["秋蘭兮青青，得道兮如素。", "娟娟兮好脩，行隠隠兮不渝。", "夫人兮孰懷，美蘭何爲兮覩處。", "秋蘭兮英英，含章兮自明。", "山中兮無人，其與誰兮晤傾。", "悲復樂兮樂復悲，悵來者兮不可期。", "悲莫悲兮有所思，樂莫樂兮心相知。", "贈子兮雜珮，朝能來兮夕能會。", "暮雨兮生愁，心繚悷兮何能嘅。", "訊蒼蒼兮如何，天不語兮雲嵯嵯。", "吐琬琰兮自通，宛清揚兮山之阿。", "望美人兮不來，閴寥寥兮浩歌。", "雲裾兮風裳，引沆瀣兮朝陽。", "澹自樂兮僾尚羊，豈無人兮而不香。"]'),
('8c344b86-826b-441b-ac36-96d2fa80463c','小山叢桂','高似孫','宋','宋诗','song-poetry','','[]','桂樹叢生兮山之幽，匽蹇布濩兮翠交流。',221,'全唐诗/poet.song.173000.json','["桂樹叢生兮山之幽，匽蹇布濩兮翠交流。", "壑谿錯互兮雲崒霄，石戔戔兮溜鳴瑶。", "鶴陰陰兮猿嗷嗷，攀援桂枝兮聊佳留。", "聊佳留兮遲遲，訊有華兮東籬。", "風景兮不可支，襟將舒兮孰怡。", "碕兮曲，山崒屼，攬賾邃兮心愰惚。", "潏兮沕，寥兮瑟，檉蘿密叢灌盤紆兮杳藏日。", "嶙峋鑿落兮蕫蘢回複，榛薄葐蒀兮葩華棻郁。", "青蘿素蔓兮薇蕪彧毓，兕勇熊遒兮來嘯來伏。", "山中崊崊兮嵬嵬，泠泠兮濟濟。", "蛩唧兮禽嘶，秋風兮自來。", "攀桂枝兮聊須留。", "桂花開兮芙蓉寒，桂花落兮芰荷乾。", "若人兮悲秋，山中兮胡爲不可留。"]'),
('fd9fedf6-ee59-4ce2-9aaa-4af44fe8eb57','朝丹霞  其一','高似孫','宋','宋诗','song-poetry','','[]','沐佳施兮清靈，滌三生兮無腥。',29,'全唐诗/poet.song.173000.json','["沐佳施兮清靈，滌三生兮無腥。", "迅玄挺兮嘉會，蛻吾骨兮坯吾形。"]'),
('e62f6de9-202d-42e7-bdd1-0a7a9f62119c','朝丹霞  其二','高似孫','宋','宋诗','song-poetry','','[]','杳倏駕兮潜青宜，舞剛風兮鵠分翎。',32,'全唐诗/poet.song.173000.json','["杳倏駕兮潜青宜，舞剛風兮鵠分翎。", "上何有兮無能名，老積氣兮寒泠泠。"]'),
('ef34dc77-799b-44d0-8730-b31dcc38f500','朝丹霞  其三','高似孫','宋','宋诗','song-poetry','','[]','窈復窈兮流火庭，物受鍊兮愁六丁。',32,'全唐诗/poet.song.173000.json','["窈復窈兮流火庭，物受鍊兮愁六丁。", "爍此鼎兮神無停，雪盡垢兮朝朱陵。"]'),
('db90b9ea-0819-49ec-b2dd-012e1752fe0d','朝丹霞  其四','高似孫','宋','宋诗','song-poetry','','[]','轉璇樞兮上亭亭，一語契兮驚群星。',32,'全唐诗/poet.song.173000.json','["轉璇樞兮上亭亭，一語契兮驚群星。", "味清浄兮不可經，玄復玄兮發新硎。"]'),
('b5d4db4a-d294-4672-8eda-dd770db202a1','朝丹霞  其五','高似孫','宋','宋诗','song-poetry','','[]','畫琳琅兮黄金繩，帝監觀兮燕清寧。',32,'全唐诗/poet.song.173000.json','["畫琳琅兮黄金繩，帝監觀兮燕清寧。", "聞不聞兮皦無際，毛髮竦兮心爲冰。"]'),
('1266bad2-3230-48ad-b26a-816ec35ddd86','朝丹霞  其六','高似孫','宋','宋诗','song-poetry','','[]','井有波兮通滄溟，玉抱德兮誰能銘。',32,'全唐诗/poet.song.173000.json','["井有波兮通滄溟，玉抱德兮誰能銘。", "憺來歸兮析然醒，道有成兮其當升。"]'),
('9bafe6f3-fe50-4b8f-9810-0671b78ddc25','由校中秘書授徽倅道出金陵投留守吳公琚','高似孫','宋','宋诗','song-poetry','','[]','四朝渥遇鬢微絲，多少恩榮世少知。',64,'全唐诗/poet.song.173000.json','["四朝渥遇鬢微絲，多少恩榮世少知。", "長樂花深春侍宴，重華香暖夕論詩。", "黄金籯滿無心愛，古錦囊歸有字奇。", "一笑難陪珠履客，看臨古帖對梅枝。"]'),
('c55d7307-ed9f-41be-9899-f48900254605','楊嗣勳惠茯苓','高似孫','宋','宋诗','song-poetry','','[]','道是青神谷，元通白帝崖。',72,'全唐诗/poet.song.173000.json','["道是青神谷，元通白帝崖。", "有松如壯士，其魄化嬰兒。", "雲溼侵鴉嘴，天寒翦兔絲。", "堯初香摘髓，秦後雪凝脂。", "穴動龍蛇窘，山空鳥獸悲。", "惟將千歲力，白了一生奇。"]'),
('364bfdb8-92a7-488d-aa24-009cb6387992','都下','高似孫','宋','宋诗','song-poetry','','[]','柳生春思拂京華，不管閒人也憶家。',32,'全唐诗/poet.song.173000.json','["柳生春思拂京華，不管閒人也憶家。", "添盡好香那睡得，月良如水浸梨花。"]'),
('4eda6c0f-a703-4dd7-9dc7-cd5aaca67ee5','中秋夜登秀臺二絕  其一','高似孫','宋','宋诗','song-poetry','','[]','青冥風露無人管，醉力飛昇入桂臺。',32,'全唐诗/poet.song.173000.json','["青冥風露無人管，醉力飛昇入桂臺。", "月過斗西親挽住，伴人騎鶴去蓬萊。"]'),
('bfd988c6-f255-4d95-9af8-a8bcd05b3b9e','中秋夜登秀臺二絕  其二','高似孫','宋','宋诗','song-poetry','','[]','冰娥看盡人間世，好事如公不數枚。',32,'全唐诗/poet.song.173000.json','["冰娥看盡人間世，好事如公不數枚。", "却喚清罍相揖酌，汝聽下界息成雷。"]'),
('1ea5e5fa-093b-4ede-98e6-a690af6068a6','梨花','高似孫','宋','宋诗','song-poetry','','[]','殿頭催引上清華，獨奏春詞喝賜茶。',32,'全唐诗/poet.song.173000.json','["殿頭催引上清華，獨奏春詞喝賜茶。", "带月歸來仙骨冷，夢魂全不到梨花。"]'),
('2fa6091c-0414-4ccc-9332-0a85ad28bbd3','晚泊江口','高似孫','宋','宋诗','song-poetry','','[]','白鷺青煙剡江口，梅六七分經雪後。',32,'全唐诗/poet.song.173000.json','["白鷺青煙剡江口，梅六七分經雪後。", "月肯流連相伴酒，隔岸呼船有魚否。"]'),
('ac604fa4-e666-4f73-aedd-7ebe8c13e6dd','答辛幼安','高似孫','宋','宋诗','song-poetry','','[]','青天不惜日，壯士偏知秋。',96,'全唐诗/poet.song.173000.json','["青天不惜日，壯士偏知秋。", "自古有奇畫，如今空白頭。", "彼時當再來，吾老不可留。", "天推璧月上，星入銀河流。", "躔度若此急，人生與之浮。", "終夜自起舞，無人共登樓。", "典謨有陳言，河洛非故州。", "黄鶴呼不來，誰能理殘裘。"]'),
('4879c6d9-d618-4fdd-810f-051c9b357241','寄桐柏山王尊師','高似孫','宋','宋诗','song-poetry','','[]','猶道中峰淺，重新入翠微。',48,'全唐诗/poet.song.173000.json','["猶道中峰淺，重新入翠微。", "讀書呼鶴聽，洗硯待猨歸。", "近瀑青松溼，朝陽紫朮肥。", "逢仙歸又晚，行得健如飛。"]'),
('5869bba6-ada1-471c-adf8-4d9d58437bf0','桑世昌澤卿歸天台','高似孫','宋','宋诗','song-poetry','','[]','且入西陵抖素衣，寒燈猶有雁相依。',64,'全唐诗/poet.song.173000.json','["且入西陵抖素衣，寒燈猶有雁相依。", "月僵積雪和梅凍，天拆殘星背斗飛。", "書策不堪供世用，江山何肯笑人歸。", "赤城仙伯皆吾輩，爲带詩行問子微。"]'),
('bf5a87fd-4596-4c24-a1c0-b72fe015c54f','夜宿金庭洞','高似孫','宋','宋诗','song-poetry','','[]','夙聞桐柏山，下入金庭洞。',192,'全唐诗/poet.song.173000.json','["夙聞桐柏山，下入金庭洞。", "五雲所出沒，千翠相迎送。", "川明芝自燁，夏冷雪猶凍。", "沙泉注陽穴，水碧孕陰峒。", "天光抱瓊室，神力扶蘭棟。", "其左鬭蒼虯，其西翔紫鳳。", "中穿穴窈複，傍見石闕空。", "青煙溜松髓，白水鳴醴甕。", "怪草不知名，珍禽時曳弄。", "石蜜吐巖房，琪芳突苔縫。", "星君時一遊，仙翁亦參從。", "或乘玄鶴來，或並青鸞控。", "香趨玉女跪，丹走山靈慟。", "谷神元不死，玄根在深種。", "誰其握性命，於此破昏夢。", "世人少知幾，何能測天用。"]'),
('8b711825-5274-4ab3-8ba9-9d0fbd33955a','次韵沈台州遊桐柏山','高似孫','宋','宋诗','song-poetry','','[]','中天積翠玉臺遥，崑閬吹風下赤霄。',64,'全唐诗/poet.song.173000.json','["中天積翠玉臺遥，崑閬吹風下赤霄。", "鶴護青松生老珀，龍歸丹井應寒潮。", "三台自逐璣衡轉，玉帝常同海嶽朝。", "休道人間仙骨少，功成也會作松喬。"]'),
('ff70626f-49a8-4b81-8e8b-482214bdfe59','桐柏山瓊臺','高似孫','宋','宋诗','song-poetry','','[]','翠嶽竦神秀，玉衡直三台。',96,'全唐诗/poet.song.173000.json','["翠嶽竦神秀，玉衡直三台。", "上有長生君，含光赤城臺。", "陽崖燁金芝，陰壑生碧苔。", "獨立雲在下，一嘯仙俱來。", "丹郎醉不醒，玉女聲如孩。", "帝鄉風自寒，洞口花長開。", "所嗟塵埃中，那有神仙才。", "秦皇漫東海，漢武空蓬萊。"]'),
('3afaa661-78ac-491b-bcd1-999374b118d3','夜宿桐柏','高似孫','宋','宋诗','song-poetry','','[]','月到中峰碧峭深，露桃微重鶴移陰。',32,'全唐诗/poet.song.173000.json','["月到中峰碧峭深，露桃微重鶴移陰。", "隔松聽得仙官話，句句皆非世上音。"]'),
('bee2636b-60e7-4c27-b068-074dff513022','瓊臺西路','高似孫','宋','宋诗','song-poetry','','[]','一夜天台雨，青鞋蹋盡沙。',48,'全唐诗/poet.song.173000.json','["一夜天台雨，青鞋蹋盡沙。", "添將清瀑水，溼盡碧桃花。", "涉澗鉏生朮，和雲嚼野茶。", "便無仙骨分，不敢更思家。"]'),
('f5c3f982-eec2-4ffd-9bd3-627be51e8911','桐柏觀閲藏經','高似孫','宋','宋诗','song-poetry','','[]','天人皆奇人，一以文爲主。',192,'全唐诗/poet.song.173000.json','["天人皆奇人，一以文爲主。", "至今崑崙山，猶有羣玉府。", "虛無天之根，清浄道所祖。", "也知自羲翁，此妙洩盤古。", "老氏啟藏室，八神負猛虡。", "玉垂太上篇，金寫神仙語。", "舜璿奔一機，漢宮鑿萬戶。", "璆諧玉女下，雷吼蒼龍舞。", "侍晨校琅簡，玉卿譔瑶譜。", "兩垣協躔度，四溟節風雨。", "恭惟上帝騭，哀此下民苦。", "昭昭懸朗監，歷歷開蒙瞽。", "粵從擘混沌，孰不趨子午。", "六爻本乎健，五行依乎土。", "神機迭經緯，和應相律呂。", "子能發此鑰，太微開帝宇。"]'),
('2ac76d03-8d4e-41f1-b7c8-87369240d4ec','清曉昇瓊臺頂石崖有仙人脚跡','高似孫','宋','宋诗','song-poetry','','[]','亂石排天倚嵐壁，苔痕不犯松喬跡。',96,'全唐诗/poet.song.173000.json','["亂石排天倚嵐壁，苔痕不犯松喬跡。", "上通羣帝集台斗，下鑿十洲通碣石。", "樹呼清風雜今古，山遺宿潤從開闢。", "丹翁曾同玉女醉，樵者亦見仙人弈。", "雲飛磴道晴掩冉，露溼衣裳香滴瀝。", "洞中靈君來不來，鶴歸衝落桃花碧。"]'),
('b0370c39-cc2e-4d4a-a43a-76a97c55850b','桐柏山黄法師齋','高似孫','宋','宋诗','song-poetry','','[]','羽人歸丹丘，輕房冒蒼頂。',96,'全唐诗/poet.song.173000.json','["羽人歸丹丘，輕房冒蒼頂。", "雲飛北斗壇，瀑洗洪崖井。", "三更火交坎，八十雪垂領。", "深香熨玉釜，淑氣回丹鼎。", "彼空此亦無，物動我自靜。", "灼知喬松輩，元涉羲老境。", "一來受清滌，內悟開微儆。", "請添無爲香，上有蕭臺景。"]'),
('33c6b9b9-8078-4734-ae20-64dd057db60c','桐柏山鄭先生齋','高似孫','宋','宋诗','song-poetry','','[]','鑿石引幽路，傍崖開碧庭。',48,'全唐诗/poet.song.173000.json','["鑿石引幽路，傍崖開碧庭。", "棋留樵客坐，鵝博老君經。", "竹榻朝吞日，松壇夜拜星。", "山中有公事，鶴觸杏花零。"]'),
('5ea2d4c8-c04f-4d5c-b953-bc30c0360801','萬年山','高似孫','宋','宋诗','song-poetry','','[]','依松屈曲疑無路，十里廿里香深沍。',192,'全唐诗/poet.song.173000.json','["依松屈曲疑無路，十里廿里香深沍。", "殿臺平入蓬萊圖，人煙盡屬天台賦。", "山奔萬馬逼人立，泉吼晴雷半天注。", "亂峰發地翠參錯，沓嶂參差龍屈怒。", "陰磴仍遺前臘雪，陽崖競拔千年樹。", "亦容羽客賣丹來，更有神僧飛錫渡。", "佛界焚香玉女跪，海舟獻寶胡兒踞。", "未午催敲集梵鐘，隨雲共展升堂具。", "冥搜窮日不知極，妙盡所歷何容遽。", "平生略持山水眼，是處且了林泉素。", "揮支公錢極易事，分龐翁榻良難遇。", "青山不是世閒無，山若識人人也住。"]'),
('b7b84eb2-4b6b-45dd-87be-6de253ae935d','石橋歌','高似孫','宋','宋诗','song-poetry','','[]','一石上負崑崙柱，一水西奔牛女渚。',64,'全唐诗/poet.song.173000.json','["一石上負崑崙柱，一水西奔牛女渚。", "玉斡獰鱗萬松古，夜夜神光干帝宇。", "石滑苔危冰一縷，四海長依開闢雨。", "月落未落逢諾矩，兩足敲泉龍罷舞。"]'),
('caa95eea-d3a3-4287-9b40-5b113c13bef8','國清寺泉時有綠蟾蹲崖石西','高似孫','宋','宋诗','song-poetry','','[]','崖腰溜清水，素光摇玉宇。',144,'全唐诗/poet.song.173000.json','["崖腰溜清水，素光摇玉宇。", "其陰透碧海，有石如砥柱。", "心知老龍都，直入蓬萊府。", "仙雲蕩涼潤，積雪明深暑。", "陰陽若在茲，噓吸多成雨。", "孤花棲暗芳，瘦木垂梢古。", "娟娟綠蟾蜍，曾識廣寒女。", "深疑珠宮物，內敬不敢侮。", "山僧惜一茶，自碾仍自煮。", "相從有覺意，兩悟無凡語。", "欲分鮮花屏，稍築松風廡。", "銅缾取明月，洗此文字苦。"]'),
('5a06f96b-085f-4206-9642-9acc641ff4fc','栖霞宮山齋','高似孫','宋','宋诗','song-poetry','','[]','山栖極造理，其北恰嵐壁。',120,'全唐诗/poet.song.173000.json','["山栖極造理，其北恰嵐壁。", "下吞泉數斗，中有蒲數脊。", "崖留未化雪，竹迸將崩石。", "不爲世所薰，直入玄之寂。", "道人無一吝，近我如相識。", "忽然問周易，再三說太極。", "言清嚼冰雪，事奧通金碧。", "吐納少滯咽，導引多精色。", "陰火養陽鼎，黄雲生寶鬲。", "定是西母池，佳桃已中食。"]'),
('4418390a-9631-40b7-b271-5d45182c3e32','參政錢公山園','高似孫','宋','宋诗','song-poetry','','[]','朝廷文物自昇平，公主園林尚典刑。',64,'全唐诗/poet.song.173000.json','["朝廷文物自昇平，公主園林尚典刑。", "山好儘强金谷澗，客來且上翠微亭。", "鶴鳴欲說前時事，花在非如舊日馨。", "多少唐人詩意思，無人知得更冥冥。"]'),
('1d2cdec9-229d-476f-ba6c-2d6f57e18a56','浮岡','高似孫','宋','宋诗','song-poetry','','[]','山含宿凍未曾銷，鳥去仍迴水路遥。',32,'全唐诗/poet.song.173000.json','["山含宿凍未曾銷，鳥去仍迴水路遥。", "千樹梅花三尺雪，一帆風力半江潮。"]'),
('a2b363ee-ce28-4bed-aed1-4e8a4fb682d3','天台渡','高似孫','宋','宋诗','song-poetry','','[]','一江夾清渾，只向青村注。',96,'全唐诗/poet.song.173000.json','["一江夾清渾，只向青村注。", "餘雲拖薄潤，遠靄飛輕素。", "船輕順流下，石狹奔湍怒。", "蒼陰布仙跡，野芳生幽趣。", "山色各有舊，春情宛如訴。", "徘徊良自得，泱漭又將暮。", "遐瞻金碧庭，可入丹泉路。", "今夜宿桃花，切莫匆匆去。"]'),
('bcddf004-b3d0-4c48-b1c7-3de575a91419','天台道中','高似孫','宋','宋诗','song-poetry','','[]','落花入谿口，山山皆可佳。',96,'全唐诗/poet.song.173000.json','["落花入谿口，山山皆可佳。", "橫矼碧水急，後峰白雲霾。", "野藥綴殷子，危松換新釵。", "魚輕爭湊石，蘭瘦深依涯。", "此處若有仙，欲留殊未階。", "一來愛清氣，全是牽幽懷。", "空色下映水，風聲高在崖。", "草草亦難通，借泉洗青鞋。"]'),
('158817a2-bac2-417d-9dae-a33f8a5e7235','再至桐柏山','高似孫','宋','宋诗','song-poetry','','[]','此山即蓬萊，其下通弱水。',96,'全唐诗/poet.song.173000.json','["此山即蓬萊，其下通弱水。", "萬里奏上帝，一嶽留仙史。", "逍遥丹霞上，出沒流精裏。", "夜子鶴又叫，月暈風欲起。", "自從西磵去，復見東峰峙。", "松施神農蘿，石護堯時髓。", "無中猶有象，玄外更無旨。", "略聞赤松道，浩劫不可紀。"]'),
('710ad6c2-8243-4ddd-a12b-4849d5d72399','桐柏臺夜作','高似孫','宋','宋诗','song-poetry','','[]','東崖紫雲飛，西壁白雪炯。',72,'全唐诗/poet.song.173000.json','["東崖紫雲飛，西壁白雪炯。", "洞口一何邃，人閒無此靜。", "松風翻瀑怒，梅月逼鶴警。", "苔汙斷闕石，茶注彭亨鼎。", "丈人極好生，生神最澄景。", "且修黄房訣，夜向香心永。"]'),
('bd702bbe-e76a-4982-b990-f31bf6951ada','鹿郎中山居','高似孫','宋','宋诗','song-poetry','','[]','非是拜龐公，何繇識此峰。',96,'全唐诗/poet.song.173000.json','["非是拜龐公，何繇識此峰。", "自唐無兩見，如漢有高蹤。", "徑吐歸來菊，山連種老松。", "輕飛雲似健，精鍊玉爲容。", "鶴要親題竹，猨常認擊筇。", "花深多不見，葉響却相逢。", "天最知陶亮，人難揖戴顒。", "一來非小事，吝到此皆溶。"]'),
('b587428b-4751-404d-8013-edf5f9a237b6','巾山雪','高似孫','宋','宋诗','song-poetry','','[]','携詩來做台州雪，台州雪好無人說。',128,'全唐诗/poet.song.173000.json','["携詩來做台州雪，台州雪好無人說。", "一峰玉削崑崙柱，一天冰夾蓬萊闕。", "大江不動網罟凍，衆壑皆聲松竹折。", "村無人行太清浄，樹無鳥棲俱峭絕。", "丹天仙君謁帝回，赤脚泠泠踏寒月。", "不管飛殘水帝魂，從頭盡笑春風拙。", "綠華之女素霓衣，從以廣寒太陰妃。", "法曲導引青鸞飛，仙人仙人胡不歸。"]'),
('24b5efe0-c96f-4d41-863c-85a06c9d3cff','王清叔舍人玉寒堂','高似孫','宋','宋诗','song-poetry','','[]','只爲襟懷別，全然少俗埃。',48,'全唐诗/poet.song.173000.json','["只爲襟懷別，全然少俗埃。", "山林非細事，天地有奇才。", "泉石皆經畫，松梅不妄栽。", "何銷嵩洛去，嵩洛在天台。"]'),
('b6951b1e-177d-439f-a863-2a2d43f473b7','寄天台蕭練師','高似孫','宋','宋诗','song-poetry','','[]','已是成仙了，全然得道長。',48,'全唐诗/poet.song.173000.json','["已是成仙了，全然得道長。", "石堅松結髓，山煖朮生香。", "近瀑衣裳冷，和雲筆硯涼。", "傍崖修碧宇，何日奏寥陽。"]'),
('6be7f0dd-9478-43af-8ad2-6d2a028ab468','石橋紋蕈','高似孫','宋','宋诗','song-poetry','','[]','絕冥萬丈深，積翠淩空危。',96,'全唐诗/poet.song.173000.json','["絕冥萬丈深，積翠淩空危。", "清澗月自浴，孤芳人不知。", "石骨溜香髓，松苓湧涼脂。", "忽然青雲陰，見此白玉姿。", "冉冉露痕重，漼漼雪花滋。", "淑氣注陽鼎，甘津灌華池。", "開經拜修靜，得道推安期。", "聊欲燕其陽，飽食五色芝。"]'),
('6f37e678-5d3f-4780-9d23-d13116e378d2','簡石橋僧璧暉','高似孫','宋','宋诗','song-poetry','','[]','只在閒雲裏，房虛溼翠屏。',48,'全唐诗/poet.song.173000.json','["只在閒雲裏，房虛溼翠屏。", "童歸收晚果，客至歇殘經。", "月落千峰黑，龍歸白水腥。", "關門無一事，草木共冥冥。"]'),
('4c14d1e7-0181-41e1-8ea0-edac915bda85','桐柏鄭練師歸故山','高似孫','宋','宋诗','song-poetry','','[]','元與玄俱妙，全無事可輕。',48,'全唐诗/poet.song.173000.json','["元與玄俱妙，全無事可輕。", "路依蒼石轉，房與碧雲平。", "鶴露收殘夢，桃風析晚酲。", "西窗留與我，却去事彌明。"]'),
('9e9f0e51-d2a1-461a-9e54-60ed2f834e72','分繡閣夜作二首  其一','高似孫','宋','宋诗','song-poetry','','[]','一燈炯微明，敲盡寒更永。',96,'全唐诗/poet.song.173000.json','["一燈炯微明，敲盡寒更永。", "老蛩泣月罅，脆葉鳴霜井。", "此事誰主宰，凡物皆動靜。", "不了達者觀，却似醉難醒。", "久無謝安石，況復陶弘景。", "殘書非一慨，孤鐘但深省。", "梅生雪後花，雁叫雲西影。", "他心不可度，此語堪自警。"]'),
('b3e0b3d0-306c-4910-b2ed-402aeaa3e895','分繡閣夜作二首  其二','高似孫','宋','宋诗','song-poetry','','[]','識字始多憂，悟理良自苦。',96,'全唐诗/poet.song.173000.json','["識字始多憂，悟理良自苦。", "少小習句讀，豈解工訓詁。", "一從入老大，甚覺悔雕組。", "人生各用命，何乃太知古。", "典謨必皋契，詩句須李杜。", "生居諸公後，已覺萬事忤。", "勤婦少完襖，惰農甘莽鹵。", "八卦不可推，天意眇如許。"]'),
('83c53859-7d30-47a0-a289-0bfc512900bf','別天台','高似孫','宋','宋诗','song-poetry','','[]','早乘霞氣入蓬萊，不識神仙也不來。',64,'全唐诗/poet.song.173000.json','["早乘霞氣入蓬萊，不識神仙也不來。", "曾與赤松游數日，自携玉女上西臺。", "當時共說黄房事，回首空驚碧海埃。", "前度劉郎今得度，桃花一一爲郎開。"]'),
('c150c8e5-dc16-4bb4-941d-5ecf6d7bf543','和居簡師韵  其一','高似孫','宋','宋诗','song-poetry','','[]','恨不相從早，分渠月半寮。',48,'全唐诗/poet.song.173000.json','["恨不相從早，分渠月半寮。", "墨飛春澗石，茶衮夕鐺潮。", "詩到如今瘦，情從此處消。", "爲君料理極，參透碧寥寥。"]'),
('9e76a660-38fc-446d-a189-8efe92adca8e','和居簡師韵  其二','高似孫','宋','宋诗','song-poetry','','[]','憶昔相尋處，時今可更麽。',48,'全唐诗/poet.song.173000.json','["憶昔相尋處，時今可更麽。", "春愁侵磊隗，晚步隔坡陀。", "風入唐聲妥，山函蜀氣多。", "一春聽盡雨，此意與誰歌。"]'),
('1c460fef-6d57-45f5-8e8f-5f3a6c74fa91','水西','高似孫','宋','宋诗','song-poetry','','[]','抱崖一水限僧居，空翠溟濛畫不如。',32,'全唐诗/poet.song.173000.json','["抱崖一水限僧居，空翠溟濛畫不如。", "落日遊人山窈窕，清風啼鳥竹蕭疎。"]'),
('a0235630-ba17-4375-975c-7fa051e69454','次韵陳校書送鶴竹筍詩','高似孫','宋','宋诗','song-poetry','','[]','竹如鶴脚瘦交加，驚識英英玉露沙。',32,'全唐诗/poet.song.173000.json','["竹如鶴脚瘦交加，驚識英英玉露沙。", "一見已知仙骨健，高於越箭更無差。"]'),
('1862492e-d507-4c8f-8880-679b38f783c4','遊九鎖  其一','高似孫','宋','宋诗','song-poetry','','[]','洞門金畫翠琅玕，杏不多花月溜寒。',32,'全唐诗/poet.song.173000.json','["洞門金畫翠琅玕，杏不多花月溜寒。", "借得御書經自讀，松風浄洗石棋盤。"]'),
('781d531f-d8b5-4a51-aedb-b9313ca814eb','遊九鎖  其二','高似孫','宋','宋诗','song-poetry','','[]','雲氣常常在上峰，松生仙骨盡成龍。',32,'全唐诗/poet.song.173000.json','["雲氣常常在上峰，松生仙骨盡成龍。", "不通名姓誰談道，却得雲邊兩度逢。"]'),
('06caa4bd-fbde-40e7-97b5-188dedda16cd','揚州官滿辭后土題玉立亭','高似孫','宋','宋诗','song-poetry','','[]','且更淮南了歲華，天香深窈竹西家。',32,'全唐诗/poet.song.173000.json','["且更淮南了歲華，天香深窈竹西家。", "忽然踏碎瓊樓月，相伴夫人暮倚花。"]'),
('9f3a11d3-680b-4e8e-b047-2a3bfa0ba0f0','天台渡','高似孫','宋','宋诗','song-poetry','','[]','歇程偏惜來時路，白鳥相隨呼野渡。',32,'全唐诗/poet.song.173000.json','["歇程偏惜來時路，白鳥相隨呼野渡。", "一樹桃花碧雲暮，過了溪西却飛去。"]'),
('42efbcac-b61c-4731-9399-15320f0d26af','濟錢清江','高似孫','宋','宋诗','song-poetry','','[]','潮分殘力引船飛，一道浮暉入杳微。',64,'全唐诗/poet.song.173000.json','["潮分殘力引船飛，一道浮暉入杳微。", "可惜梅皆容易落，相將雁又接連歸。", "依前清洛情猶在，覺道離騷事已非。", "倚枕但看王導傳，困來不復解春衣。"]'),
('41de956a-7768-4881-bf70-23e6866c7d27','紅梅花','高似孫','宋','宋诗','song-poetry','','[]','带雪匆匆別楚雲，天寒依約見湘君。',32,'全唐诗/poet.song.173000.json','["带雪匆匆別楚雲，天寒依約見湘君。", "只疑不合瑶池去，引得春風八九分。"]'),
('b2c3334f-be8d-40ce-a1f5-3e01d3217487','小閣','高似孫','宋','宋诗','song-poetry','','[]','料理閑如舊，依還略似家。',48,'全唐诗/poet.song.173000.json','["料理閑如舊，依還略似家。", "自添磨硯水，多買入瓶花。", "有客談游墅，催奴設賜茶。", "悠悠江海意，風雪滿兼葭。"]'),
('6edf0d90-2586-4260-8153-e56c4ca9764f','任賢良歸蜀','高似孫','宋','宋诗','song-poetry','','[]','衮衮江來急建瓴，一西還有幾長亭。',64,'全唐诗/poet.song.173000.json','["衮衮江來急建瓴，一西還有幾長亭。", "峨眉雪罷添巴水，玉壘雲空見蜀星。", "白浪不侵魚復陣，青苔猶護劍關銘。", "堂堂功業今皆在，天意何時更一醒。"]'),
('c2cd6965-79e3-4de5-8eff-999f9fa85eab','蔡山渡','高似孫','宋','宋诗','song-poetry','','[]','江上人家破竹門，潮來水長浸籬根。',32,'全唐诗/poet.song.173000.json','["江上人家破竹門，潮來水長浸籬根。", "鮆魚一尺枇杷小，放溜船來酒滿尊。"]'),
('0172e278-e3b3-4171-89c8-75b7b5969bad','別雲門','高似孫','宋','宋诗','song-poetry','','[]','回首雲邊更看松，風流王謝舊行蹤。',32,'全唐诗/poet.song.173000.json','["回首雲邊更看松，風流王謝舊行蹤。", "不知誰繼諸賢後，夜半來聽六寺鐘。"]'),
('24b7026a-6020-4e61-aebe-0e2f3b5e52e8','句  其一','高似孫','宋','宋诗','song-poetry','','[]','硯濕舂鋤雨，罏腥郭索泥。',12,'全唐诗/poet.song.173000.json','["硯濕舂鋤雨，罏腥郭索泥。"]'),
