('0bbb9faf-c679-4888-ac5a-a4263dcff6c3','題南山','石應孫','宋','宋诗','song-poetry','','[]','孤鶩去邊天浩渺，萬家窮處水灣環。',32,'全唐诗/poet.song.173000.json','["孤鶩去邊天浩渺，萬家窮處水灣環。", "嶺外此州爲道院，風烟殊弗類南蠻。"]'),
('75484de3-8c60-408b-bbe4-546e543690e8','遊黄山','石應孫','宋','宋诗','song-poetry','','[]','山川形勝雄江東，九華輝映天都峰。',192,'全唐诗/poet.song.173000.json','["山川形勝雄江東，九華輝映天都峰。", "傳聞早已盪胸臆，恨不插翼長相從。", "朅來隨牒官秋浦，城郭奔馳厭塵土。", "絜家捧檄過臨城，偷閒兩作煙霞主。", "黄山登覽原無由，何期易地太平遊。", "清池軒豁日舒麗，突兀樓觀撐深幽。", "憑高徙倚敞心目，絕壁半天橫碧玉。", "迴溪千里指顧間，螺髻分明三十六。", "壯懷高向紫霄懸，俯視培塿真一拳。", "古今秀色餐不盡，筆端收拾生雲煙。", "萍蹤倘未逐流水，古剎相望二三里。", "暇時風月得交游，鷗鷺同眠勿驚起。"]'),
('9e7b08d2-a58d-419c-9876-f7d026659d93','石花洞','石應孫','宋','宋诗','song-poetry','','[]','我試問陽和，洞間誰是主。',24,'全唐诗/poet.song.173000.json','["我試問陽和，洞間誰是主。", "盡日立東風，百花無一語。"]'),
('fa0ccdeb-d514-4003-b516-b51469b3b7d3','桃花洞','石應孫','宋','宋诗','song-poetry','','[]','桃花五色四時開，片片香隨磵水來。',32,'全唐诗/poet.song.173000.json','["桃花五色四時開，片片香隨磵水來。", "况是軒轅曾手植，紫烟深處有樓臺。"]'),
('5270f89c-f256-45a7-a2fd-a6a6d72fef46','水簾洞','石應孫','宋','宋诗','song-poetry','','[]','珠簾巧費水晶裁，萬古垂垂淺碧苔。',32,'全唐诗/poet.song.173000.json','["珠簾巧費水晶裁，萬古垂垂淺碧苔。", "幾度月鈎鈎不上，孤雲能入此中來。"]'),
('7e8bf28c-b487-4b02-ab49-28ffa1bb7469','九折巖  其一','張聲道','宋','宋诗','song-poetry','','[]','池繞九巖邊，鴛鴦自在眠。',48,'全唐诗/poet.song.173000.json','["池繞九巖邊，鴛鴦自在眠。", "圓荷浮簇簇，翠葆靜涓涓。", "霑足三春雨，清和四月天。", "庭空無一事，真樂付詩篇。"]'),
('6037e363-701d-4faa-94ee-336361be1c33','九折巖  其二','張聲道','宋','宋诗','song-poetry','','[]','酒送鍾聲隨晚照，雨添竹色薦新凉。',32,'全唐诗/poet.song.173000.json','["酒送鍾聲隨晚照，雨添竹色薦新凉。", "欄干燭影水波靜，簾捲杯深荷度香。"]'),
('9e89a907-c774-4544-97ac-f9a35fd689d6','遊石橋至塔頭路','徐大受','宋','宋诗','song-poetry','','[]','招手晴雲豁，妙高峰頂頭。',48,'全唐诗/poet.song.173000.json','["招手晴雲豁，妙高峰頂頭。", "竹輿摇午夢，茗椀喚春愁。", "俎豆羅千嶂，虛空起一漚。", "危欄閑徙倚，萬象入冥搜。"]'),
('9ad7d56a-d83a-40ae-8d5c-e8a62d2887fb','入石橋路林木蓊鬰但聞澗聲潺潺忽驚湍飛雹駭綠紛紅雜然而下口占二絕句  其一','徐大受','宋','宋诗','song-poetry','','[]','畧彴微分碧玉灣，杖藜穿破鬰藍天。',32,'全唐诗/poet.song.173000.json','["畧彴微分碧玉灣，杖藜穿破鬰藍天。", "山深草木春無路，時有藤花一樹妍。"]'),
('518e0d66-2f45-4620-8e75-8449c31e6201','入石橋路林木蓊鬰但聞澗聲潺潺忽驚湍飛雹駭綠紛紅雜然而下口占二絕句  其二','徐大受','宋','宋诗','song-poetry','','[]','琮琤林澗只聽聞，想見縈崖絡石紋。',32,'全唐诗/poet.song.173000.json','["琮琤林澗只聽聞，想見縈崖絡石紋。", "忽作驚湍濺飛雹，半隨花雨落紛紛。"]'),
('af276098-4aa3-4b99-992d-6440e64c1690','方外詩友機空二禪婁詫蓮峰五月梅雨深林叢薄中娑羅花特異每以未見爲恨夏初過此而橋東是花豫開豈應真大士出此以相勞耶','徐大受','宋','宋诗','song-poetry','','[]','九葩一萼鶴翎紅，開落梅黄烟雨中。',32,'全唐诗/poet.song.173000.json','["九葩一萼鶴翎紅，開落梅黄烟雨中。", "千葉青蓮無路到，不知春在石橋東。"]'),
('c9266a15-d5bb-4804-96bc-592acc8146e1','入萬年謁簡庵清老追和曾使君詩板韵','徐大受','宋','宋诗','song-poetry','','[]','踏破深崖蒼石稜，八峰來謁簡庵清。',64,'全唐诗/poet.song.173000.json','["踏破深崖蒼石稜，八峰來謁簡庵清。", "山花照座一兩點，雪狖叫雲三四聲。", "詩带烟霞藏舊刻，門開樓閣見經行。", "平田淺草歸時路，風月依然度百城。"]'),
('5095ca64-64f1-4ab1-b169-00a037ab231e','歸路過福聖觀瀑布輝老踞坐盤石二絕題飛雨亭  其一','徐大受','宋','宋诗','song-poetry','','[]','電激河翻白雨飛，青烟紫霧落斜暉。',32,'全唐诗/poet.song.173000.json','["電激河翻白雨飛，青烟紫霧落斜暉。", "山中道士秘泉石，只到此亭牽客衣。"]'),
('27a1f2fa-786d-45b2-9d7a-9242b958a48b','歸路過福聖觀瀑布輝老踞坐盤石二絕題飛雨亭  其二','徐大受','宋','宋诗','song-poetry','','[]','一水高懸千尺梭，空林終日影婆娑。',32,'全唐诗/poet.song.173000.json','["一水高懸千尺梭，空林終日影婆娑。", "仰天雄踞盤陀石，尊者真身諾巨那。"]'),
('61b74371-f502-4978-a589-c32037073163','送輝老自赤城住聖水','徐大受','宋','宋诗','song-poetry','','[]','道人去住本無心，雲出空山鶴在陰。',64,'全唐诗/poet.song.173000.json','["道人去住本無心，雲出空山鶴在陰。", "試問白蓮同浄社，何如赤壁卧青林。", "叫羣孤雁水天闊，啼雪冷猿巖洞深。", "要勘山門騎佛殿，春風杖錫儻來臨。"]'),
('85a8101c-18a8-4369-9862-0388e1e23eac','題林詠道浮江別業','徐大受','宋','宋诗','song-poetry','','[]','密林凝晝寂，一葉動須驚。',48,'全唐诗/poet.song.173000.json','["密林凝晝寂，一葉動須驚。", "砌浄飛花影，池深落果聲。", "正宜鋪枕簟，且復倒瓶罌。", "向晚催歸急，烟江野艇橫。"]'),
('745ce228-fb59-4010-83b4-c3775c703ca0','巖桂花','徐大受','宋','宋诗','song-poetry','','[]','重重簾幕護金猊，小樹花開逼麝臍。',64,'全唐诗/poet.song.173000.json','["重重簾幕護金猊，小樹花開逼麝臍。", "寒色十分新疹粟，春心一點暗通犀。", "香延棋畔仙人斧，影射燈前太乙藜。", "從此再週花甲子，伴公長醉玉東西。"]'),
('66c26bcd-aff2-45ab-a7cf-25d7e83f6b13','使金','傅諴','宋','宋诗','song-poetry','','[]','霜明玉節映寒流，馬渡蘆溝向上頭。',64,'全唐诗/poet.song.173000.json','["霜明玉節映寒流，馬渡蘆溝向上頭。", "萬里河山觀古塞，百年荆棘嘆神州。", "要臨瀚海銘燕石，莫上新亭作楚囚。", "多少遺民思舊俗，可憐金帛歲包羞。"]'),
('0f47f58c-446c-4e98-b57e-90c8e05e1e3d','東京道上口占','傅諴','宋','宋诗','song-poetry','','[]','宮闕岧嶢俯碧空，九門未曉月朦朧。',32,'全唐诗/poet.song.173000.json','["宮闕岧嶢俯碧空，九門未曉月朦朧。", "馬嘶南陌東風遠，回首神京一夢中。"]'),
('af634e26-c0bd-4178-99a7-1be026185084','澹巖紀游  其一','洪彥華','宋','宋诗','song-poetry','','[]','聞說澹巖天下稀，乘閑得得叩巖扉。',32,'全唐诗/poet.song.173000.json','["聞說澹巖天下稀，乘閑得得叩巖扉。", "中虛上透真奇觀，□□□□□悟機。"]'),
('dc0b99cd-fe04-46a3-a333-41c8213391bf','澹巖紀游  其二','洪彥華','宋','宋诗','song-poetry','','[]','朝陽巖自次山顯，鈷鉧潭由子厚彰。',32,'全唐诗/poet.song.173000.json','["朝陽巖自次山顯，鈷鉧潭由子厚彰。", "山水得人名始重，不元不柳□逢黄。"]'),
('d2aefb17-dd94-4ad1-87bd-e80982a4824e','澹巖紀游  其三','洪彥華','宋','宋诗','song-poetry','','[]','辟秦人去幾千年，介石于今尚塊然。',32,'全唐诗/poet.song.173000.json','["辟秦人去幾千年，介石于今尚塊然。", "指□載魚行播□，爭如流水亦稱賢。"]'),
('2b51a024-35ec-41f7-96a3-7d6bf68b5f24','澹巖紀游  其四','洪彥華','宋','宋诗','song-poetry','','[]','暗巖別是洞中天，石臼石棋仍石田。',32,'全唐诗/poet.song.173000.json','["暗巖別是洞中天，石臼石棋仍石田。", "因□巖扃知命戒，貪□□□復言旋。"]'),
('afd5ee19-f928-4f35-af87-425bdb9462e6','澹巖紀游  其五','洪彥華','宋','宋诗','song-poetry','','[]','老僧持鉢傍山門，古寺蕭然一味清。',32,'全唐诗/poet.song.173000.json','["老僧持鉢傍山門，古寺蕭然一味清。", "骨相山林非富貴，不應曾有訓狐鳴。"]'),
('e50dbf22-1fbb-46d0-81b3-addb9ea6995c','涵碧亭','葛洪','宋','宋诗','song-poetry','','[]','雨歇留蒸濕，明來得翳凉。',48,'全唐诗/poet.song.173000.json','["雨歇留蒸濕，明來得翳凉。", "雙嬉魚欲動，萬箇竹添長。", "景到煩詩答，歡多厄日忙。", "茲遊端勝絕，不是學高陽。"]'),
('f8baec01-4718-434f-af05-8b6624b43d59','中興寺瓊翠閣次喬夢符韵','葛洪','宋','宋诗','song-poetry','','[]','蘭若憑高處，風虛閣自涼。',48,'全唐诗/poet.song.173000.json','["蘭若憑高處，風虛閣自涼。", "川林輸望迥，日月對閑長。", "洒落幽人暇，奔馳俗累忙。", "何時足生理，卜築並山陽。"]'),
('6bee563f-ab9a-44da-b16b-deb801026674','游天宮寺','葛洪','宋','宋诗','song-poetry','','[]','昔日經遊處，如今意已荒。',48,'全唐诗/poet.song.173000.json','["昔日經遊處，如今意已荒。", "知君曾命駕，爲恨失褰裳。", "境好因人勝，詩看著脚忙。", "會須重定約，暇日共相徉。"]'),
('4616c295-d401-43b4-acdc-837692dfd8e0','癸丑臘大暖誌之','葛洪','宋','宋诗','song-poetry','','[]','歲晏風裂肉，今乃頓和柔。',156,'全唐诗/poet.song.173000.json','["歲晏風裂肉，今乃頓和柔。", "玄冥在何許，而使威令收。", "陰冰澌已泮，礎柱汗交流。", "敝扇出故篋，老體捐輕裘。", "細人幸煦燠，君子深噍啁。", "天地有正氣，來往無停輈。", "春蠶而冬敖，夏假而秋揫。", "此候或云舛，厥證良不瘳。", "念昔有名相，死人遺道周。", "睠焉不敢忽，顧逮一喘牛。", "彼誠知所職，豈伊調燮羞。", "嗟予寡所恃，隔絕明與幽。", "罪戾不自省，胡爲憂人憂。"]'),
('b18396be-04a9-4859-9232-c3e6a9bb866a','翠雲山','張元觀','宋','宋诗','song-poetry','','[]','未了人間朱墨緣，强顔荒邑又三年。',32,'全唐诗/poet.song.173000.json','["未了人間朱墨緣，强顔荒邑又三年。", "填胸瞇目皆塵土，直到峰頭始豁然。"]'),
('55281835-af70-44a4-b85a-9b7b81a44528','續和漕司高齋韵','薛紱','宋','宋诗','song-poetry','','[]','坦情渠儂嫌我真，斗升誰給太倉陳。',64,'全唐诗/poet.song.173000.json','["坦情渠儂嫌我真，斗升誰給太倉陳。", "悠悠江漢飄零客，落落乾坤老病身。", "心歷百艱彌感奮，詩留千古越清新。", "高齋高處齊文焰，付與從今仰止人。"]'),
('b768e96d-7103-4d00-ac98-d8535569b6a0','題巫山瞻華亭','鄧諫從','宋','宋诗','song-poetry','','[]','崚嶒玉削三千丈，翠潑嵐光冷相向。',320,'全唐诗/poet.song.173000.json','["崚嶒玉削三千丈，翠潑嵐光冷相向。", "風含太古雲氣長，變化溟濛紛萬象。", "陰晴一日具四時，天籟壑深虛自響。", "神山娟妙擢群參，錦繡鋪張獻奇狀。", "蟠根積鐵匯百川，龍矯蛟翻饒跌宕。", "勢連三楚此開國，故壘荒宮带溪瀼。", "樓臺井邑老風烟，環珮清聞駐仙仗。", "竹林風味便讀易，久與江山爲輩行。", "鳴絃餘暇豁心眼，戲著飛闌雲雨上。", "爽明自可達壅蔽，野獲又何勞草創。", "政和民氣長似春，景迥心平過於掌。", "征鴻明滅志何杳，黄鵠追隨意尤放。", "當年李杜經行處，太史銀鈎刻青嶂。", "寶刀珠瑟出耕墾，曲水纖腰迷草莽。", "牢盆古隸雜秦篆，飛動閒摹永平樣。", "珊瑚交柯炯不蝕，髣髴將軍勳業壯。", "英雄繁盛隨流水，時有竹枝賡牧唱。", "孔泉文物起騷經，國色明妃守孤尚。", "我家峨眉紫翠間，爲愛奇峰甘蒟醤。", "秋風野水憶絲蓴，擊汰夷猶理烟榜。"]'),
('048ad79a-5877-42d6-a511-c5734a994941','還桑澤卿蘭亭考二首  其一','葉時','宋','宋诗','song-poetry','','[]','書法光芒晉永和，後來摹寫不勝多。',32,'全唐诗/poet.song.173000.json','["書法光芒晉永和，後來摹寫不勝多。", "考論又得桑夫子，蘭渚風流轉不磨。"]'),
('5c1d4db2-d06b-4e8a-ba67-996aaf635430','還桑澤卿蘭亭考二首  其二','葉時','宋','宋诗','song-poetry','','[]','自從繭紙殉昭陵，定武流傳賸得名。',32,'全唐诗/poet.song.173000.json','["自從繭紙殉昭陵，定武流傳賸得名。", "總輯舊聞爲博議，即今真贋不難憑。"]'),
('ba9047e6-7ffe-42bc-b812-d2591e045a42','挽東萊先生  其一','楊誠之','宋','宋诗','song-poetry','','[]','德性天然具，文章少已工。',48,'全唐诗/poet.song.173000.json','["德性天然具，文章少已工。", "淳明范太史，簡澹小臾公。", "聖學驪珠貫，人材水鏡空。", "膏車輕萬里，垂發哭途窮。"]'),
('d1b1420f-bbe4-4d6b-9040-b494da70622b','挽東萊先生  其二','楊誠之','宋','宋诗','song-poetry','','[]','宇量諸公上，聲名一世宗。',48,'全唐诗/poet.song.173000.json','["宇量諸公上，聲名一世宗。", "平生無一愧，度外有兼容。", "綆斷一尋井，蘿枯百尺松。", "紛紛湖海士，末路更誰從。"]'),
('37058341-913d-4559-83c6-5a02981f9007','挽東萊先生  其三','楊誠之','宋','宋诗','song-poetry','','[]','久屬蒼生望，溫然兩玉人。',48,'全唐诗/poet.song.173000.json','["久屬蒼生望，溫然兩玉人。", "長沙纔賦鵩，絕筆遽傷麟。", "自牖無遺納，遭時有未信。", "萬牛回首處，深谷卧輪囷。"]'),
('c37ca33b-eb17-483b-9992-f1f5d19b8212','挽東萊先生  其四','楊誠之','宋','宋诗','song-poetry','','[]','共惜堂堂去，真成種種休。',48,'全唐诗/poet.song.173000.json','["共惜堂堂去，真成種種休。", "中原渺歸計，清洛更東流。", "鍛鍊言猶在，從谷志未酬。", "何心誦遺草，有路慟西州。"]'),
('85312176-2bdc-460b-ab2c-07cd6d1ce306','黄山採藥歌','汪雄圖','宋','宋诗','song-poetry','','[]','黄山青兮峛崺，三十六峰兮森起。',89,'全唐诗/poet.song.173000.json','["黄山青兮峛崺，三十六峰兮森起。", "草芸芸兮金吐華，石浥浥兮玉成髓。", "若有人兮薜荔衣，掬芳潤兮凌險巇。", "朝擷英兮巖竇，夕攬秀兮溪湄。", "招浮邱兮爲侶，豈劉阮兮自迷。", "療膏肓兮下土，陪軒轅兮與歸。"]'),
('48459de9-880a-43b6-aaac-729d2f84dccb','南湖','趙汝談','宋','宋诗','song-poetry','','["\u897f\u6e56"]','每憶西湖上，青帘賣酒亭。',48,'全唐诗/poet.song.173000.json','["每憶西湖上，青帘賣酒亭。", "柳條魚頰翠，花片馬蹄馨。", "寒食經行路，晴窗入夢屏。", "因循春又晚，風絮攪空冥。"]'),
('12fab9e6-1df2-4ff6-8555-46de88e6964a','靈谷','趙汝談','宋','宋诗','song-poetry','','[]','靈谷神仙宅，言歸肆目新。',48,'全唐诗/poet.song.173000.json','["靈谷神仙宅，言歸肆目新。", "山光遠如畫，秋色老於人。", "世事棋爭劫，人心海變塵。", "功成思范蠡，湖上一閒身。"]'),
('40f6d6bd-87b9-4b8d-acc1-be5415c6a27a','翠蛟亭和鞏豐韵','趙汝談','宋','宋诗','song-poetry','','[]','幽亭枕蒼峽，雲竇通曲水。',204,'全唐诗/poet.song.173000.json','["幽亭枕蒼峽，雲竇通曲水。", "百折如建瓴，㶁㶁鳴不止。", "客來一抽鑰，白霧噀巖底。", "欻翕千丈蛟，拏空翠濤起。", "天開混沌竅，日洗盤古髓。", "諒匪畜池鱗，多應化雷尾。", "馮陵氣易壯，怖蕩辭難侈。", "日假金洞光，景逾瑶池泚。", "誰云遊方外，巧異緇塵裏。", "坡仙頗年數，覿面猶尺咫。", "采句貴自然，鞏言良是已。", "琁題豁靈界，篆出蕃君里。", "物生亦倚數，有形必有靡。", "道人亦多事，浮念何時死。", "余生嗜泉藪，痼習牽研几。", "太息動靜機，于何寄真理。", "醉倒和滄浪，煩君更詳此。"]'),
('bb61474e-6a08-4565-b6ee-907d7a251d96','環錦亭  其一','趙汝談','宋','宋诗','song-poetry','','[]','與子鄉鄰信有年，故王遺事到今傳。',64,'全唐诗/poet.song.173000.json','["與子鄉鄰信有年，故王遺事到今傳。", "爽鳩邑改風烟在，散騎園分水竹偏。", "高架插書供夜讀，滿堂成綵敵春妍。", "相如可是區區者，戲筆題橋亦偶然。"]'),
('bbe7373f-280e-4a26-8eca-00218fa9f6b1','環錦亭  其二','趙汝談','宋','宋诗','song-poetry','','[]','枌社交陰舊有緣，蹇馿那得到亭前。',64,'全唐诗/poet.song.173000.json','["枌社交陰舊有緣，蹇馿那得到亭前。", "青山謝傅携樽地，白水錢王守冢田。", "尚友詩書厪暇日，養親豚韭樂豐年。", "異時駟馬榮歸里，虛左相迎更可賢。"]'),
('f89c853a-a0f9-4bf1-89bf-d1ad126f37cd','題謝一犁春雨圖','趙汝談','宋','宋诗','song-poetry','','[]','久客長安思野人，今年糴貴更愁新。',32,'全唐诗/poet.song.173000.json','["久客長安思野人，今年糴貴更愁新。", "江蕪漠漠春多少，展卷聊尋夢裏身。"]'),
('5a672656-f396-4760-8ccc-f12b46401800','洞霄觀水','趙汝談','宋','宋诗','song-poetry','','[]','峽口蒼蒼放水時，乾風吹落面前詩。',32,'全唐诗/poet.song.173000.json','["峽口蒼蒼放水時，乾風吹落面前詩。", "可憐無地遮秋色，流出千山也自奇。"]'),
('bd4ace6f-2a85-4997-857a-0bb33a647434','寄趙昌父','趙汝談','宋','宋诗','song-poetry','','[]','楊柳風吹神雨晴，櫻桃花發野塘春。',32,'全唐诗/poet.song.173000.json','["楊柳風吹神雨晴，櫻桃花發野塘春。", "歸來依舊青山好，白髮看山有幾人。"]'),
('349b9d6d-c29e-4fad-9950-5ea90996dafd','翠蛟亭酬和  其一','趙汝談','宋','宋诗','song-poetry','','[]','多病思君秋水深，好風忽送雁來音。',32,'全唐诗/poet.song.173000.json','["多病思君秋水深，好風忽送雁來音。", "相逢四句山中偈，說盡君心見我心。"]'),
('2bdaa019-d2dd-4eb5-966e-6f65785482fd','翠蛟亭酬和  其二','趙汝談','宋','宋诗','song-poetry','','[]','聞道今晨看洞回，老龍眠處寶千堆。',32,'全唐诗/poet.song.173000.json','["聞道今晨看洞回，老龍眠處寶千堆。", "靈珠已落君侯手，枉著明駝夜半催。"]'),
('04e909d6-69b9-4fde-8e95-ed21a0aea80d','翠蛟亭酬和  其三','趙汝談','宋','宋诗','song-poetry','','[]','衣上繽翂雲欲生，一山果熟看猿登。',32,'全唐诗/poet.song.173000.json','["衣上繽翂雲欲生，一山果熟看猿登。", "亦聞鰲背通朱關，幾擬追尋竟未曾。"]'),
('20a4eaae-9fff-4280-8c9f-296ccb7e0ce1','次曾景建和謝康樂華子岡詩韵','趙汝談','宋','宋诗','song-poetry','','[]','君言華子岡，遺跡在茲山。',120,'全唐诗/poet.song.173000.json','["君言華子岡，遺跡在茲山。", "陰霧虎嘯谷，熙暘烏浴泉。", "劃疑易區界，遐集古聖賢。", "丹井砂蕩潏，玉林桂葱阡。", "或時吹簫子，來往倏飛烟。", "徵謝靡不驗，叩玄發奇筌。", "先疇樂斯隠，荒始規後傳。", "小子夙慕遁，馳心結繩前。", "仙路邈難期，矯首涕潺湲。", "謁予願有術，投翰三喟然。"]'),
('2e972432-2524-4839-a2f6-ec53ebf61a1b','次曾景建紅泉碧澗韵  其一','趙汝談','宋','宋诗','song-poetry','','[]','詩評明水好，笑我尚逶迤。',48,'全唐诗/poet.song.173000.json','["詩評明水好，笑我尚逶迤。", "丹穴三千仞，蒼藤千萬枝。", "谷耕聞好鳥，社飲見龐眉。", "他日煩君指，書堂與佛祠。"]'),
('e94b1137-825a-4a94-94e6-03424cc67d64','次曾景建紅泉碧澗韵  其二','趙汝談','宋','宋诗','song-poetry','','[]','石不能言語，雲如過去身。',48,'全唐诗/poet.song.173000.json','["石不能言語，雲如過去身。", "意求雖彷彿，事往或湮淪。", "洞壑龍離隠，池塘草得春。", "山民忽驚避，吾此岸烏巾。"]'),
('c1105685-4657-4bae-813f-8f9732aa4179','次曾景建紅泉精舍韵','趙汝談','宋','宋诗','song-poetry','','[]','康樂秀髯長拂巾，伐山走鹿辟車塵。',64,'全唐诗/poet.song.173000.json','["康樂秀髯長拂巾，伐山走鹿辟車塵。", "才毫并觸當時禍，物色分留後代人。", "環澗已爲僧去碣，紅泉今與子通鄰。", "著書萬卷精廬裏，成佛生天自致身。"]'),
('efd51d1b-8a66-4b95-ae00-5938967f3182','資聖寺','周牧','宋','宋诗','song-poetry','','[]','點點晴光滴翠嵐，參天松幹影毿毿。',64,'全唐诗/poet.song.173000.json','["點點晴光滴翠嵐，參天松幹影毿毿。", "穿雲日閲客十數，汲水時聞僧兩三。", "俗子遶登山勒馬，禪心常共丹同龕。", "烹茶汲取盈甌雪，一味清霜齒頰寒。"]'),
('d636d5f4-d224-44bd-ac15-4552646c2feb','超覽亭','周牧','宋','宋诗','song-poetry','','[]','翠微深處著亭臺，抖擻紅塵雙眼開。',64,'全唐诗/poet.song.173000.json','["翠微深處著亭臺，抖擻紅塵雙眼開。", "嵐影剩添盃色好，泉聲不带市喧來。", "竹間啼鳥破山寂，天際孤舟界浪回。", "占斷鷂峰無限景，何妨杖屨日徘徊。"]'),
('8cb2c4c0-d939-4ac5-8c83-f0b0d13add7b','漳河疑冢','俞應符','宋','宋诗','song-poetry','','[]','生前欺天絕漢統，死後欺人設疑冢。',66,'全唐诗/poet.song.173000.json','["生前欺天絕漢統，死後欺人設疑冢。", "人生用智死即休，何有餘機到丘壟。", "人言疑冢我不疑，我有一法君未知。", "直須盡發疑冢七十二，必有一冢藏君屍。"]'),
('a539a891-c975-4af9-80f9-ed63343aea87','玉蕊花','鄭域','宋','宋诗','song-poetry','','[]','維揚后土廟瓊花，安業唐昌宮玉蕊。',224,'全唐诗/poet.song.173000.json','["維揚后土廟瓊花，安業唐昌宮玉蕊。", "判然二物本不同，喚作一般良未是。", "瓊花雪白輕壓枝，大率形模八仙耳。", "山谿野路多見之，樵夫摧殘如獮薙。", "比之玉蕊似實非，金粟冰絲那有此。", "花鬚中有碧膽瓶，別出瓏璁高半指。", "清馨靜夜衝九天，招隠瑶臺女仙子。", "乘風躍馬汗漫遊，偷折繁香分月姊。", "紫莖柘葉荼䕷條，少到尋常人眼底。", "翰林內苑集賢閣，雨露承天近尺咫。", "後生不識天上花，又把山礬輕比擬。", "葉酸而澀供染黄，不著霜縑偏入紙。", "江鄉老少知此名，鄭榐瑒音無正字。", "方言土諺隨舌訛，烏馬成焉固應爾。"]'),
('f8a405d4-0fbb-4ab2-a59d-36223582cad5','山丹花','鄭域','宋','宋诗','song-poetry','','[]','團欒蜂蕊簇枝間，鉛鼎成丹七返還。',32,'全唐诗/poet.song.173000.json','["團欒蜂蕊簇枝間，鉛鼎成丹七返還。", "乞與幽人伴幽壑，不妨相對兩朱顔。"]'),
('e7eb7e1e-b27a-43fa-b23e-7c40b968e53d','茉莉花  其一','鄭域','宋','宋诗','song-poetry','','[]','風韵傳天竺，隨經入漢京。',24,'全唐诗/poet.song.173000.json','["風韵傳天竺，隨經入漢京。", "香飄山麝馥，露染雪衣輕。"]'),
('839b22e0-bea4-4559-98a9-0d00c4e1f537','茉莉花  其二','鄭域','宋','宋诗','song-poetry','','[]','玉瑳蓮子作尖丸，龍腦熏香簇滿冠。',32,'全唐诗/poet.song.173000.json','["玉瑳蓮子作尖丸，龍腦熏香簇滿冠。", "好是瑩無紅一點，苦教紅却不堪看。"]'),
('0cde43af-1707-4ac7-b1db-22c71c9579e5','素馨花','鄭域','宋','宋诗','song-poetry','','[]','妙香真色得之天，羞御鉛華學女妍。',32,'全唐诗/poet.song.173000.json','["妙香真色得之天，羞御鉛華學女妍。", "只向溫柔鄉裏活，怕寒不許上林傳。"]'),
('869c1da2-f887-4b19-93c2-1e64fdf8c4d0','闍提花','鄭域','宋','宋诗','song-poetry','','[]','此花移種自招提，借佛爲名識者希。',32,'全唐诗/poet.song.173000.json','["此花移種自招提，借佛爲名識者希。", "優缽曼陀果何似，併參香爭問因依。"]'),
('6b340fab-18b6-4eff-8f7b-8f443c361b3d','檳榔','鄭域','宋','宋诗','song-poetry','','[]','海角人煙百萬家，蠻風未變事堪嗟。',64,'全唐诗/poet.song.173000.json','["海角人煙百萬家，蠻風未變事堪嗟。", "果堆羊豕烏青欖，菜飣丁香紫白茄。", "楊棗實酸薄蒳子，山荼無葉木棉花。", "一般氣味真難學，日啖檳榔當啜茶。"]'),
('2500b5ee-5e89-461c-8fd4-32487c264f13','題靈惠','鄭域','宋','宋诗','song-poetry','','[]','高山如逸民，不肯近人迹。',72,'全唐诗/poet.song.173000.json','["高山如逸民，不肯近人迹。", "孤峭尺五天，空洞容數百。", "不招龍自來，其下爲窟宅。", "天下待霖雨，胡爲躭睡癖。", "我今喚飛廉，駕汝上空碧。", "吾鞭不妄施，慎勿憚勞瘠。"]'),
('6e09cd04-677d-440e-aa35-cfe11ca8ab29','遊黄楊巖','鄭域','宋','宋诗','song-poetry','','[]','暮秋訪幽隠，謝屐凌崩空。',84,'全唐诗/poet.song.173000.json','["暮秋訪幽隠，謝屐凌崩空。", "行到山頂間，還與平地同。", "舉手抉層雲，下視無高峰。", "疏藤挂赤虯，粘苔糝青茸。", "面首三神山，縹緲滄海東。", "指點笑語高，吹聲半天中。", "安得大鵬背，載我遊無窮。"]'),
('dcbd29cd-3c3a-4b9b-9115-5304ed4edf69','題法相巖','鄭域','宋','宋诗','song-poetry','','[]','法相具諸相，寶方無定方。',48,'全唐诗/poet.song.173000.json','["法相具諸相，寶方無定方。", "突兀虎豹立，嵌空蛟龍藏。", "入地轉輪遠，透天圓竇光。", "何人鑿混沌，擲棄官路傍。"]'),
('4a0105e9-22ef-48b6-84ef-673bff871e07','句  其一','鄭域','宋','宋诗','song-poetry','','[]','九里花田地。',6,'全唐诗/poet.song.173000.json','["九里花田地。"]'),
('2c2ea0af-8d48-4897-b348-0c3fcf10e3a2','句  其二','鄭域','宋','宋诗','song-poetry','','[]','檳榔共聘幣。',6,'全唐诗/poet.song.173000.json','["檳榔共聘幣。"]'),
('9e7b2f16-ff1d-49a3-9a13-dd997926fafc','句  其三','鄭域','宋','宋诗','song-poetry','','[]','果子庵摩勒。',6,'全唐诗/poet.song.173000.json','["果子庵摩勒。"]'),
('95ab4caa-8eaf-4195-bf24-46d770354fe5','句  其四','鄭域','宋','宋诗','song-poetry','','[]','旅程一見錯歡喜，彷彿吾鄉茉莉花。',16,'全唐诗/poet.song.173000.json','["旅程一見錯歡喜，彷彿吾鄉茉莉花。"]'),
('c0ba2ffb-8302-4476-8364-d25a511605fd','題西湖山岩二首  其一','林㟽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','咫尺移文喚即應，此亭便可配韓亭。',64,'全唐诗/poet.song.173000.json','["咫尺移文喚即應，此亭便可配韓亭。", "溪流橫過一灣碧，山色平分兩岸青。", "落日鐘聲鳴遠樹，半空塔影倒寒汀。", "雲烟滿目皆親種，留與邦人作畫屏。"]'),
('53514ec8-f946-4c2b-9df6-f108ebbb7d81','題西湖山岩二首  其二','林㟽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','坐對高舂放晚衙，舂米和石也穿芽。',64,'全唐诗/poet.song.173000.json','["坐對高舂放晚衙，舂米和石也穿芽。", "鷗邊雲闊三千頃，樹杪烟橫數萬家。", "貯月未圓松瑣碎，怯風無力竹欹斜。", "叮嚀好護湖山景，養得陰成宿莫鴉。"]'),
('b308f967-2cc6-49e6-8331-f08cf95c962e','登潮陽東山','林㟽','宋','宋诗','song-poetry','','[]','小雨上東山，層層著意看。',48,'全唐诗/poet.song.173000.json','["小雨上東山，層層著意看。", "尋泉行處僻，就石坐來寒。", "赤舄歸周旦，蒼山起謝安。", "功能成底事，一抹莫雲殘。"]'),
('b22e680b-7f01-4fa0-9a89-537e5192122d','九日題潮陽縣齋','林㟽','宋','宋诗','song-poetry','','[]','去歲重陽尚故鄉，今朝官舍又重陽。',32,'全唐诗/poet.song.173000.json','["去歲重陽尚故鄉，今朝官舍又重陽。", "人情不似黄花好，處處相逢一種香。"]'),
('a037716d-7580-4729-8f02-432745c2a08d','重闢西湖  其一','林㟽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鏡奩平處小橋西，橋外輕鷗掠鏡飛。',64,'全唐诗/poet.song.173000.json','["鏡奩平處小橋西，橋外輕鷗掠鏡飛。", "鑿破青雲放山出，撥開碧蘚引湖歸。", "带烟插柳陰雖瘦，趁雨栽荷綠已肥。", "欲借禽魚祝君壽，君恩寬大此情微。"]'),
('66715ddc-1594-48f4-b87d-584ddf438821','重闢西湖  其二','林㟽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','新隄喜繞幾紆縈，挈榼携壺出滿城。',64,'全唐诗/poet.song.173000.json','["新隄喜繞幾紆縈，挈榼携壺出滿城。", "萍破煙紋容棹過，石開雲罅看人行。", "亭浮橫照波中影，僧拾殘霞樹杪聲。", "不必鳳凰山上問，此山東向面湖平。"]'),
('b77184ab-7463-455a-9324-d43e128174f5','鐵甕洞','陳唐佐','宋','宋诗','song-poetry','','[]','雲端象鼻通，一甕自沖融。',48,'全唐诗/poet.song.173000.json','["雲端象鼻通，一甕自沖融。", "豈是乾坤小，當知造化工。", "靈泉猿不飲，丹氣鶴常充。", "仙子乘鸞去，何年返故宮。"]'),
('4bf76149-bba5-47b0-ab78-a53de9a0077a','詩一首','醉客','宋','宋诗','song-poetry','','[]','行盡蓬萊弱水源，今朝忍渴過崑崙。',32,'全唐诗/poet.song.173000.json','["行盡蓬萊弱水源，今朝忍渴過崑崙。", "興來莫問酒中聖，且把金杯和月吞。"]'),
('ca07a8b0-5218-41d4-85c1-0e1e033cae2e','送奚宰二首  其一','陸埈','宋','宋诗','song-poetry','','[]','茂宰慈祥意，三年只似初。',48,'全唐诗/poet.song.173000.json','["茂宰慈祥意，三年只似初。", "折腰寧而米，掣肘固難書。", "機靜波浮鳥，刑疏網漏魚。", "終然清議在，褒字到公車。"]'),
('56f3b9e7-e2cb-427d-a7fe-7787816d195f','送奚宰二首  其二','陸埈','宋','宋诗','song-poetry','','[]','失學兒俱懶，師資點化開。',48,'全唐诗/poet.song.173000.json','["失學兒俱懶，師資點化開。", "砭針瘳痼疾，膏馥起枯荄。", "授□方知緒，從游奈溯洄。", "武城門下士，應許厠澹臺。"]'),
('cdeb955f-1cf1-4723-997c-08772f99ee85','醜梨','陸埈','宋','宋诗','song-poetry','','[]','灰貌凝清古，霜津溢澹甜。',48,'全唐诗/poet.song.173000.json','["灰貌凝清古，霜津溢澹甜。", "面嫌湯後白，心慰邑中黔。", "美實種寒谷，珍嘗近御匳。", "彼姝徒冠玉，爭得似無鹽。"]'),
('97333759-8b81-4793-a424-bb538c701b81','和奚宰春風樓即事','陸埈','宋','宋诗','song-poetry','','[]','恍然楹桷架虛空，意象經營九仞功。',64,'全唐诗/poet.song.173000.json','["恍然楹桷架虛空，意象經營九仞功。", "三載笑談杯酒裏，一時人物畫圖中。", "金蘭託契從今始，玉燭迎和與衆同。", "却笑楚臺雕篆客，强生分別詫雄風。"]'),
('bbaa5a4b-2bac-489a-bce2-ad4030ce5805','和太白感秋','譙令憲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','余年四十九，濫分盆城竹。',96,'全唐诗/poet.song.173000.json','["余年四十九，濫分盆城竹。", "悠然望匡廬，秀色良可掬。", "緬思二先生，風流昔所獨。", "紫極感秋吟，北窗和月宿。", "茲余還一來，契合若龜卜。", "行年適相同，妙語難再復。", "杖屨兼經從，陳迹猶可覆。", "懷人夜永歎，歸歟清睡熟。"]'),
('fd3df275-e165-4a88-8759-9af5b137dabc','題三軒','譙令憲','宋','宋诗','song-poetry','','[]','回頭四十九年非，又向盆城把一麾。',64,'全唐诗/poet.song.173000.json','["回頭四十九年非，又向盆城把一麾。", "蘇子北窗明月夜，謫仙紫極感秋時。", "來遊偶契二賢跡，欲賦難酬五字詩。", "前輩風流淪落盡，何人爲種玉田芝。"]'),
('0cb3b2c1-ee83-4ad1-97dc-4ea4d2a0ce1d','句','葉延年','宋','宋诗','song-poetry','','[]','一夜西風驚客枕，滿堤楊柳作秋聲。',16,'全唐诗/poet.song.173000.json','["一夜西風驚客枕，滿堤楊柳作秋聲。"]'),
('f7c4076e-7311-4242-a1b4-e6b733467718','題環錦亭','趙善卞','宋','宋诗','song-poetry','','[]','百世垂芳在一經，茂林修竹讀書聲。',64,'全唐诗/poet.song.173000.json','["百世垂芳在一經，茂林修竹讀書聲。", "園池日涉皆成趣，景物天然分外清。", "聊復垂綸藏渭釣，等閒釋耒起莘耕。", "知君自有真良貴，豈羨斯亭錦得名。"]'),
('98d047ca-72e5-4acb-80b0-3de3df01faa7','經由天台劉阮洞以雨作不及遊','顧士龍','宋','宋诗','song-poetry','','[]','松形夭矯學飛鸞，怪石蒼崖蘚暈團。',64,'全唐诗/poet.song.173000.json','["松形夭矯學飛鸞，怪石蒼崖蘚暈團。", "地僻不容人迹到，雲深更覺客衣單。", "春歸不見桃干樹，月冷空餘水一灘。", "欲問神仙向何處，山風吹雨作朝寒。"]'),
('fb020e58-1ac3-4663-b9c9-82db36359e4f','西峰山','顧士龍','宋','宋诗','song-poetry','','[]','三十六溪清淺水，二十四重高下山。',32,'全唐诗/poet.song.173000.json','["三十六溪清淺水，二十四重高下山。", "卓錫自無風雨厄，不然俗駕便須還。"]'),
('2ee8930f-ed24-4c49-8531-20abebf49e69','與郭敬叔','單煒','宋','宋诗','song-poetry','','[]','蘭亭一入昭陵後，筆法于今未易回。',32,'全唐诗/poet.song.173000.json','["蘭亭一入昭陵後，筆法于今未易回。", "誰識定齋三昧筆，又傳璧坼到江梅。"]'),
('4bf7043d-6fac-4a98-8cc2-4ea727f49104','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其一','姜夔','宋','宋诗','song-poetry','','[]','滔滔沔鄂留，有靦三宿桑。',48,'全唐诗/poet.song.173000.json','["滔滔沔鄂留，有靦三宿桑。", "持鉢了白日，事賤丸蛣蜣。", "念當去石友，煙席淩江湘。", "爲君試歌商，歌短意則長。"]'),
('dcf19ec1-58a3-4a02-bcbe-7a3a09386195','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其二','姜夔','宋','宋诗','song-poetry','','[]','佳人魯山下，日弄清漢波。',48,'全唐诗/poet.song.173000.json','["佳人魯山下，日弄清漢波。", "促絃調寶瑟，哀思感人多。", "咬哇秦缶擊，冷落郢客歌。", "知音良不易，如此粲者何。"]'),
('91df1c4a-a741-4d0f-a4a6-110e5274cad9','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其三','姜夔','宋','宋诗','song-poetry','','[]','英英白龍孫，眉目古人氣。',48,'全唐诗/poet.song.173000.json','["英英白龍孫，眉目古人氣。", "拮据營數椽，下簾草生砌。", "文章作逕庭，功用見造次。", "無庸垂罄嗟，遺安鹿門意。"]'),
('77c5097b-8bba-4cba-a43f-7be176f495a2','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其四','姜夔','宋','宋诗','song-poetry','','[]','詩人辛國士，句法似阿駒。',48,'全唐诗/poet.song.173000.json','["詩人辛國士，句法似阿駒。", "別墅滄浪曲，綠陰禽鳥呼。", "頗參金粟眼，漸造文字無。", "兒輩例學語，屋壁祝蒲盧。"]'),
('4f5e2749-137a-463a-af00-fab33b8f7d31','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其五','姜夔','宋','宋诗','song-poetry','','[]','山陰千載人，揮洒照八極。',48,'全唐诗/poet.song.173000.json','["山陰千載人，揮洒照八極。", "只今定武刻，猶带龍虎筆。", "單侯出機杼，豈自劍舞得。", "餘波入竹石，絕歎咄咄逼。"]'),
('ec9c7f23-1ad5-4509-8a74-c672c6c301e2','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其六','姜夔','宋','宋诗','song-poetry','','[]','異時之罘君，在涅守曰顥。',48,'全唐诗/poet.song.173000.json','["異時之罘君，在涅守曰顥。", "黄鍾欠牛鐸，淋漓弔遺稿。", "有子殊可人，特未見此老。", "客來請論文，但道曲肱好。"]'),
('cafa6b92-ccd0-49f4-a851-66f9f4cffd08','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其七','姜夔','宋','宋诗','song-poetry','','[]','中郎逝千霜，曲高復誰爲。',48,'全唐诗/poet.song.173000.json','["中郎逝千霜，曲高復誰爲。", "龐翁趣無絃，鄭伯功斲鼻。", "春風桃花溪，寒淥繞蒼翠。", "何當從兩君，放浪討幽事。"]'),
('926ecfef-4e24-4e7f-824e-04ced075904b','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其八','姜夔','宋','宋诗','song-poetry','','[]','宦達羞故妻，賤貧厭丘嫂。',48,'全唐诗/poet.song.173000.json','["宦達羞故妻，賤貧厭丘嫂。", "上書雲雨迥，還舍筍蕨老。", "江臯鉏带經，决計恨不早。", "士無五羖皮，沒世抱枯槁。"]'),
('f93132b9-d317-446c-9103-be156f8f4582','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其九','姜夔','宋','宋诗','song-poetry','','[]','伐木響虛牝，我願友褐夫。',48,'全唐诗/poet.song.173000.json','["伐木響虛牝，我願友褐夫。", "九關呀虎豹，何時內高袪。", "黄鵠眇雲樹，鸚鵡澹煙蕪。", "倚杖得清賞，洗心觀本初。"]'),
('2062aa9d-2927-4d7e-b337-b0fbbb297676','以長歌意無極好爲老夫聽爲韵奉別沔鄂親友  其一○','姜夔','宋','宋诗','song-poetry','','[]','孤鴻度關山，風霜摧翅瓴。',48,'全唐诗/poet.song.173000.json','["孤鴻度關山，風霜摧翅瓴。", "影低白雲莫，哀噭那忍聽。", "士生有如此，儲粟不滿瓶。", "著書窮愁濱，可續離騷經。"]'),
('5f522c8a-1fd7-48be-8d41-ce541e1d534e','過湘陰寄千巖','姜夔','宋','宋诗','song-poetry','','[]','眇眇臨風思美人，荻花楓葉带離聲。',32,'全唐诗/poet.song.173000.json','["眇眇臨風思美人，荻花楓葉带離聲。", "夜深吹笛移船去，三十六灣秋月明。"]'),
('9be38b6e-69a3-483b-b77b-8c15e542b319','雁圖','姜夔','宋','宋诗','song-poetry','','[]','萬里晴沙夕照西，此心唯有斷雲知。',32,'全唐诗/poet.song.173000.json','["萬里晴沙夕照西，此心唯有斷雲知。", "年年數盡秋風字，想見江南摇落時。"]'),
('c8d9ced7-fd5b-4f30-8662-6280b082f494','赤松圖','姜夔','宋','宋诗','song-poetry','','[]','山東隆準公，未語心已解。',48,'全唐诗/poet.song.173000.json','["山東隆準公，未語心已解。", "按劍堂下人，成事汝應退。", "非無带礪約，政爾有恩害。", "平生三寸舌，松間漱寒瀨。"]'),
('f1365f1d-9823-4357-9d0e-f55f4c226af2','送朝天續集歸誠齋時在金陵','姜夔','宋','宋诗','song-poetry','','[]','翰墨場中老斲輪，真能一筆掃千軍。',64,'全唐诗/poet.song.173000.json','["翰墨場中老斲輪，真能一筆掃千軍。", "年年花月無閑日，處處山川怕見君。", "箭在的中非爾力，風行水上自成文。", "先生只可三千首，回施江東日暮雲。"]'),
('dda12a58-740d-4e4d-86bd-3decd442360d','送王孟玉歸山陰','姜夔','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','淮南雪落雲繞戍，王郎鳴鞭獵狐兔。',160,'全唐诗/poet.song.173000.json','["淮南雪落雲繞戍，王郎鳴鞭獵狐兔。", "問君本是山陰人，何不扁舟剡溪去。", "人生樂事將無同，知君此心如太空。", "只今去踏龍尾道，也似寒江蓑笠翁。", "鑑湖一曲荷花浦，君不歸來花有語。", "舊宅應添竹幾竿，到家不覺秋如許。", "十年雪裏看淮南，聚米能作淮南山。", "籌邊妙處須急吐，政自不容脩竹間。", "人道長江無六月，日光正射青蘆葉。", "何以贈君濯炎熱，雪即是詩詩是雪。"]'),
('2ad738b1-b66d-49b1-b320-02416337adb2','除夜自石湖歸苕溪  其一','姜夔','宋','宋诗','song-poetry','','[]','細草穿沙雪半銷，吳宮煙冷水迢迢。',32,'全唐诗/poet.song.173000.json','["細草穿沙雪半銷，吳宮煙冷水迢迢。", "梅花竹裏無人見，一夜吹香過石橋。"]'),
('1ae4e915-1e76-4992-9930-4a606ed36456','除夜自石湖歸苕溪  其二','姜夔','宋','宋诗','song-poetry','','[]','美人臺上昔歡娛，今日空臺望五湖。',32,'全唐诗/poet.song.173000.json','["美人臺上昔歡娛，今日空臺望五湖。", "殘雪未融青草死，苦無麋鹿過姑蘇。"]'),
('4ed7a69c-9da5-46bd-a4e2-b253cf5d2ed9','除夜自石湖歸苕溪  其三','姜夔','宋','宋诗','song-poetry','','[]','黄帽傳呼睡不成，投篙細細激流冰。',32,'全唐诗/poet.song.173000.json','["黄帽傳呼睡不成，投篙細細激流冰。", "分明舊泊江南岸，舟尾春風颭客燈。"]'),
('ba411a07-9018-4ec7-a3ea-0c743bf39a74','除夜自石湖歸苕溪  其四','姜夔','宋','宋诗','song-poetry','','[]','千門列炬散林鴉，兒女相思未到家。',32,'全唐诗/poet.song.173000.json','["千門列炬散林鴉，兒女相思未到家。", "應是不眠非守歲，小窗春意入燈花。"]'),
('0e1c3e76-c948-43ea-bd94-967075aa32a3','除夜自石湖歸苕溪  其五','姜夔','宋','宋诗','song-poetry','','[]','三生定自陸天隨，又向吳松作客歸。',32,'全唐诗/poet.song.173000.json','["三生定自陸天隨，又向吳松作客歸。", "已拚新年舟上過，倩人和雪洗征衣。"]'),
('457b7667-50b7-4b81-aad3-f61e08208129','除夜自石湖歸苕溪  其六','姜夔','宋','宋诗','song-poetry','','[]','沙尾風回一棹寒，椒花今夕不登盤。',32,'全唐诗/poet.song.173000.json','["沙尾風回一棹寒，椒花今夕不登盤。", "百年草草都如此，自琢春詞剪燭看。"]'),
('75b5a39c-f133-42b1-b2fe-65204cf4a41c','除夜自石湖歸苕溪  其七','姜夔','宋','宋诗','song-poetry','','[]','笠澤茫茫雁影微，玉峰重疊護雲衣。',32,'全唐诗/poet.song.173000.json','["笠澤茫茫雁影微，玉峰重疊護雲衣。", "長橋寂寞春寒夜，只有詩人一舸歸。"]'),
('472f3c69-0d3f-4fe1-8022-274189111456','除夜自石湖歸苕溪  其八','姜夔','宋','宋诗','song-poetry','','[]','桑間篝火却宜蠶，風土相傳我未諳。',32,'全唐诗/poet.song.173000.json','["桑間篝火却宜蠶，風土相傳我未諳。", "但得明年少行役，只裁白紵作春衫。"]'),
('78790fef-883d-47af-b058-9092fb2aeec8','除夜自石湖歸苕溪  其九','姜夔','宋','宋诗','song-poetry','','[]','少小知名翰墨場，十年心事只凄涼。',32,'全唐诗/poet.song.173000.json','["少小知名翰墨場，十年心事只凄涼。", "舊時曾作梅花賦，研墨于今亦自香。"]'),
('0058280c-c210-406a-ba8c-9050b544d475','除夜自石湖歸苕溪  其一○','姜夔','宋','宋诗','song-poetry','','[]','環玦隨波冷未銷，古苔留雪卧牆腰。',32,'全唐诗/poet.song.173000.json','["環玦隨波冷未銷，古苔留雪卧牆腰。", "誰家玉笛吹春怨，看見鵝黄上柳條。"]'),
('087eb898-9aa7-473a-a3c3-917a53e0fb44','悼石湖三首  其一','姜夔','宋','宋诗','song-poetry','','[]','身退詩仍健，官高病已侵。',48,'全唐诗/poet.song.173000.json','["身退詩仍健，官高病已侵。", "江山平日眼，花鳥暮年心。", "九轉終無助，三高竟欲尋。", "尚留巾墊角，胡虜有知音。"]'),
('fa814468-4408-4e09-8065-6520f5559dc7','悼石湖三首  其二','姜夔','宋','宋诗','song-poetry','','[]','未作龍蛇夢，驚聞露電身。',48,'全唐诗/poet.song.173000.json','["未作龍蛇夢，驚聞露電身。", "百年無此老，千首屬何人。", "安得公長健，那知事轉新。", "酸風憂國淚，高冢卧麒麟。"]'),
('a10c0ad2-4168-47cf-85a8-ed9365eb3ea5','悼石湖三首  其三','姜夔','宋','宋诗','song-poetry','','[]','未定情鍾痛，何堪更悼亡。',48,'全唐诗/poet.song.173000.json','["未定情鍾痛，何堪更悼亡。", "遣書知伏枕，來吊只空堂。", "雪裏評詩句，梅邊按樂章。", "沉思酒盃落，天闊意茫茫。"]'),
('56ebb6cc-aabd-4272-8db6-6dbde8209bcd','臨安旅邸答蘇虞叟','姜夔','宋','宋诗','song-poetry','','[]','垂楊風雨小樓寒，宋玉秋詞不忍看。',32,'全唐诗/poet.song.173000.json','["垂楊風雨小樓寒，宋玉秋詞不忍看。", "萬里青山無處隠，可憐投老客長安。"]'),
('235a4552-92ad-47b9-a753-0d74eb7eaaad','張平甫哀挽','姜夔','宋','宋诗','song-poetry','','[]','將軍家世出臞儒，合上青雲作計疎。',64,'全唐诗/poet.song.173000.json','["將軍家世出臞儒，合上青雲作計疎。", "吳下宅成花未種，湖邊地吉草新鋤。", "空嗟過隙催人世，頼有提孩讀父書。", "它日石羊芳草路，弟兄來此一沾裾。"]'),
('bd1b6fd4-f10d-471b-a3ee-171a1328aab7','題華亭錢參園池','姜夔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','花裏藏仙宅，簾邊駐客舟。',48,'全唐诗/poet.song.173000.json','["花裏藏仙宅，簾邊駐客舟。", "浦涵滄海潤，雲接洞庭秋。", "草木山山秀，闌干處處幽。", "機雲韜世業，暇日此夷猶。"]'),
('80d14c3f-6d9e-44c8-b2cd-3a0eb5948f3c','寄上張參政','姜夔','宋','宋诗','song-poetry','','[]','姑蘇臺下梅花樹，應爲調羹故早開。',64,'全唐诗/poet.song.173000.json','["姑蘇臺下梅花樹，應爲調羹故早開。", "燕寢休誇香霧重，鴛行却望衮衣來。", "前時甲第仍垂柳，今度沙堤已種槐。", "應念無枝夜飛鵲，月寒風勁羽毛摧。"]'),
('ccb916b8-a944-4db7-81ea-f43a50ef66c6','雪中訪石湖','姜夔','宋','宋诗','song-poetry','','[]','雪矸如玉城，偏師敢輕犯。',48,'全唐诗/poet.song.173000.json','["雪矸如玉城，偏師敢輕犯。", "黄蘆陣野鶩，我自將十萬。", "三戰渠未降，北面石湖范。", "先生霸越手，定目一笑粲。"]'),
('b3c72945-de60-4043-ac55-645928472f21','京口留別張思順','姜夔','宋','宋诗','song-poetry','','[]','伯勞飛燕若爲忙，還憶東齋夜共床。',64,'全唐诗/poet.song.173000.json','["伯勞飛燕若爲忙，還憶東齋夜共床。", "別後無書非棄我，春前會面却它鄉。", "連宵爲說經憂患，異日相逢各老蒼。", "更欲少留天不許，曉風吹艇入垂楊。"]'),
('7b084eb1-b7b5-4b3a-a875-3790d2c43e54','虞美人草','姜夔','宋','宋诗','song-poetry','','[]','夜闌浩歌起，玉帳生悲風。',48,'全唐诗/poet.song.173000.json','["夜闌浩歌起，玉帳生悲風。", "江東可千里，棄妾蓬蒿中。", "化石那解語，作草猶可舞。", "陌上望騅來，翻愁不相顧。"]'),
('5b1fe942-a7e5-4d96-b613-ba201e99398a','姑蘇懷古','姜夔','宋','宋诗','song-poetry','','["\u5199\u666f", "\u501f\u53e4\u8bbd\u4eca", "\u6000\u53e4", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143"]','夜暗歸雲繞柂牙，江涵星影鷺眠沙。',32,'全唐诗/poet.song.173000.json','["夜暗歸雲繞柂牙，江涵星影鷺眠沙。", "行人悵望蘇臺柳，曾與吳王掃落花。"]'),
('cfda68f7-b920-46ee-93ea-721fc596b4a4','次韵德久','姜夔','宋','宋诗','song-poetry','','[]','籬落青青花倒垂，避人黄鳥雨中飛。',32,'全唐诗/poet.song.173000.json','["籬落青青花倒垂，避人黄鳥雨中飛。", "西郊寂寞無車馬，時有溪童賣菜歸。"]'),
('4581bfa3-5fc2-447e-9943-048d18cd6eb2','華藏寺雲海亭望具區','姜夔','宋','宋诗','song-poetry','','[]','茫茫復茫茫，中有山蒼蒼。',72,'全唐诗/poet.song.173000.json','["茫茫復茫茫，中有山蒼蒼。", "大哉夫差國，坐斷天一方。", "夫差醉蓮宮，大浪摇不醒。", "越師何從來，奪我玉萬頃。", "年年亭上秋，一笛千古愁。", "誰能知許事，飛下雙白鷗。"]'),
('92dc1924-8c9f-4e89-8804-7697da79434c','次朴翁遊蘭亭韵','姜夔','宋','宋诗','song-poetry','','[]','亞字橋亭面面風，六人同坐樹陰中。',64,'全唐诗/poet.song.173000.json','["亞字橋亭面面風，六人同坐樹陰中。", "松交歸路如留客，石礙流盃故惱公。", "山色最憐秦望綠，野花只作晉時紅。", "夕陽啼鳥人將散，俛仰興懷自昔同。"]'),
('7c97157c-0431-423c-92f2-c6c61ff71222','同朴翁登卧龍山','姜夔','宋','宋诗','song-poetry','','[]','龍尾回平野，簷牙出翠微。',48,'全唐诗/poet.song.173000.json','["龍尾回平野，簷牙出翠微。", "望山憐綠遠，坐樹覺春歸。", "草合平吳路，鷗忘覇越機。", "午凉松影亂，白羽對禪衣。"]'),
('634ca32a-31b0-425c-b785-9b326e7d23e0','次韵胡仲方因楊伯子見寄','姜夔','宋','宋诗','song-poetry','','[]','此去廬陵定幾程，向來筇杖未經行。',64,'全唐诗/poet.song.173000.json','["此去廬陵定幾程，向來筇杖未經行。", "懸知征棹雲邊集，大有吟情雪裏生。", "楚渡食萍應甚美，舜祠吹玉直能清。", "二君即日青冥上，唯我春山带雨耕。"]'),
('661a1e33-939b-4f63-86a8-1415570ebe44','次石湖書扇韵','姜夔','宋','宋诗','song-poetry','','["\u5199\u4eba", "\u5199\u666f", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','橋西一水曲通村，岸閣浮萍綠有痕。',32,'全唐诗/poet.song.173000.json','["橋西一水曲通村，岸閣浮萍綠有痕。", "家住石湖人不到，藕花多處別開門。"]'),
('8ccabc32-13d2-4d42-9646-529e4a0d3883','夏日寄朴翁朴時在靈隠','姜夔','宋','宋诗','song-poetry','','[]','風吹松樹枝，懷我松間友。',48,'全唐诗/poet.song.173000.json','["風吹松樹枝，懷我松間友。", "雲從北山來，令我屢回首。", "山靈夜夜起，山雨侵人衣。", "遥知竹窗裏，自吟新雨詩。"]'),
('77221302-c2b1-41cb-aa3b-c66bcf88f52e','竹友爲徐南卿作  其一','姜夔','宋','宋诗','song-poetry','','[]','髮已星星带已寬，徐郎猶自客長安。',32,'全唐诗/poet.song.173000.json','["髮已星星带已寬，徐郎猶自客長安。", "家山竹好無由看，謾種庭心一兩竿。"]'),
('b51f0158-2fb3-4901-a04f-20cda9475911','竹友爲徐南卿作  其二','姜夔','宋','宋诗','song-poetry','','[]','世路蒼黄總是愁，暮年須得小優游。',32,'全唐诗/poet.song.173000.json','["世路蒼黄總是愁，暮年須得小優游。", "如今漸覺知心少，賸種青青伴白頭。"]'),
('e67d1a87-da16-48be-a1f2-ddd2eea3f51d','賀張肖翁參政','姜夔','宋','宋诗','song-poetry','','[]','太一圖書客屢談，已知上相出淮南。',64,'全唐诗/poet.song.173000.json','["太一圖書客屢談，已知上相出淮南。", "銀臺日月非虛過，金鼎功名得細參。", "從此與人爲雨露，應憐有客卧雲嵐。", "明朝起爲蒼生賀，旋著藤冠紫竹簪。"]'),
('6b7aa3de-3145-4461-9c3e-ba1c480a9756','同潘德久作明妃作  其一','姜夔','宋','宋诗','song-poetry','','[]','明妃未嫁時，滿宮妬蛾眉。',24,'全唐诗/poet.song.173000.json','["明妃未嫁時，滿宮妬蛾眉。", "一朝辭玉陛，人人淚雙垂。"]'),
('97c45d2b-4228-4f51-9bbe-87bd8e8cc8f1','同潘德久作明妃作  其二','姜夔','宋','宋诗','song-poetry','','[]','年年心隨雁，日日穹廬中。',24,'全唐诗/poet.song.173000.json','["年年心隨雁，日日穹廬中。", "遥見沙上月，忽憶建章宮。"]'),
('d48b9cf2-17d3-4f21-a5a0-b3e263d1f253','同潘德久作明妃作  其三','姜夔','宋','宋诗','song-poetry','','[]','身同漢使來，不同漢使歸。',24,'全唐诗/poet.song.173000.json','["身同漢使來，不同漢使歸。", "雖爲胡中婦，只著漢家衣。"]'),
('9441b1d1-cbc5-49d4-9b38-af354090fa71','烏夜啼','姜夔','宋','宋诗','song-poetry','','[]','老烏棲棲飛且號，晨來枝上啄楮桃。',128,'全唐诗/poet.song.173000.json','["老烏棲棲飛且號，晨來枝上啄楮桃。", "楮桃已空楮葉死，猶啄枯枝覓蟲蟻。", "老烏賦分何其貧，未啼已被鄰公嗔。", "吁嗟老烏不自省，牆頭屋上紛成羣。", "吳中貴遊重鸚鵡，千金遠致能言語。", "花底紅絛鄭袖擎，盤中碧果秦宮取。", "天生靈物得人憐，過者須來鸚鵡邊。", "老烏事事無足錄，人間猶傳夜啼曲。"]'),
('ad74b74c-300a-4db2-823b-d027e2e0a5fc','壽朴翁','姜夔','宋','宋诗','song-poetry','','[]','與師同月不同年，歸墨歸儒各自緣。',32,'全唐诗/poet.song.173000.json','["與師同月不同年，歸墨歸儒各自緣。", "想得山中無壽酒，但携茶到菊花前。"]'),
('daf6e540-a987-4e2e-bff6-3e170cbfa4af','湖上寓居雜詠  其一','姜夔','宋','宋诗','song-poetry','','[]','荷葉披披一浦涼，青蘆奕奕夜吟商。',32,'全唐诗/poet.song.173000.json','["荷葉披披一浦涼，青蘆奕奕夜吟商。", "平生最識江湖味，聽得秋聲憶故鄉。"]'),
('9f69477b-4a83-41d8-92ae-4e859ca38da9','湖上寓居雜詠  其二','姜夔','宋','宋诗','song-poetry','','[]','湖上風恬月澹時，卧看雲影入玻璃。',32,'全唐诗/poet.song.173000.json','["湖上風恬月澹時，卧看雲影入玻璃。", "輕舟忽向窗邊過，摇動青蘆一兩枝。"]'),
('73feeec3-8a14-48c4-bebd-6998093ea440','湖上寓居雜詠  其三','姜夔','宋','宋诗','song-poetry','','[]','秋雲低結亂山愁，千頃銀波凝不流。',32,'全唐诗/poet.song.173000.json','["秋雲低結亂山愁，千頃銀波凝不流。", "堤畔畫船堤上馬，綠楊風裏兩悠悠。"]'),
('7a8c7100-9e9b-4b1d-b763-21d4d6684aea','湖上寓居雜詠  其四','姜夔','宋','宋诗','song-poetry','','[]','處處虛堂望眼寬，荷花荷葉過欄干。',32,'全唐诗/poet.song.173000.json','["處處虛堂望眼寬，荷花荷葉過欄干。", "遊人去後無歌鼓，白水青山生晚寒。"]'),
('2b9b6410-9a3e-449b-953c-0d37bfa2bd45','湖上寓居雜詠  其五','姜夔','宋','宋诗','song-poetry','','[]','輦路垂楊兩行栽，苑門秋水欲平階。',32,'全唐诗/poet.song.173000.json','["輦路垂楊兩行栽，苑門秋水欲平階。", "朝朝南望宮雲起，白鳥一雙山下來。"]'),
('98e78749-825c-4df0-a3b4-e93738995b61','湖上寓居雜詠  其六','姜夔','宋','宋诗','song-poetry','','[]','微波衝得綠萍開，數點青青粘石階。',32,'全唐诗/poet.song.173000.json','["微波衝得綠萍開，數點青青粘石階。", "綠葑自來還自去，來時須載白鷗來。"]'),
('6ea3638a-e85b-47da-9e58-8bfcc29a3f45','湖上寓居雜詠  其七','姜夔','宋','宋诗','song-poetry','','[]','布衣何用揖王公，歸向蘆根濯軟紅。',32,'全唐诗/poet.song.173000.json','["布衣何用揖王公，歸向蘆根濯軟紅。", "自覺此心無一事，小魚跳出綠萍中。"]'),
('1d50c2af-4165-4168-96d9-7ff5eb88bfe2','湖上寓居雜詠  其八','姜夔','宋','宋诗','song-poetry','','[]','囊封萬字總空言，露滴桐枝欲斷絃。',32,'全唐诗/poet.song.173000.json','["囊封萬字總空言，露滴桐枝欲斷絃。", "時事悠悠吾亦嬾，卧看秋水浸山煙。"]'),
('1d80b504-67c0-47f8-9dc7-dc1fc36ce110','湖上寓居雜詠  其九','姜夔','宋','宋诗','song-poetry','','[]','苑牆曲曲柳冥冥，人靜山空見一燈。',32,'全唐诗/poet.song.173000.json','["苑牆曲曲柳冥冥，人靜山空見一燈。", "荷葉似雲香不斷，小船摇曳入西陵。"]'),
('b0ebd830-de7d-4341-8719-4e13b30cbb56','湖上寓居雜詠  其一○','姜夔','宋','宋诗','song-poetry','','[]','處士風流不並時，移家相近若依依。',32,'全唐诗/poet.song.173000.json','["處士風流不並時，移家相近若依依。", "夜凉一舸孤山下，林黑草深螢火飛。"]'),
('f42cf70e-2a65-4ce1-9741-165ff0297fd7','湖上寓居雜詠  其一一','姜夔','宋','宋诗','song-poetry','','[]','卧榻看山綠漲天，角門長泊釣魚船。',32,'全唐诗/poet.song.173000.json','["卧榻看山綠漲天，角門長泊釣魚船。", "而今漸欲拋塵事，未了菟裘一悵然。"]'),
('d6816bce-97c0-4986-8c15-c6c689b168d2','湖上寓居雜詠  其一二','姜夔','宋','宋诗','song-poetry','','[]','釣窗不忍見南山，下有三雛骨未寒。',32,'全唐诗/poet.song.173000.json','["釣窗不忍見南山，下有三雛骨未寒。", "惆悵古今同此味，二陵風雨晉師還。"]'),
('51c86882-4328-43e3-ba92-3bb44f26abd2','湖上寓居雜詠  其一三','姜夔','宋','宋诗','song-poetry','','[]','柳下軒窗枕水開，畫船忽載故人來。',32,'全唐诗/poet.song.173000.json','["柳下軒窗枕水開，畫船忽載故人來。", "與君同過西城路，却指煙波獨自回。"]'),
('a92b0180-7fa0-48ad-bb66-51905a74a474','湖上寓居雜詠  其一四','姜夔','宋','宋诗','song-poetry','','[]','指點移舟著柳堤，美人相顧復相携。',32,'全唐诗/poet.song.173000.json','["指點移舟著柳堤，美人相顧復相携。", "上橋更覺秋香重，花在西陵小苑西。"]'),
('d11e7623-b166-4f7c-abce-11354ab0d146','坐上和約齋','姜夔','宋','宋诗','song-poetry','','[]','句入冰輪冷，愁因玉宇開。',48,'全唐诗/poet.song.173000.json','["句入冰輪冷，愁因玉宇開。", "可無如此客，猶恨不能杯。", "好句長城立，寒鴉結陣來。", "箜篌莫停手，拚却斷腸回。"]'),
('6371e5b0-b64f-45c2-9ea9-93fed81fb754','出北關','姜夔','宋','宋诗','song-poetry','','[]','吳兒臨水宅，四面見行舟。',48,'全唐诗/poet.song.173000.json','["吳兒臨水宅，四面見行舟。", "蒲葉浸鵝項，楊枝蘸馬頭。", "年年人去國，夜夜月窺樓。", "傳語城中客，功名半是愁。"]'),
('3d477441-68ac-49d6-a38c-96d08013ee50','平甫見招不欲往  其一','姜夔','宋','宋诗','song-poetry','','[]','老去無心聽管絃，病來杯酒不相便。',32,'全唐诗/poet.song.173000.json','["老去無心聽管絃，病來杯酒不相便。", "人生難得秋前雨，乞我虛堂自在眠。"]'),
('50385ebb-d0cb-459e-a5e4-d175e9f6d68b','平甫見招不欲往  其二','姜夔','宋','宋诗','song-poetry','','[]','樓閣萬重秋雨裏，峰巒四合暮潮邊。',32,'全唐诗/poet.song.173000.json','["樓閣萬重秋雨裏，峰巒四合暮潮邊。", "鳳城今夕涼如水，多少人家試管絃。"]'),
('031135ad-6172-4780-9114-131d4a05759f','三高祠','姜夔','宋','宋诗','song-poetry','','[]','越國霸來頭已白，洛京歸後夢猶驚。',32,'全唐诗/poet.song.173000.json','["越國霸來頭已白，洛京歸後夢猶驚。", "沉思只羨天隨子，蓑笠寒江過一生。"]'),
('dbe3625a-d4b9-4fb1-8634-bf50aaacb356','過桐廬','姜夔','宋','宋诗','song-poetry','','[]','橫看山色仰看雲，十幅風帆不藉人。',32,'全唐诗/poet.song.173000.json','["橫看山色仰看雲，十幅風帆不藉人。", "記取合江江畔樹，他年此處好垂綸。"]'),
('23e6a851-47b0-4c48-9265-00ab7a284adc','登烏石寺觀張魏公劉安成岳武穆留題劉云侍兒意真奉命題記','姜夔','宋','宋诗','song-poetry','','[]','諸老凋零極可哀，尚留名字壓崔嵬。',32,'全唐诗/poet.song.173000.json','["諸老凋零極可哀，尚留名字壓崔嵬。", "劉郎可是疎文墨，幾點烟脂污綠苔。"]'),
('fed36439-230b-4e61-9a7d-7a26f2d560fe','過垂虹','姜夔','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u884c\u821f"]','自作新詞韵最嬌，小紅低唱我吹簫。',32,'全唐诗/poet.song.173000.json','["自作新詞韵最嬌，小紅低唱我吹簫。", "曲終過盡松陵路，回首煙波十四橋。"]'),
('6be36f8d-0b2b-44ae-98f7-a7bca092d2a4','訪費山人','姜夔','宋','宋诗','song-poetry','','[]','稻叢茁茁欲齊肩，楊柳僛僛不蔽蟬。',32,'全唐诗/poet.song.173000.json','["稻叢茁茁欲齊肩，楊柳僛僛不蔽蟬。", "忽憶石頭城下路，槿花斜壓釣魚船。"]'),
('52ce500e-7ffa-4575-87e4-34a201955a4d','牛渚','姜夔','宋','宋诗','song-poetry','','[]','牛渚磯邊渺渺秋，笛聲吹月下中流。',32,'全唐诗/poet.song.173000.json','["牛渚磯邊渺渺秋，笛聲吹月下中流。", "西風不識張京兆，畫得蛾眉如許愁。"]'),
('70326766-0d3f-414c-a7d9-ef947fe1379d','武康丞宅同朴翁詠牽牛','姜夔','宋','宋诗','song-poetry','','[]','青花綠葉上疎籬，別有長條竹尾垂。',32,'全唐诗/poet.song.173000.json','["青花綠葉上疎籬，別有長條竹尾垂。", "老覺淡粧差有味，滿身秋露立多時。"]'),
('ef2b7485-6d5b-4020-9081-983efad06add','朴公悼牽牛甚奇余亦作','姜夔','宋','宋诗','song-poetry','','[]','不見青青繞竹生，西風籬落抱枯藤。',32,'全唐诗/poet.song.173000.json','["不見青青繞竹生，西風籬落抱枯藤。", "道人一任空花過，愁殺山陰覓句僧。"]'),
('45cab6e7-93e6-4d93-9082-0cb6b7ee63d3','春日書懷四首  其一','姜夔','宋','宋诗','song-poetry','','[]','九真何蒼蒼，乃在清漢尾。',72,'全唐诗/poet.song.173000.json','["九真何蒼蒼，乃在清漢尾。", "衡茅依草木，念遠獨伯姊。", "春來衆芳滋，春去衆芳委。", "兄弟各天涯，啼鴂見料理。", "漢江出巨魚，風雷入驅使。", "安得挾我輈，西征二千里。"]'),
('ada1a9b8-28fc-4137-ab92-d6050ebdbbdf','春日書懷四首  其二','姜夔','宋','宋诗','song-poetry','','[]','春雲驛路暗，遊子眇歸程。',48,'全唐诗/poet.song.173000.json','["春雲驛路暗，遊子眇歸程。", "永懷故山下，風雨悲柏庭。", "翁仲不解語，幽鳥時時鳴。", "人家插垂柳，客裏又清明。"]'),
('0078aefe-9c22-469d-a003-f674471c33c4','春日書懷四首  其三','姜夔','宋','宋诗','song-poetry','','[]','垂楊大別寺，春草郎官湖。',132,'全唐诗/poet.song.173000.json','["垂楊大別寺，春草郎官湖。", "家巷有石友，合并不待呼。", "瘦藤倚花樹，花片藉玉壺。", "老鄭談絕妙，辛楊句敷腴。", "平生子姚子，貌古心甚儒。", "時邀野僧語，間與琴工俱。", "酒闌興未了，左轉城南隅。", "大江圍楚碧，煙水入玄虛。", "留落不自恨，惟嗟故人疎。", "一月三見夢，夢中相與娛。", "日日潮風起，悵望武昌魚。"]'),
('fef991b8-b7c4-47d5-aeb5-c987792f8223','春日書懷四首  其四','姜夔','宋','宋诗','song-poetry','','[]','武昌十萬家，落日紫煙低。',72,'全唐诗/poet.song.173000.json','["武昌十萬家，落日紫煙低。", "亭亭頭陀塔，高處白鳥棲。", "白鳥忽飛去，春山空四圍。", "南樓有佳人，再召且再辭。", "閉門課文事，攖物深天機。", "斯人不可致，白鳥會來歸。"]'),
('e0ffdefb-1d6b-4624-b938-3d5ecf125612','過德清  其一','姜夔','宋','宋诗','song-poetry','','[]','木末誰家縹緲亭，畫堂臨水更虛明。',32,'全唐诗/poet.song.173000.json','["木末誰家縹緲亭，畫堂臨水更虛明。", "經過此處無相識，塔下秋雲爲我生。"]'),
('9b5f34b3-1a50-4a33-8f3d-c4481c9fcdf4','過德清  其二','姜夔','宋','宋诗','song-poetry','','[]','溪上佳人看客舟，舟中行客思悠悠。',32,'全唐诗/poet.song.173000.json','["溪上佳人看客舟，舟中行客思悠悠。", "煙波漸遠橋東去，猶見闌干一點愁。"]'),
('b1524f7f-ce9f-4be1-a11d-f4b4e1d33213','予居苕溪上與白石洞天爲鄰潘德久字余曰白石道人且以詩見畀其詞曰人間官爵似樗蒲采到枯松亦大夫白石道人新拜號斷無繳駁任稱呼予以長句報貺','姜夔','宋','宋诗','song-poetry','','[]','南山仙人何所食，夜夜山中煮白石。',104,'全唐诗/poet.song.173000.json','["南山仙人何所食，夜夜山中煮白石。", "世人喚作白石仙，一生費齒不費錢。", "仙人食罷腹便便，七十二峰生肺肝。", "真租只在南山南，我欲從之不憚遠。", "無方煮石何由軟。", "佳名錫我何敢辭，但愁自比長苦饑。", "囊中只有轉庵詩，便當掬水三嚥之。"]'),
('4558cc0a-c1d7-4df6-8fa0-d5fee85d8246','箜篌引','姜夔','宋','宋诗','song-poetry','','[]','箜篌且勿彈，老夫不可聽。',96,'全唐诗/poet.song.173000.json','["箜篌且勿彈，老夫不可聽。", "河邊風浪起，亦作箜篌聲。", "古人抱恨死，今人抱恨生。", "南鄰賣妻者，秋夜難爲情。", "長安買歌舞，半是良家婦。", "主人雖愛憐，賤妾那久住。", "緣貧來賣身，不緣觸夫怒。", "日日登高樓，悵望宮南樹。"]'),
('d5908b40-8cca-4d3f-a628-4e6a3ae170fd','陳君玉以小集見歸用余還誠齋朝天續集韵作七字夔報貺','姜夔','宋','宋诗','song-poetry','','[]','筆陳無功汗左輪，而今老去不能軍。',64,'全唐诗/poet.song.173000.json','["筆陳無功汗左輪，而今老去不能軍。", "水邊白鳥閑於我，窗外梅花疑是君。", "欲向江湖行此話，可無朋友託斯文。", "新篇大是相料理，因憶西山揚子雲。"]'),
('a6097f42-8320-4dea-b2e8-cccbaff74828','丁巳七月望湖上書事','姜夔','宋','宋诗','song-poetry','','[]','白天碎碎如析綿，黑天昧昧如陳玄。',240,'全唐诗/poet.song.173000.json','["白天碎碎如析綿，黑天昧昧如陳玄。", "白黑破處青天出，海月飛來光尚濕。", "是夜太史奏月蝕，三家各自矜算術。", "或云七分或食既，或云食晝不在夕。", "上令御史登吳山，下視海門監月出。", "年來曆失無人修，三家之說誰爲優。", "乍如破鏡光炯炯，漸若小兒初食餠。", "時方下令嚴禁銅，破鏡何爲來海東。", "天邊有餠不可食，聞說饑民滿淮北。", "是鏡是餠且勿論，須臾還我黄金盆。", "金盆當空四山靜，平波倒浸雲天影。", "下連八表共此光，上接銀河通一冷。", "御史歸家太史眠，人間不聞鍾鼓傳。", "白石道人呼釣船，一瓢欲酌湖中天。", "荷葉擺頭君睡去，西風急送敲窗句。"]'),
('2ff2d252-491e-4dbd-bdd9-ee34fb921b31','項里項王之里也在山陰西南二十餘里地多楊梅苔梅皆妙天下王性之賦項里楊梅云只今枝頭萬顆紅猶似咸陽三月火予近得苔梅一枝古怪特甚爲作七言','姜夔','宋','宋诗','song-poetry','','[]','舊國婆娑幾樹梅，將軍逐鹿未歸來。',32,'全唐诗/poet.song.173000.json','["舊國婆娑幾樹梅，將軍逐鹿未歸來。", "江東父老空相憶，枝上年年長綠苔。"]'),
('a4521e51-782c-409c-9329-c32c424b3523','寄田郎','姜夔','宋','宋诗','song-poetry','','[]','楚楚田郎亦大奇，少年風味我曾知。',64,'全唐诗/poet.song.173000.json','["楚楚田郎亦大奇，少年風味我曾知。", "春城寒食誰相伴，夜月梨花有所思。", "剪燭屢呼金鑿落，倚窗閑品玉參差。", "含情不擬逢人說，鸚鵡能歌自作詞。"]'),
('8660ee13-1ae3-4d06-94ef-31d06c95210f','待千巖  其一','姜夔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','搴裳望洞庭，眼過天一角。',48,'全唐诗/poet.song.173000.json','["搴裳望洞庭，眼過天一角。", "初別未甚愁，別久今始覺。", "作牋非無筆，寒雁不肯落。", "蘆花待挐音，怪底北風惡。"]'),
('c1d97f89-1965-4a00-96f7-ed20daad9449','待千巖  其二','姜夔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','若人金石心，試命洞庭浪。',48,'全唐诗/poet.song.173000.json','["若人金石心，試命洞庭浪。", "傳聞下巴陵，瀝酒喜無恙。", "我行丹楓林，屢騁白蘋望。", "烏鵲不可嗔，論功當坐上。"]'),
('d313ca8d-7b44-4f42-a060-74ed3db723e6','古樂府  其一','姜夔','宋','宋诗','song-poetry','','[]','裁衣贈所歡，曲領再三安。',24,'全唐诗/poet.song.173000.json','["裁衣贈所歡，曲領再三安。", "歡出無人試，閨中自著看。"]'),
('39509354-5da8-469f-8d43-519b0fcbc07d','古樂府  其二','姜夔','宋','宋诗','song-poetry','','[]','甚欲逐郎行，畏人笑無媒。',24,'全唐诗/poet.song.173000.json','["甚欲逐郎行，畏人笑無媒。", "日日東風起，西家桃李開。"]'),
('c9c5ef75-36db-4c8f-80af-35180bb6c657','古樂府  其三','姜夔','宋','宋诗','song-poetry','','[]','令我歌一曲，曲終郎見留。',24,'全唐诗/poet.song.173000.json','["令我歌一曲，曲終郎見留。", "萬一不當意，翻作平生羞。"]'),
('ef1e9882-0ecf-4172-a35a-2b614c71f07f','賦千巖曲水','姜夔','宋','宋诗','song-poetry','','[]','紅雨灑溪流，下瀨仍小駐。',36,'全唐诗/poet.song.173000.json','["紅雨灑溪流，下瀨仍小駐。", "魚隊獵殘香，故故作吞吐。", "老子把一盃，微風忽吹去。"]'),
('56adeb5e-d8b3-4be8-9d7d-67e07910993f','李陵臺','姜夔','宋','宋诗','song-poetry','','[]','李陵歸不得，高築望鄉臺。',36,'全唐诗/poet.song.173000.json','["李陵歸不得，高築望鄉臺。", "長安一萬里，鴻雁隔年回。", "望望雖不見，時時一上來。"]'),
('34781540-6e58-4a3d-bb1b-256efd12677d','送王德和提舉淮東','姜夔','宋','宋诗','song-poetry','','[]','京塵吹帽汗淋衣，相見頻年只道歸。',64,'全唐诗/poet.song.173000.json','["京塵吹帽汗淋衣，相見頻年只道歸。", "省裏移文那得了，家邊持節未爲非。", "煮乾碧海知誰用，割盡黄雲尚告饑。", "可得不爲根本計，秋風還見雁南飛。"]'),
('849a39a6-a458-4006-b711-94ad70f39ffe','寄時父','姜夔','宋','宋诗','song-poetry','','[]','遲君日日數歸程，到得君歸我已行。',64,'全唐诗/poet.song.173000.json','["遲君日日數歸程，到得君歸我已行。", "一路好山思共看，半年有酒不同傾。", "吾儕政坐清貧累，各自而今白髮生。", "人物眇然須强飯，天工應不負才名。"]'),
('d14ecdf1-ebbf-4e2b-ae26-246f26c83ec2','雪中六解  其一','姜夔','宋','宋诗','song-poetry','','[]','塞草汀雲護玉鞍，連天花落路漫漫。',32,'全唐诗/poet.song.173000.json','["塞草汀雲護玉鞍，連天花落路漫漫。", "如今却憶當時健，下馬題詩不道寒。"]'),
('61749276-d7af-41e3-9f31-4c8c659cfca5','雪中六解  其二','姜夔','宋','宋诗','song-poetry','','[]','黄鶴磯邊晚渡時，柳花風急片帆飛。',32,'全唐诗/poet.song.173000.json','["黄鶴磯邊晚渡時，柳花風急片帆飛。", "一聲長笛魚龍舞，白浪如山不肯歸。"]'),
('c10a21c4-2296-4736-9c1f-2586b7666c33','雪中六解  其三','姜夔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','萬馬行空轉屋簷，高寒屢索酒杯添。',32,'全唐诗/poet.song.173000.json','["萬馬行空轉屋簷，高寒屢索酒杯添。", "故人家住吳山上，借得西湖自卷簾。"]'),
('7cdcd0d8-2afd-4548-ab07-090db0f2cca2','雪中六解  其四','姜夔','宋','宋诗','song-poetry','','[]','曾泛扁舟詣石湖，恍然坐我范寬圖。',32,'全唐诗/poet.song.173000.json','["曾泛扁舟詣石湖，恍然坐我范寬圖。", "天寒遠掛一行雁，三十六峰生玉壺。"]'),
('1accd2bd-35fe-4f1b-88c8-ca0a0bd72f01','雪中六解  其五','姜夔','宋','宋诗','song-poetry','','[]','萬壑千巖一樣寒，城中別有玉龍蟠。',32,'全唐诗/poet.song.173000.json','["萬壑千巖一樣寒，城中別有玉龍蟠。", "舊人秉興扁舟處，今日詩仙戴笠看。"]'),
('3dcec82d-6fe3-4f9a-8c35-36942791eaca','雪中六解  其六','姜夔','宋','宋诗','song-poetry','','[]','沉香火裏笙簫合，煖玉鞍邊雉兔空。',32,'全唐诗/poet.song.173000.json','["沉香火裏笙簫合，煖玉鞍邊雉兔空。", "辦得煎茶有驕色，先生只合作詩窮。"]'),
('b4ec49d2-f050-49ca-8837-04e1dc3295fe','送李萬頃','姜夔','宋','宋诗','song-poetry','','[]','猛相思裏得君來，政喜歡時却便回。',64,'全唐诗/poet.song.173000.json','["猛相思裏得君來，政喜歡時却便回。", "別路苦無青柳折，到家應有小桃開。", "起居五馬兼堂上，問訊千巖及阿灰。", "兒女癡頑夫婦健，漂零何日共尊罍。"]'),
('b5fd05b8-70c1-4b69-80e2-3ea3b789e607','送陳敬甫','姜夔','宋','宋诗','song-poetry','','[]','十年所聞溢吾耳，去年誦君書一紙。',104,'全唐诗/poet.song.173000.json','["十年所聞溢吾耳，去年誦君書一紙。", "古人三語得奇士，况此磊落數百字。", "相逢千巖萬壑裏，有客如君請兄事。", "才高自古人所忌，論高不售反驚世，好詩取客如券契。", "我無三者猶至是，如君之貧不可避。", "如君之貧不可避，呼舟徑渡寒潮外。"]'),
('b625d563-48c7-49de-8608-dd538d46888f','越中士女春遊','姜夔','宋','宋诗','song-poetry','','[]','秦山越樹兩依依，閑倚闌干看落暉。',32,'全唐诗/poet.song.173000.json','["秦山越樹兩依依，閑倚闌干看落暉。", "楊柳梢頭春又暗，玉簫聲裏夜遊歸。"]'),
('621d624a-e7d7-4562-b74d-bd02824cae3b','送彭仲訥往合肥三首  其一','姜夔','宋','宋诗','song-poetry','','[]','壯志只便鞍馬上，客夢長到江淮間。',32,'全唐诗/poet.song.173000.json','["壯志只便鞍馬上，客夢長到江淮間。", "誰能辛苦運河裏，夜與商人爭往還。"]'),
('958f95d4-9303-41c2-bd0d-02d8fe12ff3f','送彭仲訥往合肥三首  其二','姜夔','宋','宋诗','song-poetry','','[]','我家曾住赤欄橋，鄰里相過不寂寥。',32,'全唐诗/poet.song.173000.json','["我家曾住赤欄橋，鄰里相過不寂寥。", "君若到時秋已半，西風門巷柳蕭蕭。"]'),
('68db2aca-b24d-4034-b246-65d96c85ebd1','送彭仲訥往合肥三首  其三','姜夔','宋','宋诗','song-poetry','','[]','小簾燈火屢題詩，回首青山失後期。',32,'全唐诗/poet.song.173000.json','["小簾燈火屢題詩，回首青山失後期。", "未老劉郎定重到，煩君說與故人知。"]'),
('338a2245-0263-4695-80bc-33e84892dfdb','下孤城','姜夔','宋','宋诗','song-poetry','','[]','人家多住竹籬中，楊柳疎疎尚带風。',32,'全唐诗/poet.song.173000.json','["人家多住竹籬中，楊柳疎疎尚带風。", "記得下孤城下路，白雲依舊兩三篷。"]'),
('450ae7a4-d48d-4ee8-bdfb-024194677c04','平甫放三十二鷗于吳松余不及與盟','姜夔','宋','宋诗','song-poetry','','[]','橋下松陵綠浪橫，來遲不與白鷗盟。',32,'全唐诗/poet.song.173000.json','["橋下松陵綠浪橫，來遲不與白鷗盟。", "知君久對青山立，飛盡梨花好句成。"]'),
('9298427a-6dca-4e38-91c1-98e65aad8697','蕭山','姜夔','宋','宋诗','song-poetry','','[]','歸心已逐晚雲輕，又見越中長短亭。',32,'全唐诗/poet.song.173000.json','["歸心已逐晚雲輕，又見越中長短亭。", "十里水邊山下路，桃花無數麥青青。"]'),
('c3445604-0367-4705-a571-b3c44e547cbc','生雲軒','姜夔','宋','宋诗','song-poetry','','["\u592a\u6e56"]','在山長與雲同齋，出山憶雲雲不來。',96,'全唐诗/poet.song.173000.json','["在山長與雲同齋，出山憶雲雲不來。", "千金買得太湖石，數峰相對寒崔嵬。", "朝來忽覺青苔濕，靉靉如炊石間出。", "白雲何處不相逢，却怪年年枉相憶。", "王郎胸中橫一丘，在山出山雲與遊。", "更呼白面老居士，來倚雲根吟七字。"]'),
('81e65f39-9dca-4a19-ac07-ab63a049f5da','戊午春帖子','姜夔','宋','宋诗','song-poetry','','[]','晴窗日日擬雕蟲，惆悵明時不易逢。',32,'全唐诗/poet.song.173000.json','["晴窗日日擬雕蟲，惆悵明時不易逢。", "二十五絃人不識，淡黄楊柳舞春風。"]'),
('fb18e164-e95b-46f4-95d3-e83eee621fb9','送項平甫倅池陽','姜夔','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71", "\u897f\u6e56"]','項侯聲名天宇窄，與君俱是荆湖客。',227,'全唐诗/poet.song.173000.json','["項侯聲名天宇窄，與君俱是荆湖客。", "向來相聞不相值，長安城中乃相識。", "論文要得文中天，邯鄲學步終不然。", "知君筆墨與性合，妙處突過蘇李前。", "我如切切秋蟲語，自詭平生用心苦。", "神凝或與元氣接，屢舉似君君亦許。", "西湖一曲古牆陰，清坐論詩夜向深。", "見謂人間有公等，不知來者不如今。", "乾坤雖大知者少，君不見古人拙處今人巧。", "我徂山林口掛壁，如君合救狂瀾倒。", "石渠春水綠泱泱，閣下無人白日長。", "萬里江湖入歸夢，子雲不願校書郎。", "九華山色梅根渡，半日風帆即秋浦。", "六條察吏安用許，幸有千巖作詩侶。"]'),
('185f818b-a891-49c5-990e-f2a0b3402cad','偶題','姜夔','宋','宋诗','song-poetry','','[]','阿八宮中酒未醒，天風吹髮夜泠泠。',32,'全唐诗/poet.song.173000.json','["阿八宮中酒未醒，天風吹髮夜泠泠。", "歸時只怕扶桑暖，赤脚橫騎太一鯨。"]'),
('f0018b6a-bda4-424f-aa9f-ddac38ae7bd3','陳日華侍兒讀書','姜夔','宋','宋诗','song-poetry','','[]','繹句尋章久未休，花房日晏不梳頭。',32,'全唐诗/poet.song.173000.json','["繹句尋章久未休，花房日晏不梳頭。", "誰教郎主能多事，乞與冥冥千古愁。"]'),
('47e3311e-0255-4c7f-99de-7d7805a4807b','女郎山','姜夔','宋','宋诗','song-poetry','','[]','不見郢中能賦客，可憐負此女郎山。',32,'全唐诗/poet.song.173000.json','["不見郢中能賦客，可憐負此女郎山。", "冰魂寂寞無歸處，獨宿鴛鴦沙水寒。"]'),
('ab7f1a9d-0b89-4012-bc1c-a96b9b15494f','金神夜獵圖二首  其一','姜夔','宋','宋诗','song-poetry','','[]','夜半金神羽獵，奔走山川百靈。',28,'全唐诗/poet.song.173000.json','["夜半金神羽獵，奔走山川百靈。", "雲氣旌旗來下，颯然已入青冥。"]'),
('b49ad934-d7e8-410f-b239-9937e2368b63','金神夜獵圖二首  其二','姜夔','宋','宋诗','song-poetry','','[]','後宮嬋娟玉女，自鞚八尺飛龍。',28,'全唐诗/poet.song.173000.json','["後宮嬋娟玉女，自鞚八尺飛龍。", "兩兩鳴鞭爭導，綠雲斜墜春風。"]'),
('9f68b356-4534-4c51-857e-bee6c6037672','書乞米帖後','姜夔','宋','宋诗','song-poetry','','[]','銀鈎鐵畫太師字，從人乞米亦可憐。',67,'全唐诗/poet.song.173000.json','["銀鈎鐵畫太師字，從人乞米亦可憐。", "五倉空虛胃神哭，竟日悄悄無炊煙。", "仙人留書說服氣，道士辟穀期引年。", "人生不食浪自苦，獨不見子桑鼓琴十日雨。"]'),
('6388ab9f-d853-43d9-96e5-d6130025739e','次韵鴛鴦梅  其一','姜夔','宋','宋诗','song-poetry','','[]','晴日小溪沙暖，春夢憐渠頸交。',28,'全唐诗/poet.song.173000.json','["晴日小溪沙暖，春夢憐渠頸交。", "只怕笛聲驚散，費人月詠風嘲。"]'),
('2e7a38f5-c9a6-47db-aaee-af938ecfec20','次韵鴛鴦梅  其二','姜夔','宋','宋诗','song-poetry','','[]','漠漠江南煙雨，于飛似報初春。',28,'全唐诗/poet.song.173000.json','["漠漠江南煙雨，于飛似報初春。", "折過女郎山下，料應愁殺佳人。"]'),
('aedc599e-979e-4856-8684-5d4e784f2abf','呈徐通仲兼簡仲錫通仲與誠齋爲鄉人近來赴調而誠齋去國又通仲久與千巖有苕霅之約而未至余挽通仲欲與同歸千巖故末章及之','姜夔','宋','宋诗','song-poetry','','["\u592a\u6e56"]','斯文準乾坤，作者難屈指。',180,'全唐诗/poet.song.173000.json','["斯文準乾坤，作者難屈指。", "我從李郎遊，知有徐孺子。", "春風橘洲前，白月太湖尾。", "懷哉來無期，玉唾炯在紙。", "去年識仲氏，何啻空谷喜。", "合并忽自天，傾倒見底裏。", "維君天下士，竹箭東南美。", "胡不在石渠，諸公當料理。", "千巖今林宗，泉石助風軌。", "示疾不下堂，有句高八米。", "此老筆硯交，誠齋古元禮。", "毫端洒秋露，去國詞愈偉。", "屬聞都門別，回首即桑梓。", "獨憐苕溪上，垂榻俟行李。", "煙波肯尋盟，歸棹爲君艤。"]'),
('595f26ba-7d17-4246-bc5d-36581e844c83','答沈器之二首  其一','姜夔','宋','宋诗','song-poetry','','[]','江漢乘流客，乾坤不繫舟。',48,'全唐诗/poet.song.173000.json','["江漢乘流客，乾坤不繫舟。", "玉琴虛素月，金劍落清秋。", "野鹿知隨草，饑鷹故上韝。", "風流大堤曲，一唱使人愁。"]'),
('92d5ae85-82db-4e25-ab07-5de2edc83c99','答沈器之二首  其二','姜夔','宋','宋诗','song-poetry','','["\u592a\u6e56"]','涉遠身良苦，登高望欲迷。',48,'全唐诗/poet.song.173000.json','["涉遠身良苦，登高望欲迷。", "試吟青玉案，不似白銅鞮。", "露下秋蟲怨，風高北馬嘶。", "槎頭有新味，人在太湖西。"]'),
('58a84f99-d90f-4b6b-9f39-fc490b55d41a','鈎雪亭','姜夔','宋','宋诗','song-poetry','','["\u601d\u5ff5", "\u5199\u4eba", "\u96ea", "\u5199\u96ea"]','闌干風冷雪漫漫，惆悵無人把釣竿。',32,'全唐诗/poet.song.173000.json','["闌干風冷雪漫漫，惆悵無人把釣竿。", "時有官船橋畔過，白鷗飛去落前灘。"]'),
('8e275112-6e64-4bdc-af0f-d0db16cf2106','馬上值牧兒','姜夔','宋','宋诗','song-poetry','','[]','馬背何如牛背，短衣落日空山。',28,'全唐诗/poet.song.173000.json','["馬背何如牛背，短衣落日空山。", "只麽身歸盤谷，未須名滿人間。"]'),
('b1812c47-eaf5-4c8b-872d-22f82c194192','契丹歌','姜夔','宋','宋诗','song-poetry','','[]','契丹家住雲沙中，耆車如水馬若龍。',192,'全唐诗/poet.song.173000.json','["契丹家住雲沙中，耆車如水馬若龍。", "春來草色一萬里，芍藥牡丹相間紅。", "大胡牽車小胡舞，彈胡琵琶調胡女。", "一春浪宕不歸家，自有穹廬障風雨。", "平沙軟草天鵝肥，胡兒千騎曉打圍。", "皂旗低昂圍漸急，驚作羊角凌空飛。", "海東健鶻健如許，韝上風生看一舉。", "萬里追奔未可知，劃見紛紛落毛羽。", "平章俊味天下無，年年海上驅群胡。", "一鵝先得金百兩，天使走送賢王廬。", "天鵝之飛鐵爲翼，射生小兒空看得。", "腹中驚怪有新薑，元是江南經宿食。"]'),
('b6698d6d-8f01-40d1-a5fe-d5dc77ca993b','綠萼梅','姜夔','宋','宋诗','song-poetry','','[]','黄雲承襪知何處，招得冰魂付北枝。',32,'全唐诗/poet.song.173000.json','["黄雲承襪知何處，招得冰魂付北枝。", "金谷樓高愁欲墜，斷腸誰把玉龍吹。"]'),
('6d724a09-125a-45be-81f3-b50e0c8b499c','次韵千巖雜謠','姜夔','宋','宋诗','song-poetry','','[]','平生中散七不堪，鳳麈時時伴燕談。',64,'全唐诗/poet.song.173000.json','["平生中散七不堪，鳳麈時時伴燕談。", "道士有神傳火棗，故人無字入雲藍。", "雨凉竹葉宜三酌，日落荷花倚半酣。", "極欲扁舟南蕩去，冷鷗輕燕略相諳。"]'),
('a5ec171d-ff9c-4059-bb5d-ece76e83d769','寄上鄭郎中','姜夔','宋','宋诗','song-poetry','','[]','梅根東望九華雲，中有風流衣繡人。',64,'全唐诗/poet.song.173000.json','["梅根東望九華雲，中有風流衣繡人。", "名下一生勞夢想，尊前數語倍情親。", "節旄在道催歸漢，花鳥留君且作春。", "見說祥風挾時雨，故園松菊亦精神。"]'),
('6899045f-499a-4c9d-80fc-51b91c38165d','送左真州還長沙','姜夔','宋','宋诗','song-poetry','','[]','吳兒牽挽醉蓴鱸，今日西歸略自如。',64,'全唐诗/poet.song.173000.json','["吳兒牽挽醉蓴鱸，今日西歸略自如。", "別路冷雲隨驛馬，望鄉喬木記吾廬。", "湘中花月偏憐酒，淮左兒童待擁車。", "凡我舊遊君更歷，橘洲相見訝無書。"]'),
('dc018ae7-6575-4d02-9d78-dd936d3fe27a','禽言如曰哥哥','姜夔','宋','宋诗','song-poetry','','[]','君不見苕溪西南石鼓山，鳥如鸜鵒啼其間。',126,'全唐诗/poet.song.173000.json','["君不見苕溪西南石鼓山，鳥如鸜鵒啼其間。", "土人相傳是阿弟，千呼萬喚云復還。", "身爲獨雁失儔侶，所愧鶺鴒圖急難。", "繞林哀哀訴明月，夜闌月落聲漸咽。", "天地闊遠兄不聞，蒼崖下淚山竹裂。", "豈無鴉舅與鵓姑，人各有心非友于，陟岡四顧空欷歔。", "君不見江南望夫誰家子，登山化石不得語。"]'),
('28524503-804c-47e5-8010-2747b76c9091','次韵誠齋送僕往見石湖長句','姜夔','宋','宋诗','song-poetry','','[]','客來讀賦作雌蜺，平生未聞衡說詩。',129,'全唐诗/poet.song.173000.json','["客來讀賦作雌蜺，平生未聞衡說詩。", "省中詩人官事了，狎鷗入夢心無機。", "韵高落落懸清月，鏗鏘妙語春冰裂。", "一自長安識子雲，三歎郢中無白雪。", "范公蕭爽思出塵，有客如此渠不貧。", "堂堂五字作城守，平章勁敵君在口。", "二公句法妙萬夫，西罩來橐中藏魯璵。", "只今擊節烏棲曲，不愧當年賀鑑湖。"]'),
('f53475b3-6927-4c18-a3f6-74a4c42c5ca9','與和甫時甫分題畫卷夔得剡溪圖','姜夔','宋','宋诗','song-poetry','','[]','枯槎啅乾鵲，交臂失夫君。',24,'全唐诗/poet.song.173000.json','["枯槎啅乾鵲，交臂失夫君。", "柰此一尊酒，憑高空水雲。"]'),
('f82c8877-5e0b-4983-9ee4-717b2f7a874a','東堂聯句','姜夔','宋','宋诗','song-poetry','','[]','金風凉夜深，吹我蕭蕭髮。',24,'全唐诗/poet.song.173000.json','["金風凉夜深，吹我蕭蕭髮。", "起折丹桂枝，驚落花上月。"]'),
('634a0089-0872-4a7f-a9fd-c128d816f5e7','次韵武伯','姜夔','宋','宋诗','song-poetry','','[]','楊柳風微約暮寒，野禽容與只波間。',32,'全唐诗/poet.song.173000.json','["楊柳風微約暮寒，野禽容與只波間。", "道人心性如天馬，可愛青絲十二閑。"]'),
('910a29a0-b37b-4e99-9250-b10ca5ec445c','觀燈口號  其一','姜夔','宋','宋诗','song-poetry','','[]','世間形象盡成燈，烘火旋沙巧思生。',32,'全唐诗/poet.song.173000.json','["世間形象盡成燈，烘火旋沙巧思生。", "列肆又多看不遍，遊人一一把燈行。"]'),
('daea8094-bed6-40f8-b8ba-76a466ce9365','觀燈口號  其二','姜夔','宋','宋诗','song-poetry','','[]','市樓歌鼓太諠譁，燈若連珠照萬家。',32,'全唐诗/poet.song.173000.json','["市樓歌鼓太諠譁，燈若連珠照萬家。", "太守令嚴君莫舞，遊人空戴玉梅花。"]'),
('3f4f2ee2-7795-44f2-b9ae-431bdbe10248','觀燈口號  其三','姜夔','宋','宋诗','song-poetry','','[]','遊人總戴孟家蟬，爭托星毬萬眼圓。',32,'全唐诗/poet.song.173000.json','["遊人總戴孟家蟬，爭托星毬萬眼圓。", "閙裏傳呼大官過，後車多少盡嬋娟。"]'),
('cca7b342-2aaa-4e72-8944-56ef831355f3','觀燈口號  其四','姜夔','宋','宋诗','song-poetry','','[]','花帽籠頭幾歲兒，女兒學著內人衣。',32,'全唐诗/poet.song.173000.json','["花帽籠頭幾歲兒，女兒學著內人衣。", "燈前月下無歸路，不到天明亦不歸。"]'),
('6f0b4ec9-475e-48c4-8fa9-5cee27630638','觀燈口號  其五','姜夔','宋','宋诗','song-poetry','','[]','好燈須買不論錢，別有玻璃價百千。',32,'全唐诗/poet.song.173000.json','["好燈須買不論錢，別有玻璃價百千。", "教下貴人多預賞，買時長在一陽前。"]'),
('0ce8e612-e37e-4c2e-8209-c62e6b91b3be','觀燈口號  其六','姜夔','宋','宋诗','song-poetry','','[]','珠絡玻璃到地垂，鳳頭銜带玉交枝。',32,'全唐诗/poet.song.173000.json','["珠絡玻璃到地垂，鳳頭銜带玉交枝。", "君王不賞無人進，天竺堂深夜雨時。"]'),
('1b678369-39fb-4c3b-b6f7-6b84ecc412c3','觀燈口號  其七','姜夔','宋','宋诗','song-poetry','','[]','紛紛鐵馬小回旋，幻出曹公大戰年。',32,'全唐诗/poet.song.173000.json','["紛紛鐵馬小回旋，幻出曹公大戰年。", "若使英雄知□事，不教兒女戲燈前。"]'),
('fa2c159e-d671-4ca8-8b72-f2576771d40b','觀燈口號  其八','姜夔','宋','宋诗','song-poetry','','[]','貴客鈎簾看御街，市中珍品一□□。',32,'全唐诗/poet.song.173000.json','["貴客鈎簾看御街，市中珍品一□□。", "簾前花架無行路，不得金錢不肯回。"]'),
('181d3b4d-8a2f-433c-a0da-b6949a10ef8c','觀燈口號  其九','姜夔','宋','宋诗','song-poetry','','[]','修內司人偏戲鼓，輦官營裏獨燒燈。',32,'全唐诗/poet.song.173000.json','["修內司人偏戲鼓，輦官營裏獨燒燈。", "春風到處皆君賜，金柳絲絲滿鳳城。"]'),
('3c3670eb-c9a1-44b6-942b-c9d5a85e46ba','觀燈口號  其一○','姜夔','宋','宋诗','song-poetry','','[]','正好嬉遊天作魔，翠裙無奈雨沾何。',32,'全唐诗/poet.song.173000.json','["正好嬉遊天作魔，翠裙無奈雨沾何。", "御街暗裏無燈火，處處但聞樓上歌。"]'),
('64c5bafc-4a77-46ad-8a76-d5bfa1896e3c','和轉庵丹桂韵','姜夔','宋','宋诗','song-poetry','','[]','野人復何知，自謂山澤好。',96,'全唐诗/poet.song.173000.json','["野人復何知，自謂山澤好。", "來裨奉常議，識笳鼓羽葆。", "誰憐老垂垂，却入閙浩浩。", "營巢猶是寓，學圃何不早。", "淮桂手所植，漢甕躬自抱。", "花開不忍出，花落不忍掃。", "佳客夜深來，清尊月中倒。", "一禪兩居士，更約踐幽討。"]'),
('066cc9eb-f0c6-4958-9ab1-ee703d39a6b5','陪張平甫遊禹廟','姜夔','宋','宋诗','song-poetry','','[]','鏡裏山林綠到天，春風只在禹祠前。',32,'全唐诗/poet.song.173000.json','["鏡裏山林綠到天，春風只在禹祠前。", "一聲何處提壺鳥，猛省紅塵二十年。"]'),
('77c3c43b-0a69-43fc-af62-252f5d1ec6af','乍凉寄朴翁','姜夔','宋','宋诗','song-poetry','','[]','前日松間步屧歸，更將荷葉障秋暉。',64,'全唐诗/poet.song.173000.json','["前日松間步屧歸，更將荷葉障秋暉。", "如今城裏拋團扇，應是山中試裌衣。", "水有秋容蓮漸少，樹含涼氣鳥慵飛。", "炎天既懶趨城市，從此尤須戀翠微。"]'),
('db8fb1ac-941d-457a-896f-6180b086093b','寄俞子  其一','姜夔','宋','宋诗','song-poetry','','[]','此郎都無子弟氣，夜對黄嬭籠青燈。',32,'全唐诗/poet.song.173000.json','["此郎都無子弟氣，夜對黄嬭籠青燈。", "只今落脚墮鳶外，欲往從之歎未能。"]'),
('dcf4bc60-5f48-487c-a0b0-782e2370762b','寄俞子  其二','姜夔','宋','宋诗','song-poetry','','[]','郎罷才名今白髮，佐州亦復坐窮邊。',32,'全唐诗/poet.song.173000.json','["郎罷才名今白髮，佐州亦復坐窮邊。", "甚欲出手相料理，東南風高難寄牋。"]'),
('40e89f07-35b0-4079-a619-ef91880fd88e','昔遊詩  其一','姜夔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭八百里，玉盤盛水銀。',84,'全唐诗/poet.song.173000.json','["洞庭八百里，玉盤盛水銀。", "長虹忽照影，大哉五色輪。", "我舟渡其中，晁晁驚我神。", "朝發黄陵祠，暮至赤沙曲。", "借問此何處，滄灣三十六。", "青蘆望不盡，明月耿如燭。", "灣灣無人家，只就蘆邊宿。"]'),
('00c76b7e-8692-479f-9e93-cbf997243d47','昔遊詩  其二','姜夔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','放舟龍陽縣，洞庭包五河。',108,'全唐诗/poet.song.173000.json','["放舟龍陽縣，洞庭包五河。", "洶洶不得道，茫茫將奈何。", "篙師請小泊，石矴沉泥沙。", "是中太無岸，强指葦與莎。", "滯留三四晨，大浪山嵯峨。", "同舟總下淚，自謂餧黿鼉。", "白水日以長，僅存青草芽。", "轉盼又已沒，但見千頃波。", "此時羨白鳥，飛入青山阿。"]'),
('fe6f84e3-1d86-427a-9202-08ee79a04d3f','昔遊詩  其三','姜夔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','九山如馬首，一一奔洞庭。',108,'全唐诗/poet.song.173000.json','["九山如馬首，一一奔洞庭。", "小舟過其下，幸哉波浪平。", "大風忽怒起，我舟如葉輕。", "或升千丈坡，或落千丈坑。", "回望九馬山，政與大浪爭。", "如飛鵝車礮，亂打睢陽城。", "又如白獅子，山下跳鬇鬡。", "須臾入別浦，萬死得一生。", "始知茵席濕，盡覆杯中羹。"]'),
('6d296b30-3268-48a3-aa32-82494a90061f','昔遊詩  其四','姜夔','宋','宋诗','song-poetry','','[]','蕭蕭湘陰縣，寂寂黄陵祠。',60,'全唐诗/poet.song.173000.json','["蕭蕭湘陰縣，寂寂黄陵祠。", "喬木蔭樓殿，畫壁半傾欹。", "蘆洲雨中淡，漁網煙外歸。", "重華不可見，但見江鷗飛。", "假令無恨事，過此亦依依。"]'),
('d62082d8-7d8d-4aed-8c80-e4e1b0054b17','昔遊詩  其五','姜夔','宋','宋诗','song-poetry','','[]','我乘五板船，將入沌河口。',84,'全唐诗/poet.song.173000.json','["我乘五板船，將入沌河口。", "大江風浪起，夜黑不見手。", "同行子周子，渠膽大如斗。", "長竿插蘆席，船作野馬走。", "不知何所詣，生死付之偶。", "忽聞入草聲，燈火亦稍有。", "杙船遂登岸，急買野家酒。"]'),
('c1ff1fb4-6f84-4bf8-9124-3d5799cf3d86','昔遊詩  其六','姜夔','宋','宋诗','song-poetry','','[]','天寒白馬渡，落日山陽村。',132,'全唐诗/poet.song.173000.json','["天寒白馬渡，落日山陽村。", "是時無霜雪，萬里風奔奔。", "外旃吹已透，內纊冰不溫。", "吹馬馬欲倒，吹笠任飛翻。", "不見行路人，但見草木蕃。", "忽看野燒起，大焰燒乾坤。", "聲如震雷震，勢若江湖吞。", "虎豹走散亂，麋鹿不足言。", "夜投野店宿，無壁亦無門。", "此行值三厄，幸得軀命存。", "明發見老姊，斗酒爲招魂。"]'),
('34879d5b-50fc-4b60-bc6f-3f97aeaa6aea','昔遊詩  其七','姜夔','宋','宋诗','song-poetry','','[]','揚舲下大江，日日風雨雪。',144,'全唐诗/poet.song.173000.json','["揚舲下大江，日日風雨雪。", "留滯鼇背洲，十日不得發。", "岸冰一尺厚，刀劍觸舟楫。", "岸雪一丈深，屹如玉城堞。", "同舟二三士，頗壯不恐懾。", "蒙氈閉篷卧，波裏任傾攧。", "晨興視氈上，積雪何皎潔。", "欲上不得梯，欲留岸頻裂。", "攀援始得上，幸有人見接。", "荒村三兩家，寒苦衣食缺。", "買豬祭波神，入市路已絕。", "如今得安坐，閑對妻兒說。"]'),
('3cbf0e6f-f7ab-4c0d-a420-edc3094a4d46','昔遊詩  其八','姜夔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','青草長沙境，洞庭渺相連。',288,'全唐诗/poet.song.173000.json','["青草長沙境，洞庭渺相連。", "洞庭西北角，雲夢更無邊。", "復有白湖沌，渺莽里數千。", "豈惟大盜窟，神龍所盤旋。", "白湖辛巳歲，忽墮死蜿蜒。", "一鱗大如箕，一髯大如椽。", "白身青鬐鬛，兩角上梢天。", "半體卧沙上，半體猶沉淵。", "里正聞之官，官使吏致虔。", "作齋爲禳禬，觀者足闐闐。", "歛席覆其體，數里聞腥羶。", "一夕雷雨過，此物忽已遷。", "遺跡陷成川，中可行大船。", "是年虜亮至，送死江之壖。", "或云祖龍讖，詭異非偶然。", "近日山陽人，採菱不知還。", "望見三龍浮，目若電火燃。", "見龍多見尾，少見四體全。", "一龍已爲異，三者亦罕傳。", "又因漁湖側，水中忽生煙。", "煙中一馿出，繞身步蹁躚。", "俄隨霹靂去，欲詰無由緣。", "我聞語此事，乘舟往觀焉。", "徑往枯葭浦，白鷺爭相先。"]'),
('8ca7cf36-3c83-4bc3-8b6e-39290caa3b6b','昔遊詩  其九','姜夔','宋','宋诗','song-poetry','','[]','昔遊桃源山，先次白馬渡。',264,'全唐诗/poet.song.173000.json','["昔遊桃源山，先次白馬渡。", "渡頭何清深，鴻鵠在高樹。", "白馬亦洞天，昔人有奇遇。", "洞門不可見，但聞水聲怒。", "瞻彼羽人宅，乃乘方船渡。", "脩廊夾五殿，重閣映千樹。", "規模象魏壯，回合綠陰護。", "山椒望五谿，壺頭入指顧。", "故宮在其北，屋瓦带松霧。", "古杉晉時物，中空野人住。", "外圍四十尺，內可十客聚。", "我遊瞿仙館，壇上表遺步。", "却下八疊坡，一亭衆妙具。", "兩山抱澄潭，老木枝榦互。", "瞻前秀而迥，坐久凜難駐。", "桃源獨不見，僻在宮南路。", "山行轉深邃，狙猿紛上下。", "石竇出微涓，令我意猶豫。", "昔聞漁舟子，水際見洞戶。", "今看去溪遠，定自後人誤。", "惆悵却歸來，此遊不得屢。", "于今二十年，歷歷經行處。"]'),
('fa6193c9-b300-4a17-9c00-3a14f99062f2','昔遊詩  其一○','姜夔','宋','宋诗','song-poetry','','["\u8861\u5c71"]','昔遊衡山下，看水入朱陵。',84,'全唐诗/poet.song.173000.json','["昔遊衡山下，看水入朱陵。", "半空掃積雪，萬萬玉花凝。", "或如生綃掛，或作薄霧橫。", "紛紛虎豹吼，往往蛟龍驚。", "人語不相聞，濺雹漂我纓。", "有魚緣峭壁，上上終不停。", "此中有神物，雷雨周八紘。"]'),
('2fbf5cab-b129-49bc-b92a-6c61b96e57f1','昔遊詩  其一一','姜夔','宋','宋诗','song-poetry','','["\u8861\u5c71"]','昔遊衡山上，未曉入幽谷。',288,'全唐诗/poet.song.173000.json','["昔遊衡山上，未曉入幽谷。", "欲識所坐輿，橫版掛兩竹。", "狀如秋千垂，高下不傾覆。", "登山九千丈，中道多佛屋。", "一峰高一峰，峰峰秀林木。", "仰看同來客，木末見冠服。", "高臺石橋路，尋常雲所宿。", "下方雷雨時，此上自晴旭。", "紫蓋何突兀，萬里在一目。", "餘峰六七十，僅如翠浪矗。", "北有嬾瓚巖，大石庇樵牧。", "下窺半崖花，杯盂琢紅玉。", "飛雲身畔過，攬之不盈掬。", "祝融最高絕，紫蓋不足錄。", "俯視同仰觀，蒼蒼萬形伏。", "惟餘岣嶁峰，南睇半空綠。", "彷彿認瀟湘，向嶽流屈曲。", "高處驚我魂，幡思宅平陸。", "其東有雷穴，靈異謹勿觸。", "雲來綿世界，雲去一峰獨。", "僧窗或留罅，雲入不可逐。", "絕頂橫石渠，仙人有遺躅。", "山多金光草，夜半如列燭。", "靈藥不可尋，吁嗟歸太速。"]'),
('cf1d2f2d-bd2a-4bcb-87e0-34821e029577','昔遊詩  其一二','姜夔','宋','宋诗','song-poetry','','[]','濠梁四無山，坡陀亙長野。',120,'全唐诗/poet.song.173000.json','["濠梁四無山，坡陀亙長野。", "吾披紫茸氈，縱飲面微赭。", "自矜意氣豪，敢騎雪中馬。", "行行逆風去，初亦畧霑灑。", "疾風吹大片，忽若亂飄瓦。", "側身當其衝，絲鞚袖中把。", "重圍萬箭急，馳突更叱咤。", "酒力不支吾，數里進一斝。", "燎茅烘濕衣，客有見留者。", "裴回望神州，沉歎英雄寡。"]'),
('93c5b9f8-d769-4df8-b5cc-cdfdce0d57b7','昔遊詩  其一三','姜夔','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','既離湖口縣，未至落星灣。',72,'全唐诗/poet.song.173000.json','["既離湖口縣，未至落星灣。", "舟中三兩程，程程見廬山。", "廬山遮半天，五老雲爲冠。", "朝看金疊疊，暮看紫巉巉。", "瀑布在山半，彷彿認一斑。", "廬山忽不見，雲雨滿人間。"]'),
('e0dc0631-85b4-4840-b31e-495aa60af6ce','昔遊詩  其一四','姜夔','宋','宋诗','song-poetry','','[]','雪霽下揚子，閑望江上山。',60,'全唐诗/poet.song.173000.json','["雪霽下揚子，閑望江上山。", "山山如白玉，日照金孱顔。", "是時江水浄，影落清鏡寒。", "潮催庾信老，雲送佛狸還。", "萬古感心事，惆悵垂楊灣。"]'),
('4cff8d94-57d3-4e32-b851-10242a29a63d','昔遊詩  其一五','姜夔','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山爲真宮，道士飲我酒。',156,'全唐诗/poet.song.173000.json','["衡山爲真宮，道士飲我酒。", "共坐有何人，山中白衣叟。", "問叟家何在，近住山洞口。", "殷勤起見邀，徐步入林藪。", "雲深險徑黑，石亂湍水吼。", "尋源行漸遠，茅屋剪如帚。", "老烹茶味苦，野琢琴形醜。", "叟云司馬僊，學道此居久。", "屋東大盤石，棋畫今尚有。", "古木庇覆之，清泉石根走。", "因悲百年內，汲汲成白首。", "僊人固難值，隠者亦可偶。", "追惟恍如夢，欲畫無好手。"]'),
('ddd2ed6d-16b6-447d-82a4-68d0af467c91','題楊冠卿客亭類稿','姜夔','宋','宋诗','song-poetry','','[]','楊侯筆力天下奇，早歲豪彥相追隨。',128,'全唐诗/poet.song.173000.json','["楊侯筆力天下奇，早歲豪彥相追隨。", "一班略見客亭稿，文采炳蔚驚羣兒。", "長安城中擇幽棲，靜退不願時人知。", "大書前榮號霧隠，意與風虎雲龍期。", "人皆炫耀身陸離，見草而悅忘皋比。", "南山十日不下食，君子一變誰能窺。", "正論不作世道微，通都大邑多狐狸。", "惜君爪牙不得施，公超五里亦奚爲。"]'),
('9ba1057f-940f-42ae-9aef-5cfdc69b1e83','琵琶洲','姜夔','宋','宋诗','song-poetry','','[]','行盡江南最遠山，却尋干越上清灘。',32,'全唐诗/poet.song.173000.json','["行盡江南最遠山，却尋干越上清灘。", "秋清雲錦溪中過，玉石瑰奇一萬般。"]'),
('e58f1a7f-62b7-4985-aa3d-e167123f8f7a','桂花','姜夔','宋','宋诗','song-poetry','','[]','空山尋桂樹，折香思故人。',96,'全唐诗/poet.song.173000.json','["空山尋桂樹，折香思故人。", "故人隔秋水，一望一回顰。", "南山北山路，載花如行雲。", "闌干望雙槳，穠枝儲待君。", "西泠蔭歌舞，夜夜明月嗔。", "棄捐頳玉佩，香盡作秋塵。", "楚調秋更苦，寂寥無復聞。", "來吟綠叢下，涼風吹練裙。"]'),
('1aa6e0cb-8692-4693-a4c4-f510d3cf4e81','郊祀後景靈宮恭謝紀事  其一','姜夔','宋','宋诗','song-poetry','','[]','六軍文武浩如雲，花簇頭冠樣樣新。',32,'全唐诗/poet.song.173000.json','["六軍文武浩如雲，花簇頭冠樣樣新。", "惟有至尊渾不戴，盡將春色賜羣臣。"]'),
('569f6385-0979-4599-aa38-c7699770a03c','郊祀後景靈宮恭謝紀事  其二','姜夔','宋','宋诗','song-poetry','','[]','萬數簪花滿御街，聖人先自景靈回。',32,'全唐诗/poet.song.173000.json','["萬數簪花滿御街，聖人先自景靈回。", "不知後面花多少，但見紅雲冉冉來。"]'),
('144bccbc-2e84-4fa8-94bf-9f980908c07f','燈詞  其一','姜夔','宋','宋诗','song-poetry','','[]','南陌東城盡舞兒，畫金刺繡滿羅衣。',32,'全唐诗/poet.song.173000.json','["南陌東城盡舞兒，畫金刺繡滿羅衣。", "也知愛惜春遊夜，舞落銀蟾不肯歸。"]'),
('9c609017-403b-4c3c-a876-da73938be43b','燈詞  其二','姜夔','宋','宋诗','song-poetry','','[]','燈已闌珊月色寒，舞兒往往夜深還。',32,'全唐诗/poet.song.173000.json','["燈已闌珊月色寒，舞兒往往夜深還。", "只因不盡婆娑意，更向街心弄影看。"]'),
('0e33def7-6e64-49f8-9f84-e532b95fd2de','燈詞  其三','姜夔','宋','宋诗','song-poetry','','[]','沙河雲合無行處，惆悵來遊路已迷。',32,'全唐诗/poet.song.173000.json','["沙河雲合無行處，惆悵來遊路已迷。", "却入靜坊燈火空，門門相似列蛾眉。"]'),
('0229c5fe-c9b7-4d44-b3c8-8eea6693b0ac','燈詞  其四','姜夔','宋','宋诗','song-poetry','','[]','遊人歸後天街靜，坊陌人家未閉門。',32,'全唐诗/poet.song.173000.json','["遊人歸後天街靜，坊陌人家未閉門。", "簾裏垂燈照尊俎，坐中嬉笑覺春溫。"]'),
('5404059a-62ec-4960-a64f-b29d1ee0b370','送王簡卿歸天台二首  其一','姜夔','宋','宋诗','song-poetry','','[]','迎風吹白髮，送客向黄巖。',48,'全唐诗/poet.song.173000.json','["迎風吹白髮，送客向黄巖。", "在事何爲爾，如君自不凡。", "城陰當復會，詩卷可頻緘。", "縱別無多久，江沙望遠帆。"]'),
('1311acd8-0ef4-428d-a6d6-9e22717fe07e','送王簡卿歸天台二首  其二','姜夔','宋','宋诗','song-poetry','','[]','讎書雖不願，治粟亦何爲。',48,'全唐诗/poet.song.173000.json','["讎書雖不願，治粟亦何爲。", "夜月同游處，春潮獨往時。", "無心資造化，任運有成虧。", "護冷加餐食，幽居且自怡。"]'),
('e15c5d9c-4754-4d81-a053-b7b6d0a24bc8','菖蒲','姜夔','宋','宋诗','song-poetry','','[]','岳麓溪毛秀，湘濱玉水香。',48,'全唐诗/poet.song.173000.json','["岳麓溪毛秀，湘濱玉水香。", "靈苗憐勁直，達節著芬芳。", "豈謂盤盂小，而忘臭味長。", "拳山并勺水，所至未能量。"]'),
('334e7381-ae19-4e3a-8287-1dcb41983fba','嘲林可山稱和靖七世孫','姜夔','宋','宋诗','song-poetry','','[]','和靖當年不娶妻，因何七世有孫兒。',32,'全唐诗/poet.song.173000.json','["和靖當年不娶妻，因何七世有孫兒。", "若非鶴種并龍種，定是瓜皮搭李皮。"]'),
('f629b13c-7872-451d-9c01-4228ffa53215','三高祠','姜夔','宋','宋诗','song-poetry','','[]','不貪名爵伐功勞，勇退深虞禍患遭。',32,'全唐诗/poet.song.173000.json','["不貪名爵伐功勞，勇退深虞禍患遭。", "甫里閒居耕釣樂，范張高處陸猶高。"]'),
('d2db6b6a-8fed-4fdd-b837-c5efbb195483','和王祕書遊水樂洞','姜夔','宋','宋诗','song-poetry','','[]','自是瀛洲客，還因野趣來。',48,'全唐诗/poet.song.173000.json','["自是瀛洲客，還因野趣來。", "解衣吟寂寞，携酒上崔嵬。", "石洞山山秀，梔花樹樹開。", "只應巖下水，相送上船回。"]'),
('88321336-3f59-4fbc-a4a1-5c2f0c8b509e','嘉泰壬戌上元日訪全老於浄林廣福院觀沈傳師碑隆茂宗畫贈詩二首  其一','姜夔','宋','宋诗','song-poetry','','[]','深衣跨羸驂，杳杳春山路。',24,'全唐诗/poet.song.173000.json','["深衣跨羸驂，杳杳春山路。", "入寺君未知，閒看移桂樹。"]'),
('a8de6a2e-1908-4a6a-ab44-4a369628dd91','嘉泰壬戌上元日訪全老於浄林廣福院觀沈傳師碑隆茂宗畫贈詩二首  其二','姜夔','宋','宋诗','song-poetry','','[]','沈碑含秀潤，隆畫出神奇。',24,'全唐诗/poet.song.173000.json','["沈碑含秀潤，隆畫出神奇。", "道人那得此，老子乃躭之。"]'),
('25fd8873-9cec-4bee-8f4b-5e549dac3f4f','齋後與全老銛樸翁聰自聞酌龍井而歸  其一','姜夔','宋','宋诗','song-poetry','','[]','四人松下共盤桓，筆硯花壺石上安。',32,'全唐诗/poet.song.173000.json','["四人松下共盤桓，筆硯花壺石上安。", "今日興懷同此味，老仙留字在孱顔。"]'),
('501e18a7-1d5e-4107-b3a4-7c946010e831','齋後與全老銛樸翁聰自聞酌龍井而歸  其二','姜夔','宋','宋诗','song-poetry','','[]','年時六月海揚塵，遥見青山起白雲。',32,'全唐诗/poet.song.173000.json','["年時六月海揚塵，遥見青山起白雲。", "聞有高僧來誦咒，巖前拋珓問龍君。"]'),
('1c5acf8e-4ab9-4745-a769-e983deead999','自題畫像','姜夔','宋','宋诗','song-poetry','','[]','鶴氅如煙羽扇風，賦情芳草綠陰中。',32,'全唐诗/poet.song.173000.json','["鶴氅如煙羽扇風，賦情芳草綠陰中。", "黑頭辦了人間事，來看淩霜數點紅。"]'),
('c9cde6eb-d364-4082-9f13-9484094bf411','寺中','姜夔','宋','宋诗','song-poetry','','[]','幸自不居城，西風覺又生。',48,'全唐诗/poet.song.173000.json','["幸自不居城，西風覺又生。", "空山多雨氣，廢寺少人聲。", "髮爲憂時白，吟因入夜清。", "推窗問天色，猶有佛燈明。"]'),
('2e67d8f6-a627-4878-a45a-f07af82363ec','有送','姜夔','宋','宋诗','song-poetry','','[]','憐君歸橐路迢迢，到得茅齋轉寂寥。',32,'全唐诗/poet.song.173000.json','["憐君歸橐路迢迢，到得茅齋轉寂寥。", "應歎藥欄經雨爛，土肥抽盡縮砂苗。"]'),
('e3c4ceb9-413a-412f-b9e3-428e0325e25f','于越亭','姜夔','宋','宋诗','song-poetry','','[]','松尾颼颼石浪寒，胡啼番曲轉聲酸。',32,'全唐诗/poet.song.173000.json','["松尾颼颼石浪寒，胡啼番曲轉聲酸。", "人間無此春風手，應是江妃夜夜彈。"]'),
('b934d71f-013d-415b-884a-d435ba8641cd','句  其一','姜夔','宋','宋诗','song-poetry','','[]','小山不能雲，大山半爲天。',12,'全唐诗/poet.song.173000.json','["小山不能雲，大山半爲天。"]'),
('05ef8997-af5d-4368-b17a-6dc50cc3f91d','句  其二','姜夔','宋','宋诗','song-poetry','','[]','屋角紅梅樹，花前白石生。',12,'全唐诗/poet.song.173000.json','["屋角紅梅樹，花前白石生。"]'),
('f5bdedd7-2f28-49dd-987d-449a9ea7e021','句  其三','姜夔','宋','宋诗','song-poetry','','[]','梅花竹裏無人見，一夜吹香過石橋。',16,'全唐诗/poet.song.173000.json','["梅花竹裏無人見，一夜吹香過石橋。"]'),
('ad99de4f-4ef0-48ab-bd0a-0b51cd44c0d7','句  其四','姜夔','宋','宋诗','song-poetry','','[]','中興無限艱難意，日暮湖平力士歸。',16,'全唐诗/poet.song.173000.json','["中興無限艱難意，日暮湖平力士歸。"]'),
('d9323b62-2c6f-4b62-9392-5f71ae002d8c','春懷','葛天民','宋','宋诗','song-poetry','','[]','向晚一鳩鳴，道人春睡足。',24,'全唐诗/poet.song.173000.json','["向晚一鳩鳴，道人春睡足。", "無處寫幽懷，巡簷數脩竹。"]'),
('bddb04c8-7fe8-4496-9978-9ac5812f91c7','絕句','葛天民','宋','宋诗','song-poetry','','[]','夜雨漲波高二尺，失却搗衣平正石。',32,'全唐诗/poet.song.173000.json','["夜雨漲波高二尺，失却搗衣平正石。", "天明水落石依然，老夫一夜空相憶。"]'),
('671f12fb-6418-4e18-abbc-da478d73ebc8','看山','葛天民','宋','宋诗','song-poetry','','[]','我本田夫作比丘，也知騎馬勝騎牛。',32,'全唐诗/poet.song.173000.json','["我本田夫作比丘，也知騎馬勝騎牛。", "如今馬上看山色，不似騎牛得自由。"]'),
('ed02d31d-5712-44aa-9045-7a6ba474bb76','寄楊誠齋','葛天民','宋','宋诗','song-poetry','','[]','參禪學詩無兩法，死蛇解弄活鱍鱍。',226,'全唐诗/poet.song.173000.json','["參禪學詩無兩法，死蛇解弄活鱍鱍。", "氣正心空眼自高，吹毛不動全生殺。", "生機熟語却不俳，近代獨有楊誠齋。", "才名萬古付公論，風月四時輸好懷。", "知公別具頂門竅，參得徹兮吟得到。", "趙州禪在口皮邊，淵明詩寫胸中妙。", "用則致君堯舜前，舍時便灌廬陵園。", "六十四卦只兩畫，三百五篇惟一言。", "我與誠齋略相識，亦不知他好官職。", "但知拚得忍饑七十年，脊梁如鐵心如石。", "不曾屈膝不皺眉，不把文章做出詩。", "玉川後身却不怪，樂天再世尤能奇。", "隔千里兮共明月，何似寒灰相對撥。", "公亦何須要我知，我只欠公頭上髮。"]'),
('e30eae83-ca07-46b0-9c8c-71df594e51a2','醉書酒肆','葛天民','宋','宋诗','song-poetry','','[]','碧床酒盎香拍浮，吳姬粉醉不識愁。',32,'全唐诗/poet.song.173000.json','["碧床酒盎香拍浮，吳姬粉醉不識愁。", "黄金手揮博歌頭，夜半春回楊柳樓。"]'),
('108e1cf1-7b05-46dd-b88d-cd02e7989305','竺澗梅','葛天民','宋','宋诗','song-poetry','','[]','龍脊橋邊鶴膝幽，一枝斜亞水橫流。',32,'全唐诗/poet.song.173000.json','["龍脊橋邊鶴膝幽，一枝斜亞水橫流。", "自從識破胡笳曲，吹徹黄昏不解愁。"]'),
('0c99372b-16e9-44eb-a2ca-7b37769b6eee','謝文思徐敬伯見訪','葛天民','宋','宋诗','song-poetry','','[]','半山徐敬伯，薄宦在中都。',48,'全唐诗/poet.song.173000.json','["半山徐敬伯，薄宦在中都。", "柳舍偷閑到，村醪就近酤。", "易添詩債負，難得醉工夫。", "却羨漁樵叟，雖貧一事無。"]'),
('0bcf7e6f-3576-49ee-888d-9ff6b729043e','即事','葛天民','宋','宋诗','song-poetry','','[]','春漲侵高岸，春雲裹亂山。',48,'全唐诗/poet.song.173000.json','["春漲侵高岸，春雲裹亂山。", "倒遷楊柳活，斜倚桔槔閑。", "世味老方淡，花時晴最慳。", "東風嗔懶動，故故撼柴關。"]'),
('02616d9a-9077-4adc-a5a0-991a5650831a','重訪白右','葛天民','宋','宋诗','song-poetry','','[]','長安唯白石，與我最相關。',48,'全唐诗/poet.song.173000.json','["長安唯白石，與我最相關。", "每到難逢面，翻思懶下山。", "欲歸愁路遠，小住待君還。", "盡日看幽桂，無人似我閑。"]'),
('bbd8aa93-4c60-4cc1-b8cb-a688fb7e0108','達磨渡蘆像','葛天民','宋','宋诗','song-poetry','','[]','一言已出駟難追，頼得君王放過伊。',32,'全唐诗/poet.song.173000.json','["一言已出駟難追，頼得君王放過伊。", "楊子江心杭折葦，浪頭何似問頭危。"]'),
('41980a53-765c-437a-8cee-e1a2284a6d50','收白匾豆因得二首  其一','葛天民','宋','宋诗','song-poetry','','[]','齒髮中年態，丘園素隠心。',48,'全唐诗/poet.song.173000.json','["齒髮中年態，丘園素隠心。", "因栽白匾豆，欲當紫團參。", "筐筥收繁莢，窗扉失茂陰。", "蕭蕭簷外竹，抱蔓替予吟。"]'),
('403f89ea-01a8-477d-8a17-b4e95d95821f','收白匾豆因得二首  其二','葛天民','宋','宋诗','song-poetry','','[]','古香無伴侶，一榻共雲分。',48,'全唐诗/poet.song.173000.json','["古香無伴侶，一榻共雲分。", "磵水塘頭過，樵歌枕上聞。", "余生聊自適，此意與誰論。", "落葉如相委，時敲月下門。"]'),
('f9b51e80-68e5-496e-b30d-a54c983bf55c','仲春初二絕  其一','葛天民','宋','宋诗','song-poetry','','[]','落梅如雪雨如麻，最怕春寒是杏花。',32,'全唐诗/poet.song.173000.json','["落梅如雪雨如麻，最怕春寒是杏花。", "病後不能涓滴飲，可憐芳信到貧家。"]'),
('0433c2ed-9d2f-47b7-8fee-b2c25be34854','仲春初二絕  其二','葛天民','宋','宋诗','song-poetry','','[]','初交二月草蒙茸，鄰里紛紛去折蓬。',32,'全唐诗/poet.song.173000.json','["初交二月草蒙茸，鄰里紛紛去折蓬。", "柳下閉門非懶出，苦無筋力趁兒童。"]'),
('76bfbf12-7468-46d8-a4f6-b67153e33cc9','湖上夜歸','葛天民','宋','宋诗','song-poetry','','[]','陌上紅塵歇，湖中翠靄生。',48,'全唐诗/poet.song.173000.json','["陌上紅塵歇，湖中翠靄生。", "定鍾山寺迥，新月夜船清。", "蛙亂鳴方急，鷗閑睡不驚。", "兒曹知我到，認得打門聲。"]'),
('1c6b88f5-649e-4ec9-997c-ae6e5d6c0445','聞鳩','葛天民','宋','宋诗','song-poetry','','[]','蟄動猶寒在，鳩鳴恰睡餘。',48,'全唐诗/poet.song.173000.json','["蟄動猶寒在，鳩鳴恰睡餘。", "素傳鷹羽化，多占鵲巢居。", "報我晴何用，憐渠拙自如。", "年年偏感處，風急杏花初。"]'),
('6837316c-d9ee-41b5-82f5-086a46fd6724','迎燕','葛天民','宋','宋诗','song-poetry','','[]','咫尺春三月，尋常百姓家。',48,'全唐诗/poet.song.173000.json','["咫尺春三月，尋常百姓家。", "爲迎新燕入，不下舊簾遮。", "翅濕沾微雨，泥香带落花。", "巢成鶵長大，相伴過年華。"]'),
('e015ef16-51c4-4dee-a397-3bc2a6af8ecd','玩蝶','葛天民','宋','宋诗','song-poetry','','[]','粉翅來何許，春風卒未休。',48,'全唐诗/poet.song.173000.json','["粉翅來何許，春風卒未休。", "衆芳皆舊識，微雨是新愁。", "鬭舞圍牆角，貪香綴蘂頭。", "與花俱不語，相可自風流。"]'),
('a9e07357-26df-42a3-9fa9-ef17d69d5bd4','聞杜鵑','葛天民','宋','宋诗','song-poetry','','[]','望帝知何苦，催歸不自禁。',48,'全唐诗/poet.song.173000.json','["望帝知何苦，催歸不自禁。", "竄身依樹密，啼血染花深。", "細雨離人淚，遊絲蕩子心。", "青山明月夜，老耳最知音。"]'),
('81bf8d5f-fd23-42b5-96c2-5d10fd2e998d','湖上觀柳偶記龍泉先生勾春柳一絲之句感而有述','葛天民','宋','宋诗','song-poetry','','[]','斷槎無葉又無枝，得似勾春柳一絲。',32,'全唐诗/poet.song.173000.json','["斷槎無葉又無枝，得似勾春柳一絲。", "不是畫船棲泊處，白鷗飛下立多時。"]'),
('53c10c00-48c0-4262-ad11-d1baedae4fef','嘗青梅','葛天民','宋','宋诗','song-poetry','','[]','疎影橫斜處，匆匆入夏看。',48,'全唐诗/poet.song.173000.json','["疎影橫斜處，匆匆入夏看。", "綠陰遮得暗，青子結來酸。", "因病全疎酒，如癡猶凭欄。", "楊花無藉在，風急正漫漫。"]');
